-- Seed all dictionary words from dist/data/words.json

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('amend', 'AMEND', '/əˈmɛnd/', 'değiştirmek · düzeltmek · ıslah etmek · tadil etmek · düzenleme yapmak', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Amend</strong> öncelikle fiil olarak kullanılan, resmi ve yazılı dilde çok sık karşılaşılan bir kelimedir. Hukuk, siyaset, iş dünyası ve yazılım geliştirme alanlarında özellikle yaygındır.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Amend\" kelimesinin temelinde <em>\"bir hatayı veya eksikliği düzelterek iyileştirmek\"</em> fikri yatar. Günlük \"düzeltmek\" anlamından farklı olarak, \"amend\" daha <em>resmi</em> ve <em>yapısal</em> bir değişikliği ifade eder. Bir yasayı, bir belgeyi, bir sözleşmeyi veya bir davranışı düzeltmekten söz ederken kullanılır. Sadece \"tamir etmek\" değil, \"daha iyi hale getirmek için değiştirmek\" anlamını taşır. İsim formu <strong>amendment</strong> özellikle hukuk ve anayasa bağlamında çok önemlidir — ABD Anayasası''nın ek maddeleri \"amendments\" olarak adlandırılır.</p>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To make changes to a text/document to improve or correct it</td><td>Bir metin/belge üzerinde düzeltme/değişiklik yapmak</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To modify a law, rule, or formal agreement</td><td>Bir yasayı, kuralı veya resmi anlaşmayı tadil etmek</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To improve one''s behavior or character (formal/literary)</td><td>Davranışını veya karakterini düzeltmek, ıslah etmek</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To correct or update a record or return (e.g., tax)</td><td>Bir kayıt veya beyanı düzeltmek (örn. vergi beyannamesi)</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>amend</strong></td><td>verb (fiil)</td><td>değiştirmek, düzeltmek, tadil etmek</td></tr>\n          <tr><td><strong>amendment</strong></td><td>noun (isim)</td><td>değişiklik, düzeltme, tadilat; anayasa eki</td></tr>\n          <tr><td><strong>amended</strong></td><td>adjective / past participle</td><td>değiştirilmiş, düzeltilmiş, tadil edilmiş</td></tr>\n          <tr><td><strong>amends</strong></td><td>noun (isim, çoğul)</td><td>telafi, tazminat (genellikle \"make amends\" yapısında)</td></tr>\n          <tr><td><strong>amendable</strong></td><td>adjective (sıfat)</td><td>değiştirilebilir, düzeltilebilir</td></tr>\n          <tr><td><strong>unamended</strong></td><td>adjective (sıfat)</td><td>değiştirilmemiş, orijinal haliyle</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Amend\" düzenli (regular) bir fiildir: <strong>amend – amended – amended</strong>.\n      </div>\n\n      <div class=\"tip\">\n        <strong>⚠️ Dikkat — amend vs. amends:</strong><br>\n        <strong>amend</strong> = fiil → düzeltmek, değiştirmek<br>\n        <strong>amends</strong> = isim (her zaman çoğul) → telafi, gönül alma<br>\n        ✅ <em>I want to <strong>make amends</strong> for my mistake.</em> (Hatamı telafi etmek istiyorum.)<br>\n        ❌ <em>I want to make <strong>amend</strong>.</em> (Yanlış — \"amends\" olmalı)\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>amend + something (a document/law/text)</code>\n        <div>→ Bir belgeyi/yasayı/metni değiştirmek/düzeltmek</div>\n        <div class=\"example\"><em>Parliament voted to <strong>amend the law</strong>.</em></div>\n        <div class=\"turkish\">Parlamento yasayı değiştirmek için oy kullandı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>amend + something + to + do something</code>\n        <div>→ Bir şeyi … yapacak şekilde değiştirmek</div>\n        <div class=\"example\"><em>They <strong>amended the contract to include</strong> a new clause.</em></div>\n        <div class=\"turkish\">Sözleşmeyi yeni bir madde içerecek şekilde değiştirdiler.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>make amends (for something)</code>\n        <div>→ (Bir şey için) telafi etmek, gönül almak</div>\n        <div class=\"example\"><em>He tried to <strong>make amends for</strong> his past behavior.</em></div>\n        <div class=\"turkish\">Geçmişteki davranışlarını telafi etmeye çalıştı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>make amends (to someone)</code>\n        <div>→ Birine karşı telafide bulunmak</div>\n        <div class=\"example\"><em>She wanted to <strong>make amends to</strong> her family.</em></div>\n        <div class=\"turkish\">Ailesine karşı telafide bulunmak istedi.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>as amended</code>\n        <div>→ Değiştirilmiş haliyle (hukuki ifade)</div>\n        <div class=\"example\"><em>The regulation, <strong>as amended</strong> in 2024, now applies to all companies.</em></div>\n        <div class=\"turkish\">2024''te değiştirilen yönetmelik artık tüm şirketler için geçerli.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>an amendment to + something</code>\n        <div>→ Bir şeye yapılan değişiklik/ek madde</div>\n        <div class=\"example\"><em>They proposed <strong>an amendment to</strong> the constitution.</em></div>\n        <div class=\"turkish\">Anayasaya bir değişiklik/ek madde önerdiler.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>amend / amends</td><td>The committee amends the rules every year.</td><td>Komite kuralları her yıl değiştirir.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are amending</td><td>They are amending the policy right now.</td><td>Şu anda politikayı değiştiriyorlar.</td></tr>\n          <tr><td>Simple Past</td><td>amended</td><td>Congress amended the bill yesterday.</td><td>Kongre dün yasa tasarısını değiştirdi.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were amending</td><td>We were amending the report when the deadline passed.</td><td>Son tarih geçtiğinde raporu düzeltiyorduk.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has amended</td><td>The board has amended the bylaws twice.</td><td>Yönetim kurulu tüzüğü iki kez değiştirdi.</td></tr>\n          <tr><td>Past Perfect</td><td>had amended</td><td>She had amended her tax return before the audit.</td><td>Denetimden önce vergi beyannamesini düzeltmişti.</td></tr>\n          <tr><td>Future Simple</td><td>will amend</td><td>The government will amend the regulation next month.</td><td>Hükümet gelecek ay yönetmeliği değiştirecek.</td></tr>\n          <tr><td>Future Perfect</td><td>will have amended</td><td>By Friday, we will have amended all the documents.</td><td>Cuma''ya kadar tüm belgeleri düzeltmiş olacağız.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Amend\" edilgen çatıda çok yaygındır — özellikle hukuki ve resmi yazılarda:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>They amended the constitution.</td><td>The constitution <strong>was amended</strong>.</td><td>Anayasa değiştirildi.</td></tr>\n          <tr><td>We are amending the terms.</td><td>The terms <strong>are being amended</strong>.</td><td>Şartlar değiştiriliyor.</td></tr>\n          <tr><td>Parliament will amend the act.</td><td>The act <strong>will be amended</strong> by Parliament.</td><td>Yasa Parlamento tarafından değiştirilecek.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>an amendment <strong>to</strong> (something)</td><td>An amendment to the contract.</td><td>Sözleşmeye yapılan değişiklik.</td></tr>\n          <tr><td>make amends <strong>for</strong> (something)</td><td>He made amends for his mistakes.</td><td>Hatalarını telafi etti.</td></tr>\n          <tr><td>make amends <strong>to</strong> (someone)</td><td>She made amends to her colleague.</td><td>İş arkadaşına karşı telafide bulundu.</td></tr>\n          <tr><td>make amends <strong>by</strong> (doing something)</td><td>He made amends by apologizing publicly.</td><td>Alenen özür dileyerek telafide bulundu.</td></tr>\n          <tr><td>amended <strong>in</strong> (year/month)</td><td>The law was amended in 2023.</td><td>Yasa 2023''te değiştirildi.</td></tr>\n          <tr><td>amended <strong>by</strong> (authority)</td><td>The rule was amended by the board.</td><td>Kural yönetim kurulu tarafından değiştirildi.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">amend the law <span class=\"tr\">— yasayı değiştirmek</span></span>\n        <span class=\"collocation-tag\">amend the constitution <span class=\"tr\">— anayasayı değiştirmek</span></span>\n        <span class=\"collocation-tag\">amend a contract <span class=\"tr\">— sözleşmeyi tadil etmek</span></span>\n        <span class=\"collocation-tag\">amend a bill <span class=\"tr\">— yasa tasarısını değiştirmek</span></span>\n        <span class=\"collocation-tag\">amend a policy <span class=\"tr\">— politikayı değiştirmek</span></span>\n        <span class=\"collocation-tag\">amend a record <span class=\"tr\">— kaydı düzeltmek</span></span>\n        <span class=\"collocation-tag\">amend a tax return <span class=\"tr\">— vergi beyannamesini düzeltmek</span></span>\n        <span class=\"collocation-tag\">amended version <span class=\"tr\">— değiştirilmiş versiyon</span></span>\n        <span class=\"collocation-tag\">constitutional amendment <span class=\"tr\">— anayasa değişikliği</span></span>\n        <span class=\"collocation-tag\">proposed amendment <span class=\"tr\">— önerilen değişiklik</span></span>\n        <span class=\"collocation-tag\">make amends <span class=\"tr\">— telafi etmek</span></span>\n        <span class=\"collocation-tag\">as amended <span class=\"tr\">— değiştirilmiş haliyle</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. Please amend the document before sending it.</div>\n          <div class=\"tr\">Lütfen belgeyi göndermeden önce düzeltin.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. The law was amended last year.</div>\n          <div class=\"tr\">Yasa geçen yıl değiştirildi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. I want to make amends for what I did.</div>\n          <div class=\"tr\">Yaptıklarım için telafi etmek istiyorum.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. The committee voted to amend the regulation to include stricter penalties.</div>\n          <div class=\"tr\">Komite, daha sıkı cezalar içerecek şekilde yönetmeliği değiştirmek için oy kullandı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. You can amend your tax return within three years of filing.</div>\n          <div class=\"tr\">Vergi beyannamenizi dosyaladıktan sonra üç yıl içinde düzeltebilirsiniz.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. The contract has been amended to reflect the new terms.</div>\n          <div class=\"tr\">Sözleşme, yeni şartları yansıtacak şekilde değiştirildi.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. The First Amendment to the U.S. Constitution protects freedom of speech.</div>\n          <div class=\"tr\">ABD Anayasası''nın Birinci Değişikliği (Ek Maddesi) ifade özgürlüğünü korur.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. The bill was heavily amended during its passage through the Senate.</div>\n          <div class=\"tr\">Yasa tasarısı Senato''dan geçerken kapsamlı şekilde değiştirildi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. No amount of apologizing can fully amend the damage caused by broken trust.</div>\n          <div class=\"tr\">Hiçbir özür, kırılmış güvenin verdiği zararı tam olarak telafi edemez.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Technology & Git / Teknoloji ve Git</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. Use \"git commit --amend\" to modify your last commit message.</div>\n          <div class=\"tr\">Son commit mesajınızı değiştirmek için \"git commit --amend\" kullanın.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. I amended the pull request description to include the new changes.</div>\n          <div class=\"tr\">Yeni değişiklikleri eklemek için pull request açıklamasını düzelttim.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>Middle English (13. yüzyıl)</td></tr>\n          <tr><td><strong>Root</strong></td><td>Old French: <strong>amender</strong> → Latin: <strong>ēmendāre</strong></td></tr>\n          <tr><td><strong>Latin breakdown</strong></td><td><strong>ē-</strong> (out of, from / -den dışarı) + <strong>menda</strong> (fault, defect / hata, kusur) = \"hatadan arındırmak\"</td></tr>\n          <tr><td><strong>Original meaning</strong></td><td>\"Bir hatayı veya kusuru gidermek, düzeltmek\" — harfi harfine \"kusursuz hale getirmek\"</td></tr>\n          <tr><td><strong>Legal sense</strong></td><td>Hukuki \"yasa değişikliği\" anlamı 14. yüzyıldan itibaren İngiliz hukukunda yerleşmiştir. ABD Anayasası''nın ek maddeleri (1791''den itibaren) bu terimi dünyaca ünlü yapmıştır.</td></tr>\n          <tr><td><strong>\"Make amends\" sense</strong></td><td>\"Telafi etmek\" anlamı 14. yüzyılda ortaya çıkmıştır. Burada \"amends\" isim olarak \"bir yanlışı düzeltme eylemi\" demektir.</td></tr>\n          <tr><td><strong>Git sense</strong></td><td>Yazılım geliştirmede <code>git commit --amend</code> komutu bu kelimenin \"düzeltmek/değiştirmek\" anlamını doğrudan kullanır — son commit''i düzeltir.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (ēmendāre)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>emend</strong></td><td>to correct errors in a text (scholarly)</td><td>bir metindeki hataları düzeltmek (akademik)</td></tr>\n          <tr><td><strong>emendation</strong></td><td>a correction made in a text</td><td>metin düzeltmesi</td></tr>\n          <tr><td><strong>amends</strong></td><td>compensation for a wrong</td><td>telafi, tazminat</td></tr>\n          <tr><td><strong>amendment</strong></td><td>a formal change to a law/document</td><td>değişiklik, tadilat, ek madde</td></tr>\n          <tr><td><strong>mend</strong></td><td>to repair something broken</td><td>tamir etmek, onarmak</td></tr>\n          <tr><td><strong>mendacious</strong></td><td>untruthful (from related Latin root <em>mendax</em>)</td><td>yalancı, düzenbaz</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Amend\" kelimesini kafanızda şöyle düşünün: Latince <em>menda</em> = hata/kusur. <em>A-mend</em> = \"hatayı gidermek\". Bir belgeyi, bir yasayı veya bir davranışı <em>kusurlarından arındırarak iyileştirmek</em>. \"Mend\" (tamir etmek) kelimesini biliyorsanız, \"amend\" onun daha resmi ve yapısal versiyonudur.\n      </div>"}, {"icon": "⚖️", "title": "Amend vs. Revise vs. Modify vs. Correct / Farkları", "content": "<p>\"Değiştirmek/düzeltmek\" anlamında kullanılan bu kelimeler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Amend</th><th>Revise</th><th>Modify</th><th>Correct</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Focus</td>\n            <td>Formal improvement of a text/law<br><em>Bir metin/yasanın resmi iyileştirmesi</em></td>\n            <td>Thorough review and update<br><em>Kapsamlı gözden geçirme ve güncelleme</em></td>\n            <td>Partial change, adjustment<br><em>Kısmi değişiklik, ayarlama</em></td>\n            <td>Fixing errors, making right<br><em>Hataları düzeltmek, doğruya getirmek</em></td>\n          </tr>\n          <tr>\n            <td>Formality</td>\n            <td>Very formal<br><em>Çok resmi</em></td>\n            <td>Formal to neutral<br><em>Resmi — nötr</em></td>\n            <td>Neutral<br><em>Nötr</em></td>\n            <td>Neutral<br><em>Nötr</em></td>\n          </tr>\n          <tr>\n            <td>Common in</td>\n            <td>Law, politics, contracts<br><em>Hukuk, siyaset, sözleşmeler</em></td>\n            <td>Writing, education, reports<br><em>Yazarlık, eğitim, raporlar</em></td>\n            <td>General, technology, design<br><em>Genel, teknoloji, tasarım</em></td>\n            <td>Any context with errors<br><em>Hata olan her bağlam</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>Amend the constitution.</td>\n            <td>Revise the essay.</td>\n            <td>Modify the settings.</td>\n            <td>Correct the typo.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Anayasayı değiştirmek.</td>\n            <td>Denemeyi gözden geçirmek.</td>\n            <td>Ayarları değiştirmek.</td>\n            <td>Yazım hatasını düzeltmek.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Amend\" en resmi olanıdır ve genellikle yasal/resmi belgeler için kullanılır. \"Revise\" daha kapsamlı bir yeniden inceleme sürecini ifade eder. \"Modify\" kısmi ve teknik bir ayarlama, \"correct\" ise doğrudan bir hatayı düzeltme anlamındadır.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Law</strong><br>(Hukuk)</td>\n            <td>Formally change a law or regulation</td>\n            <td>The act was amended to ban discrimination.</td>\n            <td>Yasa, ayrımcılığı yasaklayacak şekilde değiştirildi.</td>\n          </tr>\n          <tr>\n            <td><strong>Politics</strong><br>(Siyaset)</td>\n            <td>Change a constitution or bill</td>\n            <td>The 19th Amendment gave women the right to vote.</td>\n            <td>19. Anayasa Değişikliği kadınlara oy hakkı verdi.</td>\n          </tr>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Modify a contract or agreement</td>\n            <td>Both parties agreed to amend the terms.</td>\n            <td>Her iki taraf da şartları değiştirmeyi kabul etti.</td>\n          </tr>\n          <tr>\n            <td><strong>Taxation</strong><br>(Vergi)</td>\n            <td>Correct a filed return</td>\n            <td>I need to amend my 2024 tax return.</td>\n            <td>2024 vergi beyannamemi düzeltmem gerekiyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Software / Git</strong><br>(Yazılım)</td>\n            <td>Modify the last commit</td>\n            <td>Run \"git commit --amend\" to fix the message.</td>\n            <td>Mesajı düzeltmek için \"git commit --amend\" çalıştırın.</td>\n          </tr>\n          <tr>\n            <td><strong>Personal</strong><br>(Kişisel)</td>\n            <td>Make amends — atone for wrongdoing</td>\n            <td>He spent years trying to make amends.</td>\n            <td>Yıllarca telafi etmeye çalıştı.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "📜", "title": "\"Amendment\" — A Closer Look / Daha Yakından Bakış", "content": "<p>\"Amendment\" isim formu özellikle hukuk ve anayasa bağlamında çok önemlidir. İşte en bilinen örnekler:</p>\n\n      <table>\n        <thead><tr><th>Amendment</th><th>What it protects</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>1st Amendment</strong></td><td>Freedom of speech, religion, press</td><td>İfade, din ve basın özgürlüğü</td></tr>\n          <tr><td><strong>2nd Amendment</strong></td><td>Right to bear arms</td><td>Silah taşıma hakkı</td></tr>\n          <tr><td><strong>4th Amendment</strong></td><td>Protection from unreasonable searches</td><td>Haksız aramalardan korunma</td></tr>\n          <tr><td><strong>5th Amendment</strong></td><td>Right against self-incrimination</td><td>Kendi aleyhine ifade vermeme hakkı</td></tr>\n          <tr><td><strong>13th Amendment</strong></td><td>Abolition of slavery</td><td>Köleliğin kaldırılması</td></tr>\n          <tr><td><strong>19th Amendment</strong></td><td>Women''s right to vote</td><td>Kadınların oy hakkı</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Kültürel not:</strong> Amerikan filmlerinde ve dizilerinde sıkça duyarsınız: <em>\"I plead the Fifth\"</em> (Beşinci Ek Madde''yi ileri sürüyorum) — yani \"kendi aleyhime tanıklık etmeyi reddediyorum.\" Bu, \"5th Amendment\" hakkının günlük dildeki kullanımıdır.\n      </div>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('conduct', 'CONDUCT', 'Verb: /kənˈdʌkt/  ·  Noun: /ˈkɒndʌkt/', 'yürütmek · yönetmek · davranış · iletmek · orkestra yönetmek', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Conduct</strong> hem fiil hem de isim olarak kullanılan, çok yönlü ve resmi bir kelimedir. İş dünyası, bilim, hukuk, müzik ve günlük dilde farklı anlamlarda karşılaşırsınız.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Conduct\" kelimesinin temelinde <em>\"bir şeyi yönlendirmek, bir şeyi bir yere götürmek\"</em> fikri yatar. Latince <em>conducere</em> (bir araya getirmek, yönlendirmek) kökünden gelir. Bu temel fikirden birçok anlam dallanmıştır: (1) bir araştırma/toplantı <em>yürütmek</em>, (2) bir orkestrayı <em>yönetmek</em>, (3) elektrik/ısıyı <em>iletmek</em>, (4) kendini belirli bir şekilde <em>davranmak</em>. İsim olarak ise \"davranış, tutum\" anlamına gelir.</p>\n\n      <div class=\"tip\">\n        <strong>⚠️ Vurgu Farkı — Çok Önemli!</strong><br>\n        <strong>Fiil:</strong> con<strong>DUCT</strong> → /kənˈDʌKT/ → Vurgu ikinci hecede<br>\n        <strong>İsim:</strong> <strong>CON</strong>duct → /ˈKɒNdʌkt/ → Vurgu birinci hecede<br><br>\n        Bu kural İngilizce''de birçok fiil-isim çifti için geçerlidir: <em>record, produce, project, permit, present, protest…</em>\n      </div>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To carry out, organize, or manage (research, meeting, business)</td><td>Yürütmek, gerçekleştirmek, düzenlemek</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To direct an orchestra or choir</td><td>Orkestra/koro yönetmek</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To transmit heat, electricity, or sound</td><td>İletmek (ısı, elektrik, ses)</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To behave in a particular way (conduct oneself)</td><td>Davranmak, hareket etmek</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To guide or lead someone to a place</td><td>Rehberlik etmek, yol göstermek</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>The way a person behaves</td><td>Davranış, tutum, gidiş</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>The management or carrying out of an activity</td><td>Yürütme, idare, yönetim</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>conduct</strong> /kənˈdʌkt/</td><td>verb (fiil)</td><td>yürütmek, yönetmek, iletmek</td></tr>\n          <tr><td><strong>conduct</strong> /ˈkɒndʌkt/</td><td>noun (isim)</td><td>davranış, tutum; yürütme</td></tr>\n          <tr><td><strong>conductor</strong></td><td>noun (isim)</td><td>orkestra şefi; iletken; bilet kontrolörü</td></tr>\n          <tr><td><strong>conductive</strong></td><td>adjective (sıfat)</td><td>iletken (elektrik/ısı ileten)</td></tr>\n          <tr><td><strong>conductivity</strong></td><td>noun (isim)</td><td>iletkenlik</td></tr>\n          <tr><td><strong>misconduct</strong></td><td>noun (isim)</td><td>kötü davranış, görevi kötüye kullanma</td></tr>\n          <tr><td><strong>semiconductor</strong></td><td>noun (isim)</td><td>yarı iletken</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Conduct\" düzenli (regular) bir fiildir: <strong>conduct – conducted – conducted</strong>.\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>conduct + something (research / survey / investigation)</code>\n        <div>→ Bir araştırma/anket/soruşturma yürütmek (EN YAYGIN KULLANIM)</div>\n        <div class=\"example\"><em>The university <strong>conducted</strong> a study on climate change.</em></div>\n        <div class=\"turkish\">Üniversite iklim değişikliği üzerine bir araştırma yürüttü.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>conduct + an orchestra / a choir</code>\n        <div>→ Bir orkestrayı / koroyu yönetmek</div>\n        <div class=\"example\"><em>She <strong>conducts</strong> the Berlin Philharmonic.</em></div>\n        <div class=\"turkish\">Berlin Filarmoni Orkestrası''nı yönetiyor.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>conduct + oneself (well / badly / professionally)</code>\n        <div>→ Kendini iyi / kötü / profesyonelce davranmak</div>\n        <div class=\"example\"><em>He <strong>conducted himself</strong> with great dignity.</em></div>\n        <div class=\"turkish\">Büyük bir vakarla davrandı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>conduct + heat / electricity / sound</code>\n        <div>→ Isı / elektrik / ses iletmek</div>\n        <div class=\"example\"><em>Copper <strong>conducts</strong> electricity very well.</em></div>\n        <div class=\"turkish\">Bakır elektriği çok iyi iletir.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>conduct + someone + to / around / through</code>\n        <div>→ Birini bir yere götürmek / gezdirmek</div>\n        <div class=\"example\"><em>The guide <strong>conducted</strong> us <strong>through</strong> the museum.</em></div>\n        <div class=\"turkish\">Rehber bizi müzede gezdirdi.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>a code of conduct</code>\n        <div>→ Davranış kuralları (isim olarak)</div>\n        <div class=\"example\"><em>Every employee must follow the <strong>code of conduct</strong>.</em></div>\n        <div class=\"turkish\">Her çalışan davranış kurallarına uymalıdır.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>conduct / conducts</td><td>The lab conducts experiments daily.</td><td>Laboratuvar her gün deneyler yürütür.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are conducting</td><td>We are conducting interviews this week.</td><td>Bu hafta mülakatlar yapıyoruz.</td></tr>\n          <tr><td>Simple Past</td><td>conducted</td><td>Police conducted a thorough search.</td><td>Polis kapsamlı bir arama yaptı.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were conducting</td><td>They were conducting a survey when the power went out.</td><td>Elektrik kesildiğinde anket yapıyorlardı.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has conducted</td><td>Researchers have conducted over 200 trials.</td><td>Araştırmacılar 200''den fazla deneme yürüttü.</td></tr>\n          <tr><td>Past Perfect</td><td>had conducted</td><td>She had conducted three interviews before lunch.</td><td>Öğle yemeğinden önce üç mülakat yapmıştı.</td></tr>\n          <tr><td>Future Simple</td><td>will conduct</td><td>The team will conduct a review next month.</td><td>Ekip gelecek ay bir değerlendirme yapacak.</td></tr>\n          <tr><td>Future Perfect</td><td>will have conducted</td><td>By year-end, we will have conducted all audits.</td><td>Yıl sonuna kadar tüm denetimleri yapmış olacağız.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Conduct\" edilgen çatıda çok yaygındır — özellikle bilimsel ve resmi yazılarda:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>They conducted an experiment.</td><td>An experiment <strong>was conducted</strong>.</td><td>Bir deney yapıldı.</td></tr>\n          <tr><td>We are conducting a survey.</td><td>A survey <strong>is being conducted</strong>.</td><td>Bir anket yapılıyor.</td></tr>\n          <tr><td>The police will conduct an investigation.</td><td>An investigation <strong>will be conducted</strong> by the police.</td><td>Polis tarafından bir soruşturma yürütülecek.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>conduct + noun (direct object)</td><td>Conduct a meeting.</td><td>Toplantı yapmak.</td></tr>\n          <tr><td>conduct oneself <strong>with</strong> (dignity/care)</td><td>She conducted herself with grace.</td><td>Zarafetle davrandı.</td></tr>\n          <tr><td>conduct someone <strong>to</strong> (a place)</td><td>He conducted us to the exit.</td><td>Bizi çıkışa götürdü.</td></tr>\n          <tr><td>conduct someone <strong>through</strong> (a place)</td><td>The tour guide conducted us through the castle.</td><td>Tur rehberi bizi kalede gezdirdi.</td></tr>\n          <tr><td>conduct someone <strong>around</strong> (a place)</td><td>She conducted them around the campus.</td><td>Onları kampüste gezdirdi.</td></tr>\n          <tr><td>the conduct <strong>of</strong> (something)</td><td>The conduct of the war was criticized.</td><td>Savaşın yürütülmesi eleştirildi.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">conduct research <span class=\"tr\">— araştırma yapmak</span></span>\n        <span class=\"collocation-tag\">conduct a survey <span class=\"tr\">— anket yapmak</span></span>\n        <span class=\"collocation-tag\">conduct an experiment <span class=\"tr\">— deney yapmak</span></span>\n        <span class=\"collocation-tag\">conduct an investigation <span class=\"tr\">— soruşturma yürütmek</span></span>\n        <span class=\"collocation-tag\">conduct an interview <span class=\"tr\">— mülakat yapmak</span></span>\n        <span class=\"collocation-tag\">conduct a meeting <span class=\"tr\">— toplantı yapmak</span></span>\n        <span class=\"collocation-tag\">conduct business <span class=\"tr\">— iş yürütmek</span></span>\n        <span class=\"collocation-tag\">conduct an audit <span class=\"tr\">— denetim yapmak</span></span>\n        <span class=\"collocation-tag\">code of conduct <span class=\"tr\">— davranış kuralları</span></span>\n        <span class=\"collocation-tag\">professional conduct <span class=\"tr\">— mesleki davranış</span></span>\n        <span class=\"collocation-tag\">good / bad conduct <span class=\"tr\">— iyi / kötü davranış</span></span>\n        <span class=\"collocation-tag\">conduct electricity <span class=\"tr\">— elektrik iletmek</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. The teacher conducted the class outside today.</div>\n          <div class=\"tr\">Öğretmen bugün dersi dışarıda yaptı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. Metal conducts heat quickly.</div>\n          <div class=\"tr\">Metal ısıyı hızla iletir.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. His conduct was unacceptable.</div>\n          <div class=\"tr\">Davranışı kabul edilemezdi.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. The company conducted a customer satisfaction survey last quarter.</div>\n          <div class=\"tr\">Şirket geçen çeyrekte bir müşteri memnuniyeti anketi yaptı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The maestro has conducted orchestras all around the world.</div>\n          <div class=\"tr\">Maestro dünyanın dört bir yanında orkestralar yönetti.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. She always conducts herself professionally in meetings.</div>\n          <div class=\"tr\">Toplantılarda her zaman profesyonelce davranır.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. The study was conducted in accordance with international ethical standards.</div>\n          <div class=\"tr\">Çalışma uluslararası etik standartlara uygun olarak yürütüldü.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. The minister was dismissed for gross misconduct.</div>\n          <div class=\"tr\">Bakan ağır görevi kötüye kullanma nedeniyle görevden alındı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. Semiconductors conduct electricity only under specific conditions.</div>\n          <div class=\"tr\">Yarı iletkenler elektriği yalnızca belirli koşullar altında iletir.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Formal & Legal / Resmi ve Hukuki</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. All staff must adhere to the company''s code of conduct.</div>\n          <div class=\"tr\">Tüm personel şirketin davranış kurallarına uymalıdır.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. An independent body will conduct the inquiry into the incident.</div>\n          <div class=\"tr\">Bağımsız bir kurul olayı soruşturacak.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>15. yüzyıl (İngilizce''ye geçişi)</td></tr>\n          <tr><td><strong>Root</strong></td><td>Latin: <strong>conducere</strong></td></tr>\n          <tr><td><strong>Latin breakdown</strong></td><td><strong>con-</strong> (together, with / birlikte) + <strong>ducere</strong> (to lead / yönlendirmek, götürmek)</td></tr>\n          <tr><td><strong>Literal meaning</strong></td><td>\"Birlikte götürmek, bir araya getirip yönlendirmek\"</td></tr>\n          <tr><td><strong>Behavior sense</strong></td><td>16. yüzyılda \"kendini yönlendirmek\" → \"davranmak\" anlamını kazandı. İsim olarak \"conduct\" (davranış) bu anlamdan türemiştir.</td></tr>\n          <tr><td><strong>Music sense</strong></td><td>18. yüzyılda \"bir orkestrayı yönlendirmek\" anlamı İtalyan müzik geleneğinden İngilizce''ye geçti. Orkestra şefi (conductor) müzisyenleri \"birlikte götüren\" kişidir.</td></tr>\n          <tr><td><strong>Science sense</strong></td><td>18. yüzyılda fizik bilimlerinde \"elektrik/ısıyı bir yerden bir yere taşımak/iletmek\" anlamı yerleşti. Enerji bir iletken (conductor) aracılığıyla \"götürülür.\"</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (ducere = to lead)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>conductor</strong></td><td>one who leads (orchestra, electricity, bus)</td><td>orkestra şefi; iletken; biletçi</td></tr>\n          <tr><td><strong>produce</strong></td><td>to bring forward (pro- + ducere)</td><td>üretmek</td></tr>\n          <tr><td><strong>reduce</strong></td><td>to bring back / lower (re- + ducere)</td><td>azaltmak</td></tr>\n          <tr><td><strong>introduce</strong></td><td>to lead into (intro- + ducere)</td><td>tanıtmak, sunmak</td></tr>\n          <tr><td><strong>educate</strong></td><td>to lead out of ignorance (e- + ducere)</td><td>eğitmek</td></tr>\n          <tr><td><strong>deduce</strong></td><td>to derive by reasoning (de- + ducere)</td><td>sonuç çıkarmak</td></tr>\n          <tr><td><strong>induce</strong></td><td>to lead into, to cause (in- + ducere)</td><td>neden olmak, teşvik etmek</td></tr>\n          <tr><td><strong>duke</strong></td><td>a leader (from Latin <em>dux</em>)</td><td>dük (soylu unvan)</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Conduct\" kelimesini kafanızda bir <em>orkestra şefi</em> olarak hayal edin — o, müzisyenleri <em>birlikte (con-) yönlendirir (ducere)</em>. Aynı mantık her anlama uyar: bir araştırmayı <em>yönlendirirsiniz</em>, kendinizi belirli bir şekilde <em>yönlendirirsiniz</em> (davranış), elektriği bir yere <em>yönlendirirsiniz</em> (iletim). Her şeyin merkezinde \"yönlendirmek\" var.\n      </div>"}, {"icon": "⚖️", "title": "Conduct vs. Carry Out vs. Perform vs. Manage / Farkları", "content": "<p>\"Yürütmek/yapmak\" anlamında kullanılan bu kelimeler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Conduct</th><th>Carry Out</th><th>Perform</th><th>Manage</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Focus</td>\n            <td>Organized, formal execution<br><em>Organize, resmi yürütme</em></td>\n            <td>Completing a planned task<br><em>Planlanmış bir görevi tamamlama</em></td>\n            <td>Doing a task with skill<br><em>Beceri ile bir görevi icra etme</em></td>\n            <td>Overseeing ongoing operations<br><em>Devam eden işleri yönetme</em></td>\n          </tr>\n          <tr>\n            <td>Formality</td>\n            <td>Formal<br><em>Resmi</em></td>\n            <td>Neutral to formal<br><em>Nötr — resmi</em></td>\n            <td>Neutral<br><em>Nötr</em></td>\n            <td>Neutral<br><em>Nötr</em></td>\n          </tr>\n          <tr>\n            <td>Common with</td>\n            <td>Research, surveys, investigations<br><em>Araştırma, anket, soruşturma</em></td>\n            <td>Orders, tasks, experiments<br><em>Emirler, görevler, deneyler</em></td>\n            <td>Surgery, duties, tasks<br><em>Ameliyat, görevler</em></td>\n            <td>Teams, projects, businesses<br><em>Ekipler, projeler, işletmeler</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>Conduct a study.</td>\n            <td>Carry out a plan.</td>\n            <td>Perform surgery.</td>\n            <td>Manage a project.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Bir çalışma yürütmek.</td>\n            <td>Bir planı uygulamak.</td>\n            <td>Ameliyat yapmak.</td>\n            <td>Bir projeyi yönetmek.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Conduct\" en <em>resmi ve organize</em> olanıdır — genellikle araştırma, anket, soruşturma gibi sistematik faaliyetler için kullanılır. \"Carry out\" daha genel bir \"uygulamak/tamamlamak\" anlamındadır. \"Perform\" beceri gerektiren görevler için tercih edilir. \"Manage\" ise sürekli devam eden bir süreci yönetmek içindir.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Science</strong><br>(Bilim)</td>\n            <td>Conducting experiments and research</td>\n            <td>The team conducted a double-blind clinical trial.</td>\n            <td>Ekip çift kör klinik bir deneme yürüttü.</td>\n          </tr>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Conducting meetings, audits, business</td>\n            <td>How we conduct business reflects our values.</td>\n            <td>İş yürütme şeklimiz değerlerimizi yansıtır.</td>\n          </tr>\n          <tr>\n            <td><strong>Law</strong><br>(Hukuk)</td>\n            <td>Conducting investigations, proper conduct</td>\n            <td>The officer''s conduct during the arrest was questioned.</td>\n            <td>Memurun tutuklama sırasındaki davranışı sorgulandı.</td>\n          </tr>\n          <tr>\n            <td><strong>Music</strong><br>(Müzik)</td>\n            <td>Conducting an orchestra or choir</td>\n            <td>He conducted the symphony with great passion.</td>\n            <td>Senfoniyı büyük bir tutkuyla yönetti.</td>\n          </tr>\n          <tr>\n            <td><strong>Physics</strong><br>(Fizik)</td>\n            <td>Materials conducting electricity or heat</td>\n            <td>Water conducts electricity, making it dangerous near wiring.</td>\n            <td>Su elektriği iletir, bu yüzden kablolama yakınında tehlikelidir.</td>\n          </tr>\n          <tr>\n            <td><strong>Education</strong><br>(Eğitim)</td>\n            <td>Conduct reports for students</td>\n            <td>The student received a poor conduct grade.</td>\n            <td>Öğrenci düşük bir davranış notu aldı.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "\"Conductor\" — Multiple Meanings / Birden Fazla Anlam", "content": "<p>\"Conductor\" ismi \"conduct\" fiilinden türemiştir ve bağlama göre çok farklı anlamlara gelir:</p>\n\n      <table>\n        <thead><tr><th>Meaning</th><th>Context</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Orchestra conductor</strong></td>\n            <td>Music</td>\n            <td>The conductor raised his baton.</td>\n            <td>Orkestra şefi batonunu kaldırdı.</td>\n          </tr>\n          <tr>\n            <td><strong>Electrical conductor</strong></td>\n            <td>Physics</td>\n            <td>Copper is an excellent conductor.</td>\n            <td>Bakır mükemmel bir iletkendir.</td>\n          </tr>\n          <tr>\n            <td><strong>Bus/train conductor</strong></td>\n            <td>Transport</td>\n            <td>The conductor checked our tickets.</td>\n            <td>Biletçi biletlerimizi kontrol etti.</td>\n          </tr>\n          <tr>\n            <td><strong>Lightning conductor</strong></td>\n            <td>Building</td>\n            <td>The building has a lightning conductor on the roof.</td>\n            <td>Binanın çatısında yıldırım iletkenı (paratoner) var.</td>\n          </tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Bağlantı:</strong> Tüm \"conductor\" anlamlarında ortak bir fikir vardır: <em>bir şeyi bir yerden başka bir yere yönlendiren/ileten</em>. Orkestra şefi müziği yönlendirir, iletken elektriği iletir, biletçi yolcuları yönlendirir. Hepsi <em>ducere</em> (götürmek) kökünden gelir.\n      </div>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('convince', 'CONVINCE', '/kənˈvɪns/', 'ikna etmek · inandırmak · razı etmek · kanaat getirmek', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Convince</strong> fiil olarak kullanılan, günlük konuşmadan iş dünyasına, hukuktan kişisel ilişkilere kadar hemen her alanda sıkça karşılaşılan güçlü bir kelimedir.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Convince\" kelimesinin özünde <em>\"birinin zihnini değiştirmek, onu bir şeye inandırmak\"</em> fikri yatar. Latince <em>convincere</em> (kesin olarak kanıtlamak, çürütmek) kökünden gelir. Anahtar nokta şudur: \"convince\" ettiğinizde karşı tarafın <em>düşüncesi ve inancı</em> değişir — fiziksel bir eylem değil, zihinsel bir dönüşüm gerçekleşir. Birini \"convinced\" yaparsanız, o artık sizin söylediğinize <em>gerçekten inanıyor</em> demektir. Bu yüzden \"convince\" kelimesi \"persuade\"den (ikna etmek) biraz farklıdır: \"persuade\" birini bir <em>eylem</em> yapmaya ikna ederken, \"convince\" birini bir <em>fikre/duruma</em> inandırır.</p>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To cause someone to believe that something is true</td><td>Birini bir şeyin doğru olduğuna inandırmak</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To persuade someone to do something</td><td>Birini bir şey yapmaya ikna etmek / razı etmek</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Temel ayrım:</strong><br>\n        <strong>Convince someone <em>that</em> …</strong> → Birini bir şeye <em>inandırmak</em> (düşünce değişir)<br>\n        <strong>Convince someone <em>to do</em> …</strong> → Birini bir şey <em>yapmaya</em> ikna etmek (eylem gerçekleşir)<br>\n        Her iki kullanım da doğrudur, ancak geleneksel İngilizce''de \"convince that\" (inandırmak) ve \"persuade to\" (ikna etmek) ayrımı yapılır.\n      </div>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>convince</strong></td><td>verb (fiil)</td><td>ikna etmek, inandırmak</td></tr>\n          <tr><td><strong>convinced</strong></td><td>adjective (sıfat)</td><td>ikna olmuş, emin, kanaat getirmiş</td></tr>\n          <tr><td><strong>convincing</strong></td><td>adjective (sıfat)</td><td>ikna edici, inandırıcı</td></tr>\n          <tr><td><strong>convincingly</strong></td><td>adverb (zarf)</td><td>ikna edici bir şekilde, inandırıcı biçimde</td></tr>\n          <tr><td><strong>unconvinced</strong></td><td>adjective (sıfat)</td><td>ikna olmamış, şüpheci, inanmamış</td></tr>\n          <tr><td><strong>unconvincing</strong></td><td>adjective (sıfat)</td><td>ikna edici olmayan, inandırıcı olmayan</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Convince\" düzenli (regular) bir fiildir: <strong>convince – convinced – convinced</strong>.\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>convince + someone + that + clause</code>\n        <div>→ Birini … olduğuna inandırmak</div>\n        <div class=\"example\"><em>She <strong>convinced me that</strong> the project was worth the risk.</em></div>\n        <div class=\"turkish\">Projenin riske değer olduğuna beni ikna etti.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>convince + someone + to + verb</code>\n        <div>→ Birini … yapmaya ikna etmek</div>\n        <div class=\"example\"><em>I <strong>convinced him to</strong> apply for the job.</em></div>\n        <div class=\"turkish\">Onu işe başvurmaya ikna ettim.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>convince + someone + of + something</code>\n        <div>→ Birini bir şey konusunda ikna etmek / inandırmak</div>\n        <div class=\"example\"><em>The lawyer <strong>convinced the jury of</strong> his client''s innocence.</em></div>\n        <div class=\"turkish\">Avukat jüriyi müvekkilinin masumiyetine ikna etti.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>be convinced + that / of</code>\n        <div>→ … olduğuna ikna olmuş olmak / emin olmak</div>\n        <div class=\"example\"><em>I <strong>am convinced that</strong> this is the right decision.</em></div>\n        <div class=\"turkish\">Bunun doğru karar olduğuna eminim (ikna oldum).</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>convince + oneself (that)</code>\n        <div>→ Kendini … olduğuna inandırmak</div>\n        <div class=\"example\"><em>He <strong>convinced himself that</strong> everything would be fine.</em></div>\n        <div class=\"turkish\">Her şeyin iyi olacağına kendini inandırdı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>it takes a lot to convince + someone</code>\n        <div>→ Birini ikna etmek çok zor / çok şey gerektirir</div>\n        <div class=\"example\"><em><strong>It took a lot to convince</strong> the investors.</em></div>\n        <div class=\"turkish\">Yatırımcıları ikna etmek çok şey gerektirdi.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>convince / convinces</td><td>He always convinces people easily.</td><td>İnsanları her zaman kolayca ikna eder.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are convincing</td><td>She is convincing the board right now.</td><td>Şu anda yönetim kurulunu ikna ediyor.</td></tr>\n          <tr><td>Simple Past</td><td>convinced</td><td>They convinced us to change the plan.</td><td>Bizi planı değiştirmeye ikna ettiler.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were convincing</td><td>He was convincing his parents when I called.</td><td>Ben aradığımda ailesini ikna ediyordu.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has convinced</td><td>She has convinced everyone on the team.</td><td>Takımdaki herkesi ikna etti.</td></tr>\n          <tr><td>Past Perfect</td><td>had convinced</td><td>By the time I arrived, he had already convinced them.</td><td>Ben vardığımda, onları çoktan ikna etmişti.</td></tr>\n          <tr><td>Future Simple</td><td>will convince</td><td>The data will convince the skeptics.</td><td>Veriler şüphecileri ikna edecek.</td></tr>\n          <tr><td>Future Perfect</td><td>will have convinced</td><td>By tomorrow, I will have convinced my boss.</td><td>Yarına kadar patronumu ikna etmiş olacağım.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Convince\" edilgen çatıda sıkça kullanılır — özellikle \"be convinced\" (ikna olmak, emin olmak) yapısında:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>She convinced me.</td><td>I <strong>was convinced</strong> (by her).</td><td>İkna oldum. / İkna edildim.</td></tr>\n          <tr><td>The evidence convinced the jury.</td><td>The jury <strong>was convinced</strong> by the evidence.</td><td>Jüri kanıtlarla ikna edildi.</td></tr>\n          <tr><td>Nobody can convince him.</td><td>He <strong>cannot be convinced</strong>.</td><td>O ikna edilemez.</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"I am convinced\" hem \"İkna edildim\" (edilgen) hem de \"Eminim / İnanıyorum\" (sıfat) anlamına gelebilir. Bağlamdan anlaşılır:<br>\n        ✅ <em>I <strong>am convinced</strong> he is lying.</em> → Yalan söylediğine eminim. (sıfat)<br>\n        ✅ <em>I <strong>was convinced</strong> by her argument.</em> → Argümanıyla ikna edildim. (edilgen)\n      </div>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>convince someone <strong>of</strong> (something)</td><td>He convinced me of his honesty.</td><td>Beni dürüstlüğüne ikna etti.</td></tr>\n          <tr><td>convince someone <strong>to</strong> (do something)</td><td>She convinced him to stay.</td><td>Onu kalması için ikna etti.</td></tr>\n          <tr><td>convinced <strong>that</strong> (clause)</td><td>I''m convinced that it will work.</td><td>İşe yarayacağına eminim.</td></tr>\n          <tr><td>convinced <strong>by</strong> (evidence/person)</td><td>The judge was convinced by the testimony.</td><td>Yargıç ifadeyle ikna oldu.</td></tr>\n          <tr><td>convince someone <strong>about</strong> (topic)</td><td>I couldn''t convince her about the risks.</td><td>Onu riskler konusunda ikna edemedim.</td></tr>\n          <tr><td>not entirely / fully convinced <strong>of/that</strong></td><td>I''m not entirely convinced of the plan.</td><td>Plana tamamen ikna olmuş değilim.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">convince someone to do <span class=\"tr\">— birini yapmaya ikna etmek</span></span>\n        <span class=\"collocation-tag\">convince someone that <span class=\"tr\">— birini inandırmak</span></span>\n        <span class=\"collocation-tag\">fully / completely convinced <span class=\"tr\">— tamamen ikna olmuş</span></span>\n        <span class=\"collocation-tag\">not entirely convinced <span class=\"tr\">— tam olarak ikna olmamış</span></span>\n        <span class=\"collocation-tag\">hard to convince <span class=\"tr\">— ikna etmesi zor</span></span>\n        <span class=\"collocation-tag\">easy to convince <span class=\"tr\">— ikna etmesi kolay</span></span>\n        <span class=\"collocation-tag\">convincing argument <span class=\"tr\">— ikna edici argüman</span></span>\n        <span class=\"collocation-tag\">convincing evidence <span class=\"tr\">— ikna edici kanıt</span></span>\n        <span class=\"collocation-tag\">convincing performance <span class=\"tr\">— inandırıcı performans</span></span>\n        <span class=\"collocation-tag\">convincing victory <span class=\"tr\">— ikna edici / tartışmasız zafer</span></span>\n        <span class=\"collocation-tag\">deeply convinced <span class=\"tr\">— derinden inanmış</span></span>\n        <span class=\"collocation-tag\">remain unconvinced <span class=\"tr\">— ikna olmamaya devam etmek</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. She convinced me to try the new restaurant.</div>\n          <div class=\"tr\">Beni yeni restoranı denemeye ikna etti.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. I''m not convinced that this will work.</div>\n          <div class=\"tr\">Bunun işe yarayacağına ikna olmadım.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. His smile convinced everybody.</div>\n          <div class=\"tr\">Gülümsemesi herkesi ikna etti.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. The CEO convinced the shareholders that the merger was necessary.</div>\n          <div class=\"tr\">CEO, hissedarları birleşmenin gerekli olduğuna ikna etti.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. No amount of money could convince her to sell the house.</div>\n          <div class=\"tr\">Hiçbir miktar para onu evi satmaya ikna edemezdi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. The documentary convinced many viewers to change their eating habits.</div>\n          <div class=\"tr\">Belgesel birçok izleyiciyi yeme alışkanlıklarını değiştirmeye ikna etti.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. Despite overwhelming evidence, the defendant''s lawyer convinced the jury of his innocence.</div>\n          <div class=\"tr\">Ezici kanıtlara rağmen, sanığın avukatı jüriyi onun masumiyetine ikna etti.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. She managed to convince herself that the failure was just a stepping stone.</div>\n          <div class=\"tr\">Başarısızlığın sadece bir basamak taşı olduğuna kendini inandırmayı başardı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. The results were convincing enough to secure further funding for the research.</div>\n          <div class=\"tr\">Sonuçlar, araştırma için ek finansman sağlayacak kadar ikna ediciydi.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Negative & Unconvinced / Olumsuz Kullanımlar</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. I remain unconvinced by his explanation.</div>\n          <div class=\"tr\">Açıklamasına hâlâ ikna olmadım.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. His excuse was unconvincing — no one believed him.</div>\n          <div class=\"tr\">Bahanesi inandırıcı değildi — kimse ona inanmadı.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>16. yüzyıl (1520''ler civarı)</td></tr>\n          <tr><td><strong>Root</strong></td><td>Latin: <strong>convincere</strong></td></tr>\n          <tr><td><strong>Latin breakdown</strong></td><td><strong>con-</strong> (completely, altogether / tamamen) + <strong>vincere</strong> (to conquer, to overcome / fethetmek, yenmek)</td></tr>\n          <tr><td><strong>Literal meaning</strong></td><td>\"Tamamen yenmek, kesin olarak alt etmek\" — harfi harfine \"birinin itirazlarını tamamen yenmek\"</td></tr>\n          <tr><td><strong>Original English meaning</strong></td><td>16. yüzyılda İngilizce''ye girdiğinde \"bir tartışmada kesin olarak haklı çıkarmak, çürütmek\" anlamındaydı. Zamanla \"birini zihinsel olarak ikna etmek\" anlamına yumuşamıştır.</td></tr>\n          <tr><td><strong>Convince vs. Persuade</strong></td><td>Tarihsel olarak \"convince\" = zihinsel inanç, \"persuade\" = eyleme yöneltmek. Ancak modern İngilizce''de \"convince someone to do\" kullanımı da yaygınlaşmıştır.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (vincere = to conquer)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>victory</strong></td><td>an act of winning</td><td>zafer, galibiyet</td></tr>\n          <tr><td><strong>victor</strong></td><td>the winner</td><td>galip, kazanan</td></tr>\n          <tr><td><strong>invincible</strong></td><td>impossible to defeat</td><td>yenilmez</td></tr>\n          <tr><td><strong>evict</strong></td><td>to force someone out (originally \"to conquer out\")</td><td>evden çıkarmak, tahliye etmek</td></tr>\n          <tr><td><strong>convict</strong></td><td>to find guilty (to \"conquer\" in court)</td><td>mahkûm etmek, suçlu bulmak</td></tr>\n          <tr><td><strong>province</strong></td><td>a conquered territory (pro- + vincere)</td><td>il, eyalet (aslında \"fethedilmiş bölge\")</td></tr>\n          <tr><td><strong>Vincent</strong></td><td>a name meaning \"conquering\"</td><td>erkek ismi, \"fetheden\" anlamında</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Convince\" kelimesini kafanızda şöyle düşünün: <em>con</em> (tamamen) + <em>vince</em> (yenmek) = \"birinin şüphelerini tamamen yenmek\". Birini convince ettiğinizde, onun itirazlarını ve şüphelerini \"fethetmiş\" olursunuz — artık o kişi size inanır. \"Victory\" (zafer) ve \"invincible\" (yenilmez) kelimelerini hatırlarsanız, hepsinin kökü aynıdır: <em>vincere</em> = yenmek.\n      </div>"}, {"icon": "⚖️", "title": "Convince vs. Persuade vs. Assure vs. Reassure / Farkları", "content": "<p>\"İkna etmek / inandırmak\" anlamında kullanılan bu kelimeler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Convince</th><th>Persuade</th><th>Assure</th><th>Reassure</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Focus</td>\n            <td>Change someone''s <em>belief/mind</em><br><em>Birinin inancını/düşüncesini değiştirmek</em></td>\n            <td>Get someone to <em>take action</em><br><em>Birini bir eyleme yönlendirmek</em></td>\n            <td>Tell confidently that something is true<br><em>Bir şeyin doğru olduğunu güvenle söylemek</em></td>\n            <td>Remove doubts or worries<br><em>Şüphe veya endişeleri gidermek</em></td>\n          </tr>\n          <tr>\n            <td>Result</td>\n            <td>Person now <em>believes</em><br><em>Kişi artık inanır</em></td>\n            <td>Person now <em>acts</em><br><em>Kişi artık hareket eder</em></td>\n            <td>Person is <em>informed</em><br><em>Kişi bilgilendirilir</em></td>\n            <td>Person feels <em>relieved</em><br><em>Kişi rahatlar</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>She convinced me it was safe.</td>\n            <td>She persuaded me to jump.</td>\n            <td>She assured me it was safe.</td>\n            <td>She reassured me after the scare.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Güvenli olduğuna beni inandırdı.</td>\n            <td>Beni atlamaya ikna etti.</td>\n            <td>Bana güvenli olduğunu temin etti.</td>\n            <td>Korkudan sonra beni rahatlattı.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Convince\" birinin <em>düşüncesini</em> değiştirir. \"Persuade\" birini bir <em>eyleme</em> yönlendirir. \"Assure\" bir <em>bilgi/güvence</em> verir. \"Reassure\" var olan <em>endişeleri giderir</em>. Modern İngilizce''de \"convince to do\" ve \"persuade to do\" birbirinin yerine kullanılsa da, sınavlarda ve resmi yazıda bu farkı bilmek önemlidir.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Persuading clients, investors, or stakeholders</td>\n            <td>We need to convince investors that the product is viable.</td>\n            <td>Yatırımcıları ürünün uygulanabilir olduğuna ikna etmemiz gerekiyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Law</strong><br>(Hukuk)</td>\n            <td>Convincing a judge or jury</td>\n            <td>The prosecution failed to convince the jury.</td>\n            <td>Savcılık jüriyi ikna edemedi.</td>\n          </tr>\n          <tr>\n            <td><strong>Personal</strong><br>(Kişisel)</td>\n            <td>Convincing friends, family, or oneself</td>\n            <td>I finally convinced my parents to let me study abroad.</td>\n            <td>Sonunda ailemi yurt dışında okumama izin vermeye ikna ettim.</td>\n          </tr>\n          <tr>\n            <td><strong>Politics</strong><br>(Siyaset)</td>\n            <td>Convincing voters or opponents</td>\n            <td>The candidate convinced rural voters with her economic plan.</td>\n            <td>Aday, ekonomi planıyla kırsal seçmenleri ikna etti.</td>\n          </tr>\n          <tr>\n            <td><strong>Sales</strong><br>(Satış)</td>\n            <td>Convincing customers to buy</td>\n            <td>A good demo convinces customers better than any brochure.</td>\n            <td>İyi bir demo, müşterileri herhangi bir broşürden daha iyi ikna eder.</td>\n          </tr>\n          <tr>\n            <td><strong>Science</strong><br>(Bilim)</td>\n            <td>Convincing evidence or results</td>\n            <td>The data was convincing enough to publish.</td>\n            <td>Veriler yayımlanacak kadar ikna ediciydi.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "\"Convinced\" & \"Convincing\" as Adjectives / Sıfat Olarak Kullanım", "content": "<p>\"Convinced\" ve \"convincing\" İngilizce''de çok yaygın sıfatlardır. Aralarındaki farkı anlamak önemlidir:</p>\n\n      <table>\n        <thead><tr><th></th><th>Convinced (sıfat)</th><th>Convincing (sıfat)</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Describes</strong></td>\n            <td>The person who <em>believes</em><br><em>İnanan kişiyi tanımlar</em></td>\n            <td>The thing/person that <em>causes belief</em><br><em>İnandıran şeyi/kişiyi tanımlar</em></td>\n          </tr>\n          <tr>\n            <td><strong>Pattern</strong></td>\n            <td>person + is convinced</td>\n            <td>thing/argument + is convincing</td>\n          </tr>\n          <tr>\n            <td><strong>Example</strong></td>\n            <td>I am <strong>convinced</strong> he is telling the truth.</td>\n            <td>His story was very <strong>convincing</strong>.</td>\n          </tr>\n          <tr>\n            <td><strong>Turkish</strong></td>\n            <td>Doğruyu söylediğine eminim.</td>\n            <td>Hikayesi çok inandırıcıydı.</td>\n          </tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Kolay kural:</strong> \"-ed\" sıfatlar <em>hisseden kişiyi</em> tanımlar, \"-ing\" sıfatlar <em>hissettiren şeyi</em> tanımlar. Bu kural tüm duygu fiilleri için geçerlidir:<br>\n        <em>convinced / convincing</em> · <em>surprised / surprising</em> · <em>bored / boring</em> · <em>excited / exciting</em>\n      </div>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('reach-out', 'REACH OUT', '/ˌriːtʃ ˈaʊt/', 'ulaşmak · iletişime geçmek · yardım eli uzatmak · uzanmak · bağlantı kurmak', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Reach out</strong> hem somut (fiziksel) hem de mecazi anlamlarda kullanılan, özellikle iş dünyası ve kişisel iletişimde son derece yaygın bir phrasal verb''dür.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Reach out\" ifadesinin fiziksel kökü <em>\"elini/kolunu uzatmak\"</em>tır — bir şeye dokunmak veya almak için uzanma eylemi. Bu basit hareket, mecazi olarak üç güçlü anlama genişlemiştir: (1) birine <em>iletişime geçmek</em> (e-posta, telefon, mesaj ile), (2) birine <em>yardım eli uzatmak</em> (duygusal veya pratik destek), (3) bir topluluğa veya kitleye <em>erişmeye çalışmak</em>. Bugün özellikle iş e-postalarında ve profesyonel iletişimde \"I''m reaching out to…\" kalıbı İngilizce''nin en yaygın açılış cümlelerinden biridir.</p>\n\n      <table>\n        <thead><tr><th>Usage</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Phrasal Verb</strong><br>Fiziksel</td><td>To extend your hand or arm to touch or grab something</td><td>Elini/kolunu uzatmak, uzanmak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>İletişim</td><td>To contact someone, especially for the first time or after a while</td><td>Birine ulaşmak, iletişime geçmek, bağlantı kurmak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Yardım</td><td>To offer help or support to someone in need</td><td>Yardım eli uzatmak, destek sunmak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Erişim</td><td>To try to communicate with or engage a wider audience</td><td>Daha geniş bir kitleye erişmeye çalışmak</td></tr>\n          <tr><td><strong>Noun</strong><br>(outreach)</td><td>The act of reaching out to communities or the public</td><td>Sosyal yardım faaliyeti, topluma ulaşma çabası</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>reach out</strong></td><td>phrasal verb (öbekli fiil)</td><td>ulaşmak, iletişime geçmek, uzanmak</td></tr>\n          <tr><td><strong>reached out</strong></td><td>past tense / past participle</td><td>ulaştı, iletişime geçti</td></tr>\n          <tr><td><strong>reaching out</strong></td><td>present participle</td><td>ulaşıyor, iletişime geçiyor</td></tr>\n          <tr><td><strong>outreach</strong></td><td>noun (isim) / adjective (sıfat)</td><td>topluma ulaşma, sosyal yardım faaliyeti</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Fiil Bilgisi:</strong><br>\n        \"Reach\" düzenli (regular) bir fiildir: <strong>reach – reached – reached</strong>. \"Out\" kısmı değişmez.<br><br>\n        <strong>Ayrılabilir mi?</strong> \"Reach out\" <strong>ayrılamaz</strong> (inseparable) — iletişim/yardım anlamında nesne araya girmez:<br>\n        ✅ <em>I <strong>reached out to</strong> him.</em><br>\n        ❌ <em>I <strong>reached him out</strong>.</em> (Yanlış!)<br><br>\n        Ancak fiziksel anlamda sınırlı olarak ayrılabilir:<br>\n        ✅ <em>She <strong>reached out</strong> her hand.</em><br>\n        ✅ <em>She <strong>reached</strong> her hand <strong>out</strong>.</em>\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>reach out to + someone</code>\n        <div>→ Birine ulaşmak / iletişime geçmek (EN YAYGIN KULLANIM)</div>\n        <div class=\"example\"><em>I''ll <strong>reach out to</strong> the client tomorrow.</em></div>\n        <div class=\"turkish\">Yarın müşteriyle iletişime geçeceğim.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>reach out + for + something</code>\n        <div>→ Bir şeye uzanmak (fiziksel); bir şey için başvurmak</div>\n        <div class=\"example\"><em>He <strong>reached out for</strong> the glass on the shelf.</em></div>\n        <div class=\"turkish\">Raftaki bardağa uzandı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>reach out to + someone + for help</code>\n        <div>→ Yardım için birine ulaşmak</div>\n        <div class=\"example\"><em>Don''t hesitate to <strong>reach out to us for help</strong>.</em></div>\n        <div class=\"turkish\">Yardım için bize ulaşmaktan çekinmeyin.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>reach out + to help / to support</code>\n        <div>→ Yardım etmek / destek olmak için el uzatmak</div>\n        <div class=\"example\"><em>The community <strong>reached out to help</strong> the flood victims.</em></div>\n        <div class=\"turkish\">Topluluk sel mağdurlarına yardım eli uzattı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>feel free to reach out</code>\n        <div>→ Çekinmeden ulaşın / iletişime geçin (profesyonel kalıp)</div>\n        <div class=\"example\"><em><strong>Feel free to reach out</strong> if you have any questions.</em></div>\n        <div class=\"turkish\">Herhangi bir sorunuz varsa çekinmeden ulaşın.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>I''m reaching out because…</code>\n        <div>→ Size ulaşıyorum çünkü… (e-posta açılış kalıbı)</div>\n        <div class=\"example\"><em><strong>I''m reaching out because</strong> I''d like to discuss a partnership.</em></div>\n        <div class=\"turkish\">Bir ortaklığı görüşmek istediğim için size ulaşıyorum.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>reach(es) out</td><td>She reaches out to new clients every week.</td><td>Her hafta yeni müşterilere ulaşır.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are reaching out</td><td>I''m reaching out to discuss an opportunity.</td><td>Bir fırsatı görüşmek için ulaşıyorum.</td></tr>\n          <tr><td>Simple Past</td><td>reached out</td><td>He reached out to me last week.</td><td>Geçen hafta bana ulaştı.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were reaching out</td><td>They were reaching out to donors when the news broke.</td><td>Haber geldiğinde bağışçılara ulaşıyorlardı.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has reached out</td><td>We have reached out to several suppliers.</td><td>Birkaç tedarikçiyle iletişime geçtik.</td></tr>\n          <tr><td>Past Perfect</td><td>had reached out</td><td>She had already reached out before I could.</td><td>Ben yapamadan o çoktan ulaşmıştı.</td></tr>\n          <tr><td>Future Simple</td><td>will reach out</td><td>I will reach out to them on Monday.</td><td>Pazartesi onlara ulaşacağım.</td></tr>\n          <tr><td>Future Perfect</td><td>will have reached out</td><td>By Friday, we will have reached out to all candidates.</td><td>Cuma''ya kadar tüm adaylara ulaşmış olacağız.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Reach out\" edilgen çatıda nadiren kullanılır, çünkü genellikle aktif bir eylemdir. Ancak isim formu \"outreach\" edilgen bağlamlarda yaygındır:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Alternative (noun form)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>The team reached out to the community.</td><td>Community <strong>outreach</strong> was conducted by the team.</td><td>Topluma ulaşma faaliyeti ekip tarafından gerçekleştirildi.</td></tr>\n          <tr><td>She reached out to 50 leads.</td><td>50 leads <strong>were contacted</strong> through outreach.</td><td>50 potansiyel müşteriye ulaşım çalışmasıyla iletişime geçildi.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>reach out <strong>to</strong> (someone)</td><td>I reached out to the manager.</td><td>Müdüre ulaştım.</td></tr>\n          <tr><td>reach out <strong>for</strong> (something)</td><td>She reached out for the book.</td><td>Kitaba uzandı.</td></tr>\n          <tr><td>reach out <strong>for</strong> (help/support)</td><td>He reached out for professional help.</td><td>Profesyonel yardım için başvurdu.</td></tr>\n          <tr><td>reach out <strong>about</strong> (a topic)</td><td>I''m reaching out about the job posting.</td><td>İş ilanıyla ilgili ulaşıyorum.</td></tr>\n          <tr><td>reach out <strong>via</strong> (method)</td><td>You can reach out via email or phone.</td><td>E-posta veya telefonla ulaşabilirsiniz.</td></tr>\n          <tr><td>reach out <strong>across</strong> (a divide)</td><td>Leaders must reach out across political divides.</td><td>Liderler siyasi ayrılıkların ötesine uzanmalı.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">reach out to someone <span class=\"tr\">— birine ulaşmak</span></span>\n        <span class=\"collocation-tag\">reach out for help <span class=\"tr\">— yardım istemek</span></span>\n        <span class=\"collocation-tag\">reach out for support <span class=\"tr\">— destek aramak</span></span>\n        <span class=\"collocation-tag\">feel free to reach out <span class=\"tr\">— çekinmeden ulaşın</span></span>\n        <span class=\"collocation-tag\">don''t hesitate to reach out <span class=\"tr\">— ulaşmaktan çekinmeyin</span></span>\n        <span class=\"collocation-tag\">I''m reaching out because <span class=\"tr\">— ulaşıyorum çünkü</span></span>\n        <span class=\"collocation-tag\">reach out and touch <span class=\"tr\">— uzanıp dokunmak</span></span>\n        <span class=\"collocation-tag\">community outreach <span class=\"tr\">— topluma ulaşma faaliyeti</span></span>\n        <span class=\"collocation-tag\">outreach program <span class=\"tr\">— ulaşım/sosyal yardım programı</span></span>\n        <span class=\"collocation-tag\">customer outreach <span class=\"tr\">— müşteriye ulaşma çabası</span></span>\n        <span class=\"collocation-tag\">voter outreach <span class=\"tr\">— seçmene ulaşma</span></span>\n        <span class=\"collocation-tag\">reach out a hand <span class=\"tr\">— el uzatmak</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. She reached out and grabbed my hand.</div>\n          <div class=\"tr\">Uzanıp elimi tuttu.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. I reached out to my old friend on social media.</div>\n          <div class=\"tr\">Sosyal medyadan eski arkadaşıma ulaştım.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. If you need anything, just reach out.</div>\n          <div class=\"tr\">Bir şeye ihtiyacın olursa, sadece ulaş / haber ver.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. I''m reaching out to see if you''d be interested in collaborating.</div>\n          <div class=\"tr\">İş birliği yapmakla ilgilenip ilgilenmediğinizi öğrenmek için ulaşıyorum.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The charity reaches out to homeless people during winter.</div>\n          <div class=\"tr\">Yardım kuruluşu kış aylarında evsiz insanlara yardım eli uzatır.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. Don''t hesitate to reach out if you have any questions about the offer.</div>\n          <div class=\"tr\">Teklifle ilgili herhangi bir sorunuz varsa iletişime geçmekten çekinmeyin.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. The government is reaching out across party lines to build consensus on the reform.</div>\n          <div class=\"tr\">Hükümet, reform konusunda uzlaşı sağlamak için parti sınırlarının ötesine uzanıyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. Mental health organizations encourage people to reach out before a crisis develops.</div>\n          <div class=\"tr\">Ruh sağlığı kuruluşları insanları bir kriz gelişmeden yardım istemeye teşvik ediyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. The company''s outreach campaign successfully engaged underserved communities in the region.</div>\n          <div class=\"tr\">Şirketin ulaşım kampanyası bölgedeki yeterince hizmet alamayan toplulukları başarıyla kapsadı.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Professional Emails / Profesyonel E-postalar</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. Hi Sarah, I''m reaching out because I saw your presentation at the conference.</div>\n          <div class=\"tr\">Merhaba Sarah, konferanstaki sunumunuzu gördüğüm için size ulaşıyorum.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. Thank you for reaching out. I''ll get back to you by end of day.</div>\n          <div class=\"tr\">Ulaştığınız için teşekkürler. Gün sonuna kadar size döneceğim.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">12. Please feel free to reach out at any time — my door is always open.</div>\n          <div class=\"tr\">Lütfen istediğiniz zaman ulaşın — kapım her zaman açıktır.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Type</strong></td><td>Phrasal verb: <strong>reach</strong> + <strong>out</strong></td></tr>\n          <tr><td><strong>\"Reach\" origin</strong></td><td>Old English: <strong>rǣcan</strong> (to stretch out, to extend the hand) → Proto-Germanic: <strong>*raikijaną</strong> → PIE root: <strong>*h₃reyǵ-</strong> (to stretch, to extend / uzanmak, germek)</td></tr>\n          <tr><td><strong>\"Out\" origin</strong></td><td>Old English: <strong>ūt</strong> → Proto-Germanic: <strong>*ūt</strong> (out, outside / dışarı)</td></tr>\n          <tr><td><strong>Literal meaning</strong></td><td>\"Elini/kolunu dışarıya doğru uzatmak\" — fiziksel bir uzanma eylemi</td></tr>\n          <tr><td><strong>Contact sense</strong></td><td>\"Birine iletişime geçmek\" anlamı 20. yüzyılda özellikle Amerikan İngilizce''sinde yaygınlaştı. Telefon ve e-postanın yaygınlaşmasıyla \"ulaşmak\" mecazı güçlendi. 2000''lerden sonra iş İngilizce''sinin vazgeçilmez bir kalıbı oldu.</td></tr>\n          <tr><td><strong>Help sense</strong></td><td>\"Yardım eli uzatmak\" anlamı 1960''lar ve 1970''lerde toplumsal hareketlerle birlikte yaygınlaştı. Kilise ve sosyal hizmet kuruluşları \"outreach\" kavramını popülerleştirdi.</td></tr>\n          <tr><td><strong>\"Outreach\" as noun</strong></td><td>\"Outreach\" isim formu 1960''lardan itibaren \"topluma ulaşma faaliyeti\" anlamında kullanılmaya başlandı. Günümüzde \"community outreach\", \"voter outreach\", \"customer outreach\" gibi bileşiklerde çok yaygındır.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (*h₃reyǵ- = to stretch)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>reach</strong></td><td>to extend; to arrive at</td><td>uzanmak; ulaşmak, varmak</td></tr>\n          <tr><td><strong>outreach</strong></td><td>effort to connect with a community</td><td>topluma ulaşma çabası</td></tr>\n          <tr><td><strong>overreach</strong></td><td>to go too far; to exceed one''s limits</td><td>haddini aşmak, gereğinden fazla uzanmak</td></tr>\n          <tr><td><strong>far-reaching</strong></td><td>having wide effects or influence</td><td>geniş kapsamlı, uzun vadeli etkileri olan</td></tr>\n          <tr><td><strong>within reach</strong></td><td>close enough to touch or achieve</td><td>erişilebilir, el altında</td></tr>\n          <tr><td><strong>out of reach</strong></td><td>too far to touch; unattainable</td><td>erişilmez, ulaşılmaz</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Reach out\" ifadesini kafanızda şöyle hayal edin: Birinin size doğru <em>elini uzattığını</em> düşünün — bu hareket hem \"sana yardım etmek istiyorum\" hem de \"seninle konuşmak istiyorum\" demektir. İster bir e-postada \"I''m reaching out…\" diye yazın, ister birine destek sunun, özünde hep aynı jest: <em>el uzatmak</em>.\n      </div>"}, {"icon": "⚖️", "title": "Reach Out vs. Contact vs. Get in Touch vs. Connect / Farkları", "content": "<p>\"Birine ulaşmak/iletişime geçmek\" anlamında kullanılan bu ifadeler arasında önemli ton ve kullanım farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Reach Out</th><th>Contact</th><th>Get in Touch</th><th>Connect</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Tone</td>\n            <td>Warm, personal, proactive<br><em>Sıcak, kişisel, proaktif</em></td>\n            <td>Neutral, professional<br><em>Nötr, profesyonel</em></td>\n            <td>Friendly, casual<br><em>Samimi, günlük</em></td>\n            <td>Network-focused, modern<br><em>Ağ odaklı, modern</em></td>\n          </tr>\n          <tr>\n            <td>Implies</td>\n            <td>Initiative, care, intention<br><em>İnisiyatif, ilgi, niyet</em></td>\n            <td>Simple communication<br><em>Basit iletişim</em></td>\n            <td>Mutual, relaxed<br><em>Karşılıklı, rahat</em></td>\n            <td>Building a relationship<br><em>İlişki kurma</em></td>\n          </tr>\n          <tr>\n            <td>Common in</td>\n            <td>Emails, business, support<br><em>E-posta, iş, destek</em></td>\n            <td>Formal, customer service<br><em>Resmi, müşteri hizmetleri</em></td>\n            <td>Casual, British English<br><em>Günlük, İngiliz İngilizce''si</em></td>\n            <td>LinkedIn, networking<br><em>LinkedIn, ağ oluşturma</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>I''m reaching out to discuss…</td>\n            <td>Please contact our office.</td>\n            <td>Let''s get in touch soon.</td>\n            <td>Let''s connect on LinkedIn.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>… hakkında konuşmak için ulaşıyorum.</td>\n            <td>Lütfen ofisimizle iletişime geçin.</td>\n            <td>Yakında haberleşelim.</td>\n            <td>LinkedIn''den bağlantı kuralım.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Reach out\" en <em>sıcak ve proaktif</em> olanıdır — \"Sana geliyor, sana uzanıyorum\" hissi verir. \"Contact\" en <em>resmi ve nötr</em> olanıdır — sadece iletişim. \"Get in touch\" daha <em>samimi ve karşılıklı</em>. \"Connect\" ise özellikle <em>profesyonel ağ kurma</em> (networking) bağlamında tercih edilir.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Contacting clients, partners, or leads</td>\n            <td>I''m reaching out regarding your recent inquiry.</td>\n            <td>Son sorgunuzla ilgili ulaşıyorum.</td>\n          </tr>\n          <tr>\n            <td><strong>Sales & Marketing</strong><br>(Satış & Pazarlama)</td>\n            <td>Cold outreach to potential customers</td>\n            <td>Our outreach campaign generated 500 leads.</td>\n            <td>Ulaşım kampanyamız 500 potansiyel müşteri oluşturdu.</td>\n          </tr>\n          <tr>\n            <td><strong>Mental Health</strong><br>(Ruh Sağlığı)</td>\n            <td>Asking for help when struggling</td>\n            <td>It''s okay to reach out when you''re feeling overwhelmed.</td>\n            <td>Bunaldığınızda yardım istemek normaldir.</td>\n          </tr>\n          <tr>\n            <td><strong>Community</strong><br>(Toplum)</td>\n            <td>Outreach programs for underserved populations</td>\n            <td>The outreach program provides free meals to families.</td>\n            <td>Ulaşım programı ailelere ücretsiz yemek sağlıyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Politics</strong><br>(Siyaset)</td>\n            <td>Reaching out to voters or rival parties</td>\n            <td>The senator reached out across the aisle to gain bipartisan support.</td>\n            <td>Senatör, çift taraflı destek kazanmak için karşı tarafa el uzattı.</td>\n          </tr>\n          <tr>\n            <td><strong>Personal</strong><br>(Kişisel)</td>\n            <td>Reconnecting with old friends or family</td>\n            <td>I reached out to my estranged brother after years of silence.</td>\n            <td>Yıllarca süren sessizliğin ardından küs kardeşime ulaştım.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "Other Uses & Phrases with \"Reach\" / \"Reach\" İle Diğer Kullanımlar", "content": "<table>\n        <thead><tr><th>Expression</th><th>Meaning</th><th>Turkish</th><th>Example</th></tr></thead>\n        <tbody>\n          <tr><td><strong>reach for</strong></td><td>to try to grab something</td><td>bir şeye uzanmak</td><td>He reached for his wallet.</td></tr>\n          <tr><td><strong>reach out to</strong></td><td>to contact; to offer help</td><td>ulaşmak; yardım eli uzatmak</td><td>Reach out to us anytime.</td></tr>\n          <tr><td><strong>within reach</strong></td><td>attainable, accessible</td><td>erişilebilir, ulaşılabilir</td><td>Success is within reach.</td></tr>\n          <tr><td><strong>out of reach</strong></td><td>unattainable, too far</td><td>ulaşılmaz, erişilmez</td><td>The goal felt out of reach.</td></tr>\n          <tr><td><strong>far-reaching</strong></td><td>having wide impact</td><td>geniş kapsamlı</td><td>The decision had far-reaching consequences.</td></tr>\n          <tr><td><strong>overreach</strong></td><td>to go beyond one''s limits</td><td>haddini aşmak</td><td>The company overreached and collapsed.</td></tr>\n          <tr><td><strong>reach a conclusion</strong></td><td>to arrive at a decision</td><td>bir sonuca varmak</td><td>We finally reached a conclusion.</td></tr>\n        </tbody>\n      </table>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('refinement', 'REFINEMENT', '/rɪˈfaɪnmənt/', 'iyileştirme · incelik · arıtma · zarafet · geliştirme · saflaştırma', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Refinement</strong> hem somut hem soyut anlamlarda kullanılan bir isimdir. Temel fikri <em>\"bir şeyi daha iyi, daha saf veya daha zarif hale getirme süreci ya da sonucu\"</em>dur.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Refinement\" kelimesi <em>\"refine\"</em> (iyileştirmek, arıtmak) fiiline <em>\"-ment\"</em> eki getirilerek oluşturulmuştur. Üç ana anlam katmanı vardır: (1) <strong>Fiziksel arıtma</strong> — ham petrolü, şekeri veya metali safsızlıklardan temizleyip saf hale getirme süreci. (2) <strong>Soyut iyileştirme</strong> — bir fikri, planı, tasarımı veya ürünü küçük ama önemli değişikliklerle daha iyi hale getirme. (3) <strong>Zarafet ve incelik</strong> — bir kişinin veya ortamın kültürel olgunluğu, davranış inceliği. Yazılım dünyasında \"refinement\" terimi çok yaygındır: Agile/Scrum''da \"backlog refinement\" (iş listesi iyileştirme) sürecini ifade eder.</p>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Noun</strong> (isim)</td><td>The process of making something better by small changes</td><td>İyileştirme, geliştirme</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>The process of removing impurities from a substance</td><td>Arıtma, saflaştırma, tasfiye</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>An improvement or modification made to something</td><td>İyileştirme, düzeltme (yapılan değişiklik)</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>Elegance and cultured quality in behavior or taste</td><td>Zarafet, incelik, nezaket</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>(Software) The act of clarifying and detailing requirements</td><td>Refinement / gereksinimleri netleştirme (yazılım)</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>refine</strong></td><td>verb (fiil)</td><td>iyileştirmek, arıtmak, saflaştırmak</td></tr>\n          <tr><td><strong>refined</strong></td><td>adjective (sıfat)</td><td>rafine, zarif, inceltilmiş, işlenmiş</td></tr>\n          <tr><td><strong>refinement</strong></td><td>noun (isim)</td><td>iyileştirme, arıtma, zarafet</td></tr>\n          <tr><td><strong>refinery</strong></td><td>noun (isim)</td><td>rafineri, arıtma tesisi</td></tr>\n          <tr><td><strong>refiner</strong></td><td>noun (isim)</td><td>arıtıcı; rafinerici</td></tr>\n          <tr><td><strong>unrefined</strong></td><td>adjective (sıfat)</td><td>işlenmemiş, ham; kaba, nezaketsiz</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Refinement\" sayılabilir ve sayılamaz isim olarak kullanılır.<br>\n        <strong>Sayılamaz:</strong> \"a person of great refinement\" (büyük zarafet sahibi biri)<br>\n        <strong>Sayılabilir:</strong> \"several refinements to the design\" (tasarıma yapılan birkaç iyileştirme)\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>refinement of + something</code>\n        <div>→ Bir şeyin iyileştirilmesi / arıtılması</div>\n        <div class=\"example\"><em>The <strong>refinement of</strong> the algorithm took weeks.</em></div>\n        <div class=\"turkish\">Algoritmanın iyileştirilmesi haftalarca sürdü.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>refinement to + something</code>\n        <div>→ Bir şeye yapılan iyileştirme (değişiklik odaklı)</div>\n        <div class=\"example\"><em>We made several <strong>refinements to</strong> the user interface.</em></div>\n        <div class=\"turkish\">Kullanıcı arayüzüne birkaç iyileştirme yaptık.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>refinement in + something</code>\n        <div>→ Bir alandaki iyileşme / gelişme</div>\n        <div class=\"example\"><em>There has been a significant <strong>refinement in</strong> manufacturing processes.</em></div>\n        <div class=\"turkish\">Üretim süreçlerinde önemli bir iyileşme yaşandı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>a person of (great) refinement</code>\n        <div>→ (Büyük) zarafet / incelik sahibi biri</div>\n        <div class=\"example\"><em>She was a woman of considerable <strong>refinement</strong>.</em></div>\n        <div class=\"turkish\">Hatırı sayılır derecede zarif bir kadındı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>backlog refinement (Software/Agile)</code>\n        <div>→ İş listesi iyileştirme toplantısı (Scrum)</div>\n        <div class=\"example\"><em>We discuss user stories during <strong>backlog refinement</strong>.</em></div>\n        <div class=\"turkish\">Kullanıcı hikâyelerini backlog refinement sırasında tartışırız.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>further / continuous refinement</code>\n        <div>→ Daha fazla / sürekli iyileştirme</div>\n        <div class=\"example\"><em>The model needs <strong>further refinement</strong> before deployment.</em></div>\n        <div class=\"turkish\">Model dağıtımdan önce daha fazla iyileştirme gerektiriyor.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses: \"Refine\" / Fiil Zamanları", "content": "<div class=\"tip\" style=\"margin-bottom: 1rem;\">\n        <strong>📌 Not:</strong> \"Refinement\" bir isimdir, fiil olarak kullanılmaz. Fiil hali <strong>refine</strong>''dır. Düzenli (regular) fiildir: <strong>refine – refined – refined</strong>.\n      </div>\n\n      <table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>refine / refines</td><td>She refines the code after every review.</td><td>Her incelemeden sonra kodu iyileştirir.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are refining</td><td>We are refining our marketing strategy.</td><td>Pazarlama stratejimizi iyileştiriyoruz.</td></tr>\n          <tr><td>Simple Past</td><td>refined</td><td>They refined the process over several months.</td><td>Süreci birkaç ay boyunca iyileştirdiler.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were refining</td><td>The team was refining the requirements when the deadline changed.</td><td>Süre sonu değiştiğinde ekip gereksinimleri netleştiriyordu.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has refined</td><td>Engineers have refined the engine significantly.</td><td>Mühendisler motoru önemli ölçüde iyileştirdiler.</td></tr>\n          <tr><td>Past Perfect</td><td>had refined</td><td>By the time of launch, we had refined every detail.</td><td>Lansman zamanında her detayı iyileştirmiştik.</td></tr>\n          <tr><td>Future Simple</td><td>will refine</td><td>We will refine the model based on feedback.</td><td>Geri bildirimlere göre modeli iyileştireceğiz.</td></tr>\n          <tr><td>Future Perfect</td><td>will have refined</td><td>By next sprint, we will have refined all user stories.</td><td>Gelecek sprinte kadar tüm kullanıcı hikâyelerini iyileştirmiş olacağız.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Refine\" edilgen çatıda hem endüstriyel hem soyut bağlamda yaygındır:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Workers refine the crude oil.</td><td>The crude oil <strong>is refined</strong> at the plant.</td><td>Ham petrol tesiste arıtılır.</td></tr>\n          <tr><td>They refined the proposal.</td><td>The proposal <strong>was refined</strong> after feedback.</td><td>Teklif geri bildirimden sonra iyileştirildi.</td></tr>\n          <tr><td>We are refining the UI.</td><td>The UI <strong>is being refined</strong>.</td><td>Kullanıcı arayüzü iyileştiriliyor.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>refinement <strong>of</strong> (something)</td><td>The refinement of sugar involves multiple stages.</td><td>Şekerin arıtılması birden fazla aşama içerir.</td></tr>\n          <tr><td>refinement <strong>to</strong> (something)</td><td>They added refinements to the draft.</td><td>Taslağa iyileştirmeler eklediler.</td></tr>\n          <tr><td>refinement <strong>in</strong> (an area)</td><td>Refinement in AI models has accelerated.</td><td>Yapay zekâ modellerindeki gelişme hızlandı.</td></tr>\n          <tr><td>refine <strong>into</strong> (a product)</td><td>Crude oil is refined into gasoline.</td><td>Ham petrol benzine dönüştürülür.</td></tr>\n          <tr><td><strong>with</strong> refinement</td><td>She handled the situation with refinement.</td><td>Durumu zarafetle yönetti.</td></tr>\n          <tr><td><strong>through</strong> refinement</td><td>Quality improves through constant refinement.</td><td>Kalite, sürekli iyileştirme yoluyla artar.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">backlog refinement <span class=\"tr\">— iş listesi iyileştirme (Scrum)</span></span>\n        <span class=\"collocation-tag\">continuous refinement <span class=\"tr\">— sürekli iyileştirme</span></span>\n        <span class=\"collocation-tag\">further refinement <span class=\"tr\">— ileri iyileştirme</span></span>\n        <span class=\"collocation-tag\">gradual refinement <span class=\"tr\">— kademeli iyileştirme</span></span>\n        <span class=\"collocation-tag\">oil refinement <span class=\"tr\">— petrol arıtma</span></span>\n        <span class=\"collocation-tag\">sugar refinement <span class=\"tr\">— şeker arıtma</span></span>\n        <span class=\"collocation-tag\">cultural refinement <span class=\"tr\">— kültürel incelik</span></span>\n        <span class=\"collocation-tag\">social refinement <span class=\"tr\">— sosyal zarafet</span></span>\n        <span class=\"collocation-tag\">iterative refinement <span class=\"tr\">— yinelemeli iyileştirme</span></span>\n        <span class=\"collocation-tag\">design refinement <span class=\"tr\">— tasarım iyileştirmesi</span></span>\n        <span class=\"collocation-tag\">process refinement <span class=\"tr\">— süreç iyileştirme</span></span>\n        <span class=\"collocation-tag\">make refinements <span class=\"tr\">— iyileştirmeler yapmak</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. The plan needs some refinement before we present it.</div>\n          <div class=\"tr\">Sunmadan önce planın biraz iyileştirilmesi gerekiyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. Oil refinement is a complex industrial process.</div>\n          <div class=\"tr\">Petrol arıtma karmaşık bir endüstriyel süreçtir.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. Her refinement and good manners impressed everyone.</div>\n          <div class=\"tr\">Zarafeti ve iyi davranışları herkesi etkiledi.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. After several rounds of refinement, the product was ready for launch.</div>\n          <div class=\"tr\">Birkaç tur iyileştirmeden sonra ürün lansmana hazırdı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The refinement of the search algorithm improved results by 30%.</div>\n          <div class=\"tr\">Arama algoritmasının iyileştirilmesi sonuçları %30 artırdı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. The hotel''s interior reflects a level of refinement you rarely see.</div>\n          <div class=\"tr\">Otelin iç tasarımı nadiren gördüğünüz bir incelik seviyesini yansıtıyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. We made several refinements to the contract wording.</div>\n          <div class=\"tr\">Sözleşme ifadelerinde birkaç iyileştirme yaptık.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. The iterative refinement of machine learning models is essential for accuracy.</div>\n          <div class=\"tr\">Makine öğrenimi modellerinin yinelemeli iyileştirilmesi, doğruluk için vazgeçilmezdir.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. Through decades of refinement, Japanese craftsmanship has become synonymous with precision.</div>\n          <div class=\"tr\">Onlarca yıllık inceleme/işleme süreciyle Japon zanaatkârlığı, hassasiyetin eş anlamlısı haline geldi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. The paper represents a significant refinement of earlier theories on quantum entanglement.</div>\n          <div class=\"tr\">Makale, kuantum dolanıklığına ilişkin önceki teorilerin önemli bir geliştirilmesini temsil ediyor.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Technology / Teknoloji</div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. Backlog refinement helps the team understand upcoming work.</div>\n          <div class=\"tr\">Backlog refinement, ekibin yaklaşan işleri anlamasına yardımcı olur.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">12. Each sprint brings further refinement to the application''s UX.</div>\n          <div class=\"tr\">Her sprint, uygulamanın kullanıcı deneyimine daha fazla iyileştirme getirir.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>17. yüzyıl başları (İngilizce''de ilk kullanım)</td></tr>\n          <tr><td><strong>Formation</strong></td><td><strong>refine</strong> (fiil) + <strong>-ment</strong> (isim yapma eki)</td></tr>\n          <tr><td><strong>Root verb</strong></td><td><strong>refine</strong> → 16. yüzyılda Fransızca <em>raffiner</em>''den İngilizce''ye geçti</td></tr>\n          <tr><td><strong>French root</strong></td><td><strong>raffiner</strong> → <strong>re-</strong> (again / tekrar) + <strong>affiner</strong> (to make fine / inceltmek, saflaştırmak)</td></tr>\n          <tr><td><strong>Latin base</strong></td><td><strong>fīnis</strong> (end, limit / son, sınır) → \"son noktasına kadar işlemek\" fikri → Latin <strong>fīnus</strong> → Latince <strong>fīnīre</strong> → eski Fransızca <strong>fin</strong> (fine, pure / ince, saf)</td></tr>\n          <tr><td><strong>Literal sense</strong></td><td>\"Tekrar tekrar inceltme / saflaştırma\" — ham bir maddeyi veya fikri her seferinde biraz daha saf ve iyi hale getirmek</td></tr>\n          <tr><td><strong>Industrial meaning</strong></td><td>17. yüzyılda şeker ve metal arıtma endüstrilerinde yaygınlaştı. \"Refinery\" (rafineri) kelimesi de bu dönemde ortaya çıktı.</td></tr>\n          <tr><td><strong>Abstract meaning</strong></td><td>18. yüzyılda \"davranış, zevk ve kültür inceliği\" anlamı eklendi — Aydınlanma Çağı''nda \"refined person\" (zarif/kültürlü insan) kavramı önem kazandı.</td></tr>\n          <tr><td><strong>Software meaning</strong></td><td>20. yüzyılın sonlarından itibaren yazılım mühendisliğinde \"gereksinimleri netleştirme, ürünü kademeli olarak iyileştirme\" anlamında yaygınlaştı. Agile/Scrum''da \"backlog refinement\" standart bir tören haline geldi.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (fīnis = fine, end)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>refine</strong></td><td>to improve, to purify</td><td>iyileştirmek, arıtmak</td></tr>\n          <tr><td><strong>refined</strong></td><td>elegant; purified</td><td>zarif; rafine, arıtılmış</td></tr>\n          <tr><td><strong>refinery</strong></td><td>a factory for purifying substances</td><td>rafineri</td></tr>\n          <tr><td><strong>fine</strong></td><td>of high quality; thin; a penalty</td><td>ince, güzel, kaliteli; ceza</td></tr>\n          <tr><td><strong>finish</strong></td><td>to bring to an end</td><td>bitirmek, tamamlamak</td></tr>\n          <tr><td><strong>finite</strong></td><td>having limits</td><td>sonlu, sınırlı</td></tr>\n          <tr><td><strong>infinite</strong></td><td>without limits</td><td>sonsuz</td></tr>\n          <tr><td><strong>define</strong></td><td>to set the limits of meaning (de- + fīnīre)</td><td>tanımlamak</td></tr>\n          <tr><td><strong>final</strong></td><td>last, ultimate</td><td>son, nihai</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Refinement\" kelimesini kafanızda bir kuyumcunun altını işlemesi gibi düşünün — ham altını alır, tekrar tekrar (<em>re-</em>) eritir, saflaştırır ve <em>ince</em> (<em>fine</em>) bir hale getirir. Bir fikri veya ürünü \"refine\" etmek de aynı şey: her seferinde biraz daha parlak ve saf hale getirmek.\n      </div>"}, {"icon": "⚖️", "title": "Refinement vs. Improvement vs. Enhancement vs. Optimization", "content": "<p>\"İyileştirme\" anlamında kullanılan bu kelimeler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Refinement</th><th>Improvement</th><th>Enhancement</th><th>Optimization</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Focus</td>\n            <td>Small, precise adjustments<br><em>Küçük, hassas ayarlamalar</em></td>\n            <td>Making something generally better<br><em>Genel olarak daha iyi yapma</em></td>\n            <td>Adding value or capability<br><em>Değer veya yetenek ekleme</em></td>\n            <td>Achieving maximum efficiency<br><em>Maksimum verimlilik sağlama</em></td>\n          </tr>\n          <tr>\n            <td>Character</td>\n            <td>Subtle, detailed, iterative<br><em>İnce, detaylı, yinelemeli</em></td>\n            <td>Broad, general<br><em>Geniş, genel</em></td>\n            <td>Adding features or quality<br><em>Özellik veya kalite ekleme</em></td>\n            <td>Technical, measurable<br><em>Teknik, ölçülebilir</em></td>\n          </tr>\n          <tr>\n            <td>Common in</td>\n            <td>Design, Agile, craftsmanship<br><em>Tasarım, Agile, zanaatkârlık</em></td>\n            <td>Everyday, all contexts<br><em>Günlük, tüm bağlamlar</em></td>\n            <td>Software, products, features<br><em>Yazılım, ürünler, özellikler</em></td>\n            <td>Engineering, performance<br><em>Mühendislik, performans</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>Refinement of the design.</td>\n            <td>Improvement in sales.</td>\n            <td>Enhancement to the feature.</td>\n            <td>Optimization of the algorithm.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Tasarımın inceltilmesi.</td>\n            <td>Satışlardaki iyileşme.</td>\n            <td>Özelliğe eklenen geliştirme.</td>\n            <td>Algoritmanın optimizasyonu.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Refinement\" en <em>ince ve hassas</em> olanıdır — zaten iyi olan bir şeyi mükemmele yaklaştırma. \"Improvement\" en genel ve en yaygınıdır. \"Enhancement\" mevcut bir şeye yeni değer katmayı, \"optimization\" ise genellikle teknik verimlilik en yüksek seviyeye çıkarmayı ifade eder.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Software / Agile</strong><br>(Yazılım)</td>\n            <td>Backlog refinement; iterative development</td>\n            <td>The PO leads backlog refinement every Wednesday.</td>\n            <td>PO her Çarşamba backlog refinement''ı yönetir.</td>\n          </tr>\n          <tr>\n            <td><strong>Industry</strong><br>(Endüstri)</td>\n            <td>Oil, sugar, metal refinement</td>\n            <td>The refinement of crude oil produces gasoline and diesel.</td>\n            <td>Ham petrolün arıtılması benzin ve dizel üretir.</td>\n          </tr>\n          <tr>\n            <td><strong>Design / UX</strong><br>(Tasarım)</td>\n            <td>Refining prototypes and interfaces</td>\n            <td>The design went through three rounds of refinement.</td>\n            <td>Tasarım üç tur iyileştirmeden geçti.</td>\n          </tr>\n          <tr>\n            <td><strong>Science</strong><br>(Bilim)</td>\n            <td>Refining theories and data models</td>\n            <td>Refinement of the hypothesis led to a breakthrough.</td>\n            <td>Hipotezin geliştirilmesi bir atılıma yol açtı.</td>\n          </tr>\n          <tr>\n            <td><strong>Culture</strong><br>(Kültür)</td>\n            <td>Elegance and cultivated taste</td>\n            <td>The palace is a symbol of aristocratic refinement.</td>\n            <td>Saray, aristokrat zarafetinin bir sembolüdür.</td>\n          </tr>\n          <tr>\n            <td><strong>AI / ML</strong><br>(Yapay Zekâ)</td>\n            <td>Model refinement, fine-tuning</td>\n            <td>RLHF is used for the refinement of large language models.</td>\n            <td>RLHF, büyük dil modellerinin iyileştirilmesi için kullanılır.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "Bonus: Refined vs. Unrefined / Rafine ile Ham Karşılaştırması", "content": "<p>\"Refined\" ve \"unrefined\" hem fiziksel hem de kişilik anlamında zıt kavramlardır:</p>\n      <table>\n        <thead><tr><th></th><th>Refined</th><th>Unrefined</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Physical / Fiziksel</strong></td>\n            <td>Purified, processed<br><em>Arıtılmış, işlenmiş</em></td>\n            <td>Raw, unprocessed<br><em>Ham, işlenmemiş</em></td>\n          </tr>\n          <tr>\n            <td><strong>Example</strong></td>\n            <td>Refined sugar, refined oil</td>\n            <td>Unrefined sugar (brown), unrefined oil (crude)</td>\n          </tr>\n          <tr>\n            <td><strong>Turkish</strong></td>\n            <td>Rafine şeker, rafine yağ</td>\n            <td>Ham şeker (esmer), ham petrol</td>\n          </tr>\n          <tr>\n            <td><strong>Personality / Kişilik</strong></td>\n            <td>Elegant, cultured, polished<br><em>Zarif, kültürlü, kibar</em></td>\n            <td>Rough, crude, unsophisticated<br><em>Kaba, görgüsüz, incelikten yoksun</em></td>\n          </tr>\n          <tr>\n            <td><strong>Example</strong></td>\n            <td>A refined gentleman</td>\n            <td>His manners are a bit unrefined.</td>\n          </tr>\n          <tr>\n            <td><strong>Turkish</strong></td>\n            <td>Zarif bir beyefendi</td>\n            <td>Tavırları biraz kaba.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>💡 İlginç not:</strong> Sağlık dünyasında \"unrefined\" bazen olumlu anlam taşır: <em>unrefined sugar</em> (işlenmemiş şeker) ve <em>unrefined coconut oil</em> (işlenmemiş hindistan cevizi yağı) daha doğal ve sağlıklı kabul edilir!\n      </div>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('roll-out', 'ROLL OUT', '/ˌroʊl ˈaʊt/', 'piyasaya sürmek · dağıtmak · yaymak · kullanıma sunmak · açmak', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Roll out</strong> hem bir <em>phrasal verb</em> (öbekli fiil) hem de birleşik isim (<em>rollout / roll-out</em>) olarak kullanılan, özellikle iş dünyası ve teknoloji alanlarında çok sık karşılaşılan bir ifadedir.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Roll out\" ifadesinin fiziksel kökü <em>\"bir şeyi yuvarlayarak/açarak dışarı çıkarmak\"</em> anlamına gelir. Bir halının açılmasını, bir hamurun açılmasını ya da bir uçağın hangardan çıkarılmasını düşünün. Bu somut fikirden mecazi olarak iki önemli anlam dallanmıştır: (1) bir ürünü, hizmeti veya planı <em>kamuya/piyasaya sunmak</em>, (2) bir sistemi veya güncellemeyi <em>aşamalı olarak dağıtmak/yaymak</em>. İsim formu \"rollout\" özellikle teknolojide \"yeni bir özelliğin kullanıcılara sunulması\" anlamında çok yaygındır.</p>\n\n      <table>\n        <thead><tr><th>Usage</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Phrasal Verb</strong><br>Fiziksel</td><td>To unroll or spread something flat (dough, carpet, fabric)</td><td>Açmak, yaymak (hamur, halı, kumaş)</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Lansman</td><td>To introduce or launch a new product, service, or plan</td><td>Piyasaya sürmek, kullanıma sunmak, tanıtmak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Dağıtım</td><td>To make available gradually across regions or users</td><td>Aşamalı olarak dağıtmak, yaymak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Çıkma</td><td>To move out slowly (vehicle, person from bed)</td><td>Yavaşça dışarı çıkmak (araç); yataktan çıkmak</td></tr>\n          <tr><td><strong>Noun</strong><br>(rollout / roll-out)</td><td>The act of introducing something new</td><td>Lansman, dağıtım, kullanıma sunma</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>roll out</strong></td><td>phrasal verb (öbekli fiil)</td><td>piyasaya sürmek, açmak, yaymak</td></tr>\n          <tr><td><strong>rollout / roll-out</strong></td><td>noun (isim)</td><td>lansman, dağıtım, kullanıma sunma</td></tr>\n          <tr><td><strong>rolled out</strong></td><td>past tense / past participle</td><td>piyasaya sürüldü / sunuldu</td></tr>\n          <tr><td><strong>rolling out</strong></td><td>present participle</td><td>piyasaya sürülüyor, dağıtılıyor</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Yazım Kuralı:</strong><br>\n        <strong>Fiil olarak:</strong> iki ayrı kelime → <em>roll out</em><br>\n        <strong>İsim olarak:</strong> bitişik veya tire ile → <em>rollout</em> veya <em>roll-out</em><br>\n        ✅ <em>We will <strong>roll out</strong> the update next week.</em> (fiil — ayrı)<br>\n        ✅ <em>The <strong>rollout</strong> was successful.</em> (isim — bitişik)<br>\n        ❌ <em>We will <strong>rollout</strong> the update.</em> (fiil olarak bitişik yanlış!)\n      </div>\n\n      <h3>Separable or Inseparable? / Ayrılabilir mi?</h3>\n      <div class=\"tip\">\n        <strong>📌 Önemli:</strong> \"Roll out\" <strong>ayrılabilir</strong> (separable) bir phrasal verb''dür. Nesne araya girebilir:<br><br>\n        ✅ <em>They <strong>rolled out</strong> the new feature.</em><br>\n        ✅ <em>They <strong>rolled</strong> the new feature <strong>out</strong>.</em><br>\n        ✅ <em>They <strong>rolled it out</strong>.</em> (zamir araya girmeli)<br>\n        ❌ <em>They <strong>rolled out it</strong>.</em> (zamir ile ayrılmamak yanlış!)\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>roll out + something (product/feature/plan)</code>\n        <div>→ Bir ürünü/özelliği/planı piyasaya sürmek</div>\n        <div class=\"example\"><em>Apple <strong>rolled out</strong> a new iPhone model.</em></div>\n        <div class=\"turkish\">Apple yeni bir iPhone modeli piyasaya sürdü.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>roll out + across / in / to (locations/users)</code>\n        <div>→ Bölgelere/kullanıcılara aşamalı olarak dağıtmak</div>\n        <div class=\"example\"><em>The vaccine was <strong>rolled out across</strong> the country.</em></div>\n        <div class=\"turkish\">Aşı ülke genelinde dağıtıldı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>roll out + the red carpet</code>\n        <div>→ Kırmızı halı sermek; birini çok özel karşılamak (deyim)</div>\n        <div class=\"example\"><em>They <strong>rolled out the red carpet</strong> for the visiting president.</em></div>\n        <div class=\"turkish\">Ziyarete gelen cumhurbaşkanı için kırmızı halı serdiler. (Onu çok özel karşıladılar.)</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>roll out + the dough</code>\n        <div>→ Hamur açmak</div>\n        <div class=\"example\"><em>She <strong>rolled out the dough</strong> on the counter.</em></div>\n        <div class=\"turkish\">Tezgâhın üzerinde hamuru açtı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>roll out (of bed)</code>\n        <div>→ Yataktan (isteksizce) kalkmak / çıkmak</div>\n        <div class=\"example\"><em>I <strong>rolled out of bed</strong> at 6 a.m.</em></div>\n        <div class=\"turkish\">Sabah 6''da yataktan kalktım (sürünerek çıktım).</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>a rollout of + something</code>\n        <div>→ Bir şeyin lansmanı/dağıtımı (isim olarak)</div>\n        <div class=\"example\"><em>The <strong>rollout of</strong> 5G is still in progress.</em></div>\n        <div class=\"turkish\">5G''nin dağıtımı hâlâ devam ediyor.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<div class=\"tip\" style=\"margin-bottom: 1rem;\">\n        <strong>⚠️ Not:</strong> \"Roll\" düzenli (regular) bir fiildir: <strong>roll – rolled – rolled</strong>. \"Out\" kısmı değişmez.\n      </div>\n\n      <table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>roll(s) out</td><td>Google rolls out updates regularly.</td><td>Google düzenli olarak güncelleme yayınlar.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are rolling out</td><td>We are rolling out a new design.</td><td>Yeni bir tasarım sunuyoruz.</td></tr>\n          <tr><td>Simple Past</td><td>rolled out</td><td>They rolled out the service last year.</td><td>Hizmeti geçen yıl kullanıma sundular.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were rolling out</td><td>The company was rolling out changes when the bug appeared.</td><td>Hata ortaya çıktığında şirket değişiklikleri dağıtıyordu.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has rolled out</td><td>We have rolled out the feature to all users.</td><td>Özelliği tüm kullanıcılara sunduk.</td></tr>\n          <tr><td>Past Perfect</td><td>had rolled out</td><td>They had rolled out the patch before the crash.</td><td>Çökmeden önce yamayı yayınlamışlardı.</td></tr>\n          <tr><td>Future Simple</td><td>will roll out</td><td>The update will roll out next Monday.</td><td>Güncelleme gelecek Pazartesi yayınlanacak.</td></tr>\n          <tr><td>Future Perfect</td><td>will have rolled out</td><td>By December, they will have rolled out the app worldwide.</td><td>Aralık''a kadar uygulamayı dünya genelinde yayınlamış olacaklar.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Roll out\" edilgen çatıda sıkça kullanılır — özellikle ürün ve hizmet dağıtımında:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>They rolled out the update.</td><td>The update <strong>was rolled out</strong>.</td><td>Güncelleme yayınlandı.</td></tr>\n          <tr><td>We are rolling out new features.</td><td>New features <strong>are being rolled out</strong>.</td><td>Yeni özellikler sunuluyor.</td></tr>\n          <tr><td>The government will roll out the plan.</td><td>The plan <strong>will be rolled out</strong> by the government.</td><td>Plan hükümet tarafından uygulamaya konulacak.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>roll out <strong>across</strong> (a region)</td><td>The program was rolled out across Europe.</td><td>Program Avrupa genelinde yaygınlaştırıldı.</td></tr>\n          <tr><td>roll out <strong>to</strong> (users/people)</td><td>The feature is rolling out to all users.</td><td>Özellik tüm kullanıcılara sunuluyor.</td></tr>\n          <tr><td>roll out <strong>in</strong> (a place/phase)</td><td>It will roll out in stages.</td><td>Aşamalı olarak dağıtılacak.</td></tr>\n          <tr><td>rollout <strong>of</strong> (something)</td><td>The rollout of the vaccine took months.</td><td>Aşının dağıtımı aylar sürdü.</td></tr>\n          <tr><td>roll out <strong>on</strong> (a date/platform)</td><td>The app rolled out on Android first.</td><td>Uygulama önce Android''de yayınlandı.</td></tr>\n          <tr><td>roll out <strong>from</strong> (origin)</td><td>Changes are rolling out from headquarters.</td><td>Değişiklikler merkez ofisten yayılıyor.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">roll out an update <span class=\"tr\">— güncelleme yayınlamak</span></span>\n        <span class=\"collocation-tag\">roll out a product <span class=\"tr\">— ürün piyasaya sürmek</span></span>\n        <span class=\"collocation-tag\">roll out a plan <span class=\"tr\">— plan uygulamaya koymak</span></span>\n        <span class=\"collocation-tag\">roll out a feature <span class=\"tr\">— özellik sunmak</span></span>\n        <span class=\"collocation-tag\">roll out a service <span class=\"tr\">— hizmet başlatmak</span></span>\n        <span class=\"collocation-tag\">roll out a campaign <span class=\"tr\">— kampanya başlatmak</span></span>\n        <span class=\"collocation-tag\">gradual rollout <span class=\"tr\">— kademeli dağıtım</span></span>\n        <span class=\"collocation-tag\">phased rollout <span class=\"tr\">— aşamalı dağıtım</span></span>\n        <span class=\"collocation-tag\">global rollout <span class=\"tr\">— küresel lansman</span></span>\n        <span class=\"collocation-tag\">nationwide rollout <span class=\"tr\">— ülke çapında dağıtım</span></span>\n        <span class=\"collocation-tag\">roll out the red carpet <span class=\"tr\">— kırmızı halı sermek (özel karşılamak)</span></span>\n        <span class=\"collocation-tag\">roll out the dough <span class=\"tr\">— hamur açmak</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. Roll out the dough until it''s thin.</div>\n          <div class=\"tr\">Hamuru incelene kadar aç.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. The company rolled out a new app today.</div>\n          <div class=\"tr\">Şirket bugün yeni bir uygulama piyasaya sürdü.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. I rolled out of bed at noon.</div>\n          <div class=\"tr\">Öğlen yataktan kalktım (sürünerek çıktım).</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. The government is rolling out a new vaccination program across the country.</div>\n          <div class=\"tr\">Hükümet ülke genelinde yeni bir aşı programı başlatıyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. We plan to roll out the software update to all devices by Friday.</div>\n          <div class=\"tr\">Yazılım güncellemesini Cuma''ya kadar tüm cihazlara dağıtmayı planlıyoruz.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. The new policy has been rolled out in three phases.</div>\n          <div class=\"tr\">Yeni politika üç aşamada uygulamaya konuldu.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. The phased rollout allowed the team to identify bugs before reaching all users.</div>\n          <div class=\"tr\">Aşamalı dağıtım, ekibin tüm kullanıcılara ulaşmadan önce hataları tespit etmesini sağladı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. Critics argue the policy was rolled out too quickly without adequate consultation.</div>\n          <div class=\"tr\">Eleştirmenler, politikanın yeterli istişare yapılmadan çok hızlı uygulamaya konulduğunu savunuyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. The global rollout of the electric vehicle infrastructure represents a massive investment.</div>\n          <div class=\"tr\">Elektrikli araç altyapısının küresel dağıtımı devasa bir yatırımı temsil ediyor.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Informal & Idioms / Günlük Dil ve Deyimler</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. They rolled out the red carpet for us — we felt like celebrities!</div>\n          <div class=\"tr\">Bize kırmızı halı serdiler — kendimizi ünlü gibi hissettik!</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. I barely managed to roll out of bed this morning.</div>\n          <div class=\"tr\">Bu sabah yataktan zar zor kalkabildim.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Type</strong></td><td>Phrasal verb: <strong>roll</strong> + <strong>out</strong></td></tr>\n          <tr><td><strong>\"Roll\" origin</strong></td><td>Old French: <strong>roler</strong> → Latin: <strong>rotulare</strong> (to roll) → Latin: <strong>rota</strong> (wheel / tekerlek)</td></tr>\n          <tr><td><strong>\"Out\" origin</strong></td><td>Old English: <strong>ūt</strong> → Proto-Germanic: <strong>*ūt</strong> (out, outside / dışarı)</td></tr>\n          <tr><td><strong>Literal meaning</strong></td><td>\"Yuvarlayarak/açarak dışarı çıkarmak\" — bir halı veya hamur açmak gibi fiziksel bir eylem</td></tr>\n          <tr><td><strong>Physical → Business</strong></td><td>1940''larda havacılıkta \"uçağı hangardan çıkarmak\" (aircraft rollout) anlamında kullanılmaya başlandı. Buradan iş dünyasında \"yeni bir ürünü/hizmeti halka sunmak\" anlamına genişledi.</td></tr>\n          <tr><td><strong>Technology sense</strong></td><td>1990''lardan itibaren yazılım dünyasında \"güncelleme dağıtmak, yeni özellik sunmak\" anlamında yaygınlaştı. Bugün teknolojide en sık kullanılan anlamıdır.</td></tr>\n          <tr><td><strong>Red carpet sense</strong></td><td>\"Roll out the red carpet\" deyimi kelimenin en eski somut anlamına dayanır: kırmızı halıyı yuvarlayarak açıp sermek. Mecazi olarak \"birini çok özel karşılamak\" demektir.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (rota = wheel)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>roll</strong></td><td>to move by turning; a rounded shape</td><td>yuvarlanmak; rulo</td></tr>\n          <tr><td><strong>rotate</strong></td><td>to turn around a central point</td><td>döndürmek, dönmek</td></tr>\n          <tr><td><strong>rotation</strong></td><td>the act of rotating</td><td>dönüş, rotasyon</td></tr>\n          <tr><td><strong>rotary</strong></td><td>involving circular motion</td><td>döner, dairesel</td></tr>\n          <tr><td><strong>role</strong></td><td>a part played (originally a rolled-up script)</td><td>rol (aslen \"sarılmış senaryo\")</td></tr>\n          <tr><td><strong>control</strong></td><td>from Latin <em>contrarotulare</em> (counter-roll)</td><td>kontrol etmek</td></tr>\n          <tr><td><strong>enroll</strong></td><td>to enter a name on a roll/list</td><td>kaydolmak, kayıt yaptırmak</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Roll out\" ifadesini kafanızda \"bir halıyı yuvarlayarak açmak\" olarak hayal edin. Bir halı açıldığında herkes ona bakar ve üzerinde yürüyebilir — tıpkı yeni bir ürün veya hizmet herkesin kullanımına sunulduğunda olduğu gibi. Fiziksel açılış = mecazi lansman!\n      </div>"}, {"icon": "⚖️", "title": "Roll Out vs. Launch vs. Release vs. Deploy / Farkları", "content": "<p>\"Bir şeyi kullanıma sunmak\" anlamında kullanılan bu kelimeler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Roll Out</th><th>Launch</th><th>Release</th><th>Deploy</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Focus</td>\n            <td>Gradual distribution<br><em>Aşamalı dağıtım</em></td>\n            <td>Big, public introduction<br><em>Büyük, kamuya duyurma</em></td>\n            <td>Making available officially<br><em>Resmi olarak yayınlama</em></td>\n            <td>Putting into active use (technical)<br><em>Aktif kullanıma alma (teknik)</em></td>\n          </tr>\n          <tr>\n            <td>Speed</td>\n            <td>Gradual, phased<br><em>Kademeli, aşamalı</em></td>\n            <td>Instant, event-based<br><em>Anlık, etkinlik bazlı</em></td>\n            <td>Instant or scheduled<br><em>Anlık veya planlanmış</em></td>\n            <td>Can be instant or staged<br><em>Anlık veya aşamalı olabilir</em></td>\n          </tr>\n          <tr>\n            <td>Common in</td>\n            <td>Business, tech, government<br><em>İş, teknoloji, devlet</em></td>\n            <td>Marketing, startups<br><em>Pazarlama, girişimler</em></td>\n            <td>Software, music, films<br><em>Yazılım, müzik, film</em></td>\n            <td>Software engineering, military<br><em>Yazılım mühendisliği, askeri</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>We rolled out the update.</td>\n            <td>We launched the product.</td>\n            <td>We released v2.0.</td>\n            <td>We deployed to production.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Güncellemeyi dağıttık.</td>\n            <td>Ürünü piyasaya sürdük.</td>\n            <td>v2.0''ı yayınladık.</td>\n            <td>Üretime deploy ettik.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Roll out\" genellikle <em>aşamalı/kademeli bir süreci</em> ima eder — önce bir gruba, sonra herkese. \"Launch\" ise daha çok <em>büyük bir duyuru</em> hissi verir. \"Release\" resmi yayınlama anlamında daha nötrdür. \"Deploy\" ise tamamen teknik bir terimdir.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Technology</strong><br>(Teknoloji)</td>\n            <td>Distribute software update or feature</td>\n            <td>The update is being rolled out to all Android devices.</td>\n            <td>Güncelleme tüm Android cihazlara dağıtılıyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Introduce a product or strategy</td>\n            <td>The company rolled out its new pricing strategy.</td>\n            <td>Şirket yeni fiyatlandırma stratejisini uygulamaya koydu.</td>\n          </tr>\n          <tr>\n            <td><strong>Government</strong><br>(Devlet)</td>\n            <td>Implement a policy or program</td>\n            <td>The vaccination rollout saved many lives.</td>\n            <td>Aşı dağıtımı birçok hayat kurtardı.</td>\n          </tr>\n          <tr>\n            <td><strong>Aviation</strong><br>(Havacılık)</td>\n            <td>Move an aircraft out of the hangar</td>\n            <td>The new Boeing 777X was rolled out for the first time.</td>\n            <td>Yeni Boeing 777X ilk kez hangardan çıkarıldı.</td>\n          </tr>\n          <tr>\n            <td><strong>Cooking</strong><br>(Mutfak)</td>\n            <td>Flatten dough with a rolling pin</td>\n            <td>Roll out the pastry to 3mm thickness.</td>\n            <td>Hamuru 3mm kalınlığında açın.</td>\n          </tr>\n          <tr>\n            <td><strong>Daily Life</strong><br>(Günlük Hayat)</td>\n            <td>Get out of bed (informal)</td>\n            <td>I rolled out of bed late this morning.</td>\n            <td>Bu sabah geç yataktan kalktım.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "Other Phrasal Verbs with \"Roll\" / \"Roll\" İle Diğer Öbekli Fiiller", "content": "<table>\n        <thead><tr><th>Phrasal Verb</th><th>Meaning</th><th>Turkish</th><th>Example</th></tr></thead>\n        <tbody>\n          <tr><td><strong>roll in</strong></td><td>to arrive in large amounts; to arrive casually</td><td>bol bol gelmek; gelip çıkmak</td><td>Money started rolling in after the ad.</td></tr>\n          <tr><td><strong>roll back</strong></td><td>to reduce or reverse</td><td>geri almak, azaltmak</td><td>They rolled back the price increase.</td></tr>\n          <tr><td><strong>roll over</strong></td><td>to turn over; to extend a deadline</td><td>devrilmek; süreyi uzatmak</td><td>The dog rolled over on the grass.</td></tr>\n          <tr><td><strong>roll up</strong></td><td>to arrive (informal); to wrap by rolling</td><td>gelmek (günlük dil); sarmak</td><td>Roll up your sleeves and get to work.</td></tr>\n          <tr><td><strong>roll with</strong></td><td>to accept and adapt to</td><td>uyum sağlamak, kabullenmek</td><td>Sometimes you just have to roll with it.</td></tr>\n          <tr><td><strong>roll off</strong></td><td>to come off a production line</td><td>üretim bandından çıkmak</td><td>500 cars roll off the line daily.</td></tr>\n        </tbody>\n      </table>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('run', 'RUN', '/rʌn/', 'koşmak · çalıştırmak · yönetmek · işletmek · akmak · uzanmak', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Run</strong> İngilizce''nin en çok anlamlı kelimelerinden biridir — Oxford sözlüğünde 600''den fazla tanımıyla rekor kırar. Hem fiil hem isim olarak kullanılır ve neredeyse her alanda karşınıza çıkar.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Run\" kelimesinin en temel anlamı <em>\"hızlı hareket etmek, koşmak\"</em>tır. Ancak bu basit fiziksel eylemden çok sayıda mecazi anlam türemiştir. Hareket eden her şey \"run\" yapabilir: su akar (runs), bir makine çalışır (runs), bir yol uzanır (runs), bir iş işletilir (run), bir program çalıştırılır (run), bir renk akar (runs). Ortak tema her zaman aynıdır: <em>sürekli, kesintisiz hareket veya işleyiş</em>.</p>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To move quickly on foot</td><td>Koşmak</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To operate a machine, program, or system</td><td>Çalıştırmak (makine, program)</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To manage or be in charge of (a business, organization)</td><td>İşletmek, yönetmek</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To flow (water, liquid, nose)</td><td>Akmak (su, sıvı, burun)</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To extend or stretch in a direction (road, fence)</td><td>Uzanmak (yol, çit)</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To be a candidate in an election</td><td>Aday olmak, seçime katılmak</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To spread (color in fabric, ink)</td><td>Akmak, yayılmak (renk, mürekkep)</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>The act of running; a period of running</td><td>Koşu, koşma eylemi</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>A series or sequence</td><td>Seri, ardışık dizin</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>A trip or route</td><td>Sefer, rota</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>run</strong></td><td>verb / noun</td><td>koşmak; koşu / çalıştırmak; işletmek</td></tr>\n          <tr><td><strong>runner</strong></td><td>noun (isim)</td><td>koşucu; aday</td></tr>\n          <tr><td><strong>running</strong></td><td>noun / adjective / adverb</td><td>koşu; akan; art arda</td></tr>\n          <tr><td><strong>runaway</strong></td><td>noun / adjective</td><td>kaçak; kontrolsüz</td></tr>\n          <tr><td><strong>runway</strong></td><td>noun (isim)</td><td>uçuş pisti; podyum</td></tr>\n          <tr><td><strong>run-up</strong></td><td>noun (isim)</td><td>hazırlık dönemi; koşu mesafesi</td></tr>\n          <tr><td><strong>run-down</strong></td><td>adjective / noun</td><td>bakımsız, harap; özet</td></tr>\n          <tr><td><strong>overrun</strong></td><td>verb / noun</td><td>istila etmek; süre/bütçe aşımı</td></tr>\n          <tr><td><strong>rerun</strong></td><td>noun / verb</td><td>tekrar yayın; tekrar çalıştırmak</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>⚠️ Düzensiz fiil:</strong> \"Run\" düzensiz (irregular) bir fiildir: <strong>run – ran – run</strong>.<br>\n        Present participle: <strong>running</strong> (çift ''n'' — CVC kuralı)\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>run + (adverb/direction)</code>\n        <div>→ Koşmak / hızlı hareket etmek</div>\n        <div class=\"example\"><em>She <strong>ran</strong> quickly to the bus stop.</em></div>\n        <div class=\"turkish\">Otobüs durağına hızla koştu.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>run + a business / company / organization</code>\n        <div>→ Bir işletmeyi / şirketi yönetmek</div>\n        <div class=\"example\"><em>He <strong>runs</strong> a small restaurant downtown.</em></div>\n        <div class=\"turkish\">Şehir merkezinde küçük bir restoran işletiyor.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>run + a program / script / test</code>\n        <div>→ Bir program / betik / test çalıştırmak</div>\n        <div class=\"example\"><em><strong>Run</strong> the script and check the output.</em></div>\n        <div class=\"turkish\">Betiği çalıştır ve çıktıyı kontrol et.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>run + for (president / office / election)</code>\n        <div>→ Bir göreve aday olmak</div>\n        <div class=\"example\"><em>She decided to <strong>run for</strong> president.</em></div>\n        <div class=\"turkish\">Cumhurbaşkanlığına aday olmaya karar verdi.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>something + runs (flows/extends)</code>\n        <div>→ Bir şey akar / uzanır</div>\n        <div class=\"example\"><em>The river <strong>runs</strong> through the city.</em></div>\n        <div class=\"turkish\">Nehir şehrin içinden akar / geçer.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>go for a run</code>\n        <div>→ Koşuya çıkmak (isim olarak)</div>\n        <div class=\"example\"><em>I <strong>go for a run</strong> every morning.</em></div>\n        <div class=\"turkish\">Her sabah koşuya çıkarım.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>in the long run / in the short run</code>\n        <div>→ Uzun vadede / kısa vadede (deyim)</div>\n        <div class=\"example\"><em>This investment will pay off <strong>in the long run</strong>.</em></div>\n        <div class=\"turkish\">Bu yatırım uzun vadede karşılığını verecek.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<div class=\"tip\" style=\"margin-bottom: 1rem;\">\n        <strong>⚠️ Düzensiz fiil:</strong> <strong>run – ran – run</strong>. Past participle yine \"run\"dır, \"runned\" değil!\n      </div>\n\n      <table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>run / runs</td><td>He runs the company efficiently.</td><td>Şirketi verimli bir şekilde yönetir.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are running</td><td>The kids are running in the park.</td><td>Çocuklar parkta koşuyor.</td></tr>\n          <tr><td>Simple Past</td><td>ran</td><td>She ran a marathon last year.</td><td>Geçen yıl bir maraton koştu.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were running</td><td>I was running when it started to rain.</td><td>Yağmur başladığında koşuyordum.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has run</td><td>He has run this café for ten years.</td><td>Bu kafeyi on yıldır işletiyor.</td></tr>\n          <tr><td>Past Perfect</td><td>had run</td><td>The program had run for two hours before it crashed.</td><td>Program çökmeden önce iki saat çalışmıştı.</td></tr>\n          <tr><td>Future Simple</td><td>will run</td><td>The server will run 24/7.</td><td>Sunucu 7/24 çalışacak.</td></tr>\n          <tr><td>Future Perfect</td><td>will have run</td><td>By December, the show will have run for five seasons.</td><td>Aralık''a kadar dizi beş sezon sürmüş olacak.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Run\" edilgen çatıda belirli anlamlarda kullanılır:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>She runs the department.</td><td>The department <strong>is run</strong> by her.</td><td>Departman onun tarafından yönetilir.</td></tr>\n          <tr><td>They ran the tests.</td><td>The tests <strong>were run</strong> yesterday.</td><td>Testler dün çalıştırıldı.</td></tr>\n          <tr><td>A charity runs the shelter.</td><td>The shelter <strong>is run</strong> by a charity.</td><td>Barınak bir hayır kurumu tarafından işletilir.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>run <strong>for</strong> (position/office)</td><td>He ran for mayor.</td><td>Belediye başkanlığına aday oldu.</td></tr>\n          <tr><td>run <strong>on</strong> (fuel/power/software)</td><td>This car runs on electricity.</td><td>Bu araba elektrikle çalışır.</td></tr>\n          <tr><td>run <strong>into</strong> (someone/problems)</td><td>I ran into an old friend.</td><td>Eski bir arkadaşla karşılaştım.</td></tr>\n          <tr><td>run <strong>through</strong> (a place/a topic)</td><td>The highway runs through the valley.</td><td>Otoyol vadiden geçer.</td></tr>\n          <tr><td>run <strong>out of</strong> (something)</td><td>We ran out of sugar.</td><td>Şekerimiz bitti.</td></tr>\n          <tr><td>run <strong>over</strong> (time/something)</td><td>The meeting ran over by 20 minutes.</td><td>Toplantı 20 dakika uzadı.</td></tr>\n          <tr><td>run <strong>from … to …</strong></td><td>The festival runs from June to August.</td><td>Festival Haziran''dan Ağustos''a kadar sürer.</td></tr>\n          <tr><td><strong>in the long</strong> run</td><td>It will be cheaper in the long run.</td><td>Uzun vadede daha ucuz olacak.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">run a business <span class=\"tr\">— iş işletmek</span></span>\n        <span class=\"collocation-tag\">run a company <span class=\"tr\">— şirket yönetmek</span></span>\n        <span class=\"collocation-tag\">run a test <span class=\"tr\">— test çalıştırmak</span></span>\n        <span class=\"collocation-tag\">run a program <span class=\"tr\">— program çalıştırmak</span></span>\n        <span class=\"collocation-tag\">run a marathon <span class=\"tr\">— maraton koşmak</span></span>\n        <span class=\"collocation-tag\">run errands <span class=\"tr\">— ayak işleri yapmak</span></span>\n        <span class=\"collocation-tag\">run a risk <span class=\"tr\">— risk almak</span></span>\n        <span class=\"collocation-tag\">run late <span class=\"tr\">— geç kalmak</span></span>\n        <span class=\"collocation-tag\">run low <span class=\"tr\">— azalmak, tükenmek üzere olmak</span></span>\n        <span class=\"collocation-tag\">run wild <span class=\"tr\">— kontrolden çıkmak</span></span>\n        <span class=\"collocation-tag\">a good run <span class=\"tr\">— iyi bir dönem/seri</span></span>\n        <span class=\"collocation-tag\">home run <span class=\"tr\">— büyük başarı (beyzbol terimi)</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. The dog ran across the field.</div>\n          <div class=\"tr\">Köpek tarlanın karşısına koştu.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. Can you run this program for me?</div>\n          <div class=\"tr\">Bu programı benim için çalıştırabilir misin?</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. Water is running from the tap.</div>\n          <div class=\"tr\">Musluktan su akıyor.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. She runs a successful startup in Berlin.</div>\n          <div class=\"tr\">Berlin''de başarılı bir girişim işletiyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The road runs along the coast for 50 kilometers.</div>\n          <div class=\"tr\">Yol 50 kilometre boyunca sahil boyunca uzanır.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. I need to run some errands before lunch.</div>\n          <div class=\"tr\">Öğle yemeğinden önce birkaç ayak işi halletmem gerekiyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. The play ran for three years on Broadway.</div>\n          <div class=\"tr\">Oyun Broadway''de üç yıl sürdü / sahnelendi.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. She''s considering running for Congress in the next election.</div>\n          <div class=\"tr\">Bir sonraki seçimde Kongre''ye aday olmayı düşünüyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. Costs have been running higher than expected, threatening the project''s viability.</div>\n          <div class=\"tr\">Maliyetler beklenenden yüksek seyrediyor ve projenin uygulanabilirliğini tehdit ediyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. In the long run, renewable energy will be more cost-effective than fossil fuels.</div>\n          <div class=\"tr\">Uzun vadede, yenilenebilir enerji fosil yakıtlardan daha uygun maliyetli olacak.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Technology / Teknoloji</div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. Run \"npm install\" to install all dependencies.</div>\n          <div class=\"tr\">Tüm bağımlılıkları yüklemek için \"npm install\" çalıştırın.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">12. The cron job runs every hour.</div>\n          <div class=\"tr\">Zamanlanmış görev her saat çalışır.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>Old English (Eski İngilizce, 9. yüzyıl öncesi)</td></tr>\n          <tr><td><strong>Root</strong></td><td>Old English: <strong>rinnan</strong> (to flow, to run) ve <strong>ærnan / iernan</strong> (to ride, to reach by running)</td></tr>\n          <tr><td><strong>Proto-Germanic</strong></td><td><strong>*rinnaną</strong> (to flow, to run)</td></tr>\n          <tr><td><strong>PIE Root</strong></td><td><strong>*h₃reyH-</strong> (to flow, to move / akmak, hareket etmek)</td></tr>\n          <tr><td><strong>Original meaning</strong></td><td>İlk anlamı \"akmak\" (su gibi) idi — \"koşmak\" anlamı sonradan gelişti. Bu yüzden bugün hâlâ \"Water runs\" (Su akar) diyoruz.</td></tr>\n          <tr><td><strong>Meaning explosion</strong></td><td>\"Run\" İngilizce''nin en çok anlamlı kelimesidir. Oxford English Dictionary''de 645''ten fazla tanımı vardır. 14. yüzyıldan itibaren mecazi anlamları hızla çoğalmıştır.</td></tr>\n          <tr><td><strong>Machine sense</strong></td><td>\"Bir makinenin çalışması\" anlamı 18. yüzyılda Sanayi Devrimi ile yaygınlaştı — çarklar ve mekanizmalar \"hareket eder\" (run).</td></tr>\n          <tr><td><strong>Business sense</strong></td><td>\"İşletmek\" anlamı 19. yüzyılda yerleşti — bir işi \"hareket halinde tutmak\" mecazı.</td></tr>\n          <tr><td><strong>Computing sense</strong></td><td>\"Program çalıştırmak\" anlamı 1950''lerde bilgisayar çağıyla ortaya çıktı.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (*h₃reyH- = to flow)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>run</strong></td><td>to move fast; to flow; to operate</td><td>koşmak; akmak; çalıştırmak</td></tr>\n          <tr><td><strong>runner</strong></td><td>one who runs</td><td>koşucu</td></tr>\n          <tr><td><strong>runway</strong></td><td>a strip for planes</td><td>uçuş pisti</td></tr>\n          <tr><td><strong>runoff</strong></td><td>excess liquid flowing away</td><td>yüzey akışı</td></tr>\n          <tr><td><strong>river</strong></td><td>a flowing body of water</td><td>nehir</td></tr>\n          <tr><td><strong>rival</strong></td><td>one who uses the same stream (Latin <em>rivalis</em>)</td><td>rakip</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Run\" kelimesini hatırlamanın en iyi yolu onun temel fikrini anlamaktır: <em>sürekli hareket</em>. Su akar, bacaklar koşar, motor çalışır, iş döner, program işler, yol uzanır, zaman geçer — hepsi \"run\" yapar. Hareket eden, akan, devam eden her şey \"run\" ile ifade edilebilir!\n      </div>"}, {"icon": "🎭", "title": "The Many Faces of \"Run\" / Run''ın Birçok Yüzü", "content": "<p>\"Run\"ın farklı anlamlarını tek tabloda görelim — aynı kelime, bambaşka anlamlar:</p>\n      <table>\n        <thead><tr><th>Meaning</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Koşmak</td><td>He runs every morning.</td><td>Her sabah koşar.</td></tr>\n          <tr><td>Çalıştırmak (makine)</td><td>Run the engine.</td><td>Motoru çalıştır.</td></tr>\n          <tr><td>İşletmek</td><td>She runs a hotel.</td><td>Bir otel işletiyor.</td></tr>\n          <tr><td>Akmak</td><td>Tears ran down her cheeks.</td><td>Gözyaşları yanaklarından aktı.</td></tr>\n          <tr><td>Uzanmak</td><td>The fence runs along the property.</td><td>Çit mülk boyunca uzanır.</td></tr>\n          <tr><td>Aday olmak</td><td>He ran for mayor.</td><td>Belediye başkanlığına aday oldu.</td></tr>\n          <tr><td>Sürmek (zaman)</td><td>The contract runs until 2027.</td><td>Sözleşme 2027''ye kadar sürer.</td></tr>\n          <tr><td>Çalışmak (yazılım)</td><td>The app runs on iOS.</td><td>Uygulama iOS''ta çalışır.</td></tr>\n          <tr><td>Gecikme</td><td>The train is running late.</td><td>Tren geç kalıyor.</td></tr>\n          <tr><td>Akma (renk)</td><td>The colors ran in the wash.</td><td>Renkler yıkamada aktı.</td></tr>\n          <tr><td>Koşu (isim)</td><td>I went for a run.</td><td>Koşuya çıktım.</td></tr>\n          <tr><td>Seri (isim)</td><td>A run of bad luck.</td><td>Bir dizi talihsizlik.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "Phrasal Verbs with \"Run\" / \"Run\" İle Öbekli Fiiller", "content": "<table>\n        <thead><tr><th>Phrasal Verb</th><th>Meaning</th><th>Turkish</th><th>Example</th></tr></thead>\n        <tbody>\n          <tr><td><strong>run out (of)</strong></td><td>to deplete, to have none left</td><td>tükenmek, bitmek</td><td>We ran out of coffee.</td></tr>\n          <tr><td><strong>run into</strong></td><td>to meet by chance; to encounter a problem</td><td>tesadüfen karşılaşmak; sorunla karşılaşmak</td><td>I ran into my neighbor at the store.</td></tr>\n          <tr><td><strong>run over</strong></td><td>to hit with a vehicle; to exceed time</td><td>araçla ezmek; süreyi aşmak</td><td>The presentation ran over by 10 minutes.</td></tr>\n          <tr><td><strong>run through</strong></td><td>to review quickly; to rehearse</td><td>hızlıca gözden geçirmek; prova etmek</td><td>Let''s run through the agenda.</td></tr>\n          <tr><td><strong>run away</strong></td><td>to escape, to flee</td><td>kaçmak</td><td>The prisoner ran away.</td></tr>\n          <tr><td><strong>run up</strong></td><td>to accumulate (debt/costs)</td><td>biriktirmek (borç)</td><td>He ran up a huge bill.</td></tr>\n          <tr><td><strong>run down</strong></td><td>to lose energy; to criticize; to hit with a car</td><td>enerjisi tükenmek; eleştirmek; çarpmak</td><td>Don''t run down your colleagues.</td></tr>\n          <tr><td><strong>run after</strong></td><td>to chase</td><td>kovalamak, peşinden koşmak</td><td>The kid ran after the ball.</td></tr>\n          <tr><td><strong>run across</strong></td><td>to find unexpectedly</td><td>tesadüfen bulmak</td><td>I ran across an old photo.</td></tr>\n          <tr><td><strong>run by</strong></td><td>to briefly present an idea for feedback</td><td>fikrini sormak, görüş almak</td><td>Let me run this idea by you.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Sports</strong><br>(Spor)</td>\n            <td>Running as physical activity</td>\n            <td>She runs 10 km every day.</td>\n            <td>Her gün 10 km koşar.</td>\n          </tr>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Managing or operating a company</td>\n            <td>Who runs this department?</td>\n            <td>Bu departmanı kim yönetir?</td>\n          </tr>\n          <tr>\n            <td><strong>Technology</strong><br>(Teknoloji)</td>\n            <td>Executing software, servers, commands</td>\n            <td>Run the build pipeline.</td>\n            <td>Build pipeline''ını çalıştır.</td>\n          </tr>\n          <tr>\n            <td><strong>Politics</strong><br>(Siyaset)</td>\n            <td>Being a candidate</td>\n            <td>She''s running for governor.</td>\n            <td>Vali adayı olarak yarışıyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Finance</strong><br>(Finans)</td>\n            <td>A sudden demand (bank run)</td>\n            <td>There was a run on the banks.</td>\n            <td>Bankalara hücum oldu (mevduat çekme paniği).</td>\n          </tr>\n          <tr>\n            <td><strong>Daily Life</strong><br>(Günlük Hayat)</td>\n            <td>Running errands, running late</td>\n            <td>Sorry, I''m running a bit late.</td>\n            <td>Üzgünüm, biraz geç kalıyorum.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "💎", "title": "Idioms & Expressions with \"Run\" / \"Run\" ile Deyimler", "content": "<table>\n        <thead><tr><th>Idiom</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>in the long run</strong></td><td>over a long period of time</td><td>uzun vadede</td></tr>\n          <tr><td><strong>in the short run</strong></td><td>in the near future</td><td>kısa vadede</td></tr>\n          <tr><td><strong>run out of steam</strong></td><td>to lose energy or enthusiasm</td><td>enerjisi / heyecanı tükenmek</td></tr>\n          <tr><td><strong>run the show</strong></td><td>to be in charge</td><td>işleri yönetmek, patronluk yapmak</td></tr>\n          <tr><td><strong>hit and run</strong></td><td>an accident where the driver flees</td><td>çarpıp kaçma (trafik kazası)</td></tr>\n          <tr><td><strong>a dry run</strong></td><td>a practice or rehearsal</td><td>prova, deneme</td></tr>\n          <tr><td><strong>run of the mill</strong></td><td>ordinary, nothing special</td><td>sıradan, olağan</td></tr>\n          <tr><td><strong>run it by someone</strong></td><td>to share an idea for feedback</td><td>birine danışmak, fikrini sormak</td></tr>\n          <tr><td><strong>make a run for it</strong></td><td>to try to escape quickly</td><td>kaçmaya çalışmak, fırsatı değerlendirmek</td></tr>\n          <tr><td><strong>run rings around someone</strong></td><td>to be much better than someone</td><td>birinden çok daha iyi olmak</td></tr>\n        </tbody>\n      </table>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('run-out', 'RUN OUT', '/ˌrʌn ˈaʊt/', 'tükenmek · bitmek · süresi dolmak · dışarı koşmak · kalmamak', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Run out</strong> İngilizce''de en sık kullanılan phrasal verb''lerden biridir. Günlük hayatta, iş dünyasında ve birçok farklı bağlamda sürekli karşılaşırsınız.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Run out\" ifadesinin en somut anlamı <em>\"koşarak dışarı çıkmak\"</em>tır. Ancak en yaygın kullanımı mecazidir: bir şeyin <em>tükenmesi, bitmesi, kalmamışı</em>. Bunu şöyle düşünün: bir bardaktaki su akarken (run) sonunda bardağın dışına çıkar (out) ve bardak boşalır — yani tükenir. Bu temel görüntü, kelimenin tüm anlamlarına ışık tutar: para biter, zaman biter, sabır biter, benzin biter, süre dolar. Ayrıca \"run out on someone\" gibi deyimsel kullanımları da vardır: birini terk etmek, yüzüstü bırakmak.</p>\n\n      <table>\n        <thead><tr><th>Usage</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Phrasal Verb</strong><br>Tükenme</td><td>To use all of something so that none is left</td><td>Tükenmek, bitmek, kalmamak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Süre dolma</td><td>To reach the end of a period of validity</td><td>Süresi dolmak, geçerliliği bitmek</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Fiziksel</td><td>To leave a place quickly by running</td><td>Koşarak dışarı çıkmak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Terk etme</td><td>To abandon or desert someone (run out on)</td><td>Birini terk etmek, yüzüstü bırakmak</td></tr>\n          <tr><td><strong>Noun</strong><br>(run-out)</td><td>The final part of something (cricket term; also general)</td><td>Son kısım; bitiriş (kriket terimi)</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>run out</strong></td><td>phrasal verb (öbekli fiil)</td><td>tükenmek, bitmek, dışarı koşmak</td></tr>\n          <tr><td><strong>run out of</strong></td><td>phrasal verb + preposition</td><td>…''sı/si tükenmek, …''sı/si bitmek</td></tr>\n          <tr><td><strong>ran out</strong></td><td>past tense</td><td>tükendi, bitti, dışarı koştu</td></tr>\n          <tr><td><strong>running out</strong></td><td>present participle</td><td>tükeniyor, bitiyor</td></tr>\n          <tr><td><strong>run-out</strong></td><td>noun (isim)</td><td>tükenme, bitme; kriket terimi</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>⚠️ Düzensiz fiil:</strong> \"Run\" düzensiz (irregular) bir fiildir: <strong>run – ran – run</strong>. \"Out\" kısmı değişmez.<br><br>\n        <strong>📌 Ayrılabilir mi?</strong> \"Run out\" genellikle <strong>ayrılamaz</strong> (inseparable). Nesne araya girmez:<br>\n        ✅ <em>We <strong>ran out of</strong> milk.</em><br>\n        ❌ <em>We <strong>ran milk out of</strong>.</em> (Yanlış!)\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>run out of + something</code>\n        <div>→ Bir şeyi tüketmek, bir şeyin kalmamış olması (EN YAYGIN KULLANIM)</div>\n        <div class=\"example\"><em>We''ve <strong>run out of</strong> coffee.</em></div>\n        <div class=\"turkish\">Kahvemiz bitti. / Kahvemiz tükendi.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>something + runs out</code>\n        <div>→ Bir şey tükenir / biter / süresi dolar</div>\n        <div class=\"example\"><em>Time is <strong>running out</strong>.</em></div>\n        <div class=\"turkish\">Zaman tükeniyor. / Vakit daralıyor.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>something + has run out</code>\n        <div>→ Bir şey tükenmiş / bitmiş / süresi dolmuş</div>\n        <div class=\"example\"><em>My patience <strong>has run out</strong>.</em></div>\n        <div class=\"turkish\">Sabrım tükendi.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>run out on + someone</code>\n        <div>→ Birini terk etmek, yüzüstü bırakmak</div>\n        <div class=\"example\"><em>He <strong>ran out on</strong> his family.</em></div>\n        <div class=\"turkish\">Ailesini terk etti. / Ailesini yüzüstü bıraktı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>run out + of + a place</code>\n        <div>→ Bir yerden koşarak çıkmak</div>\n        <div class=\"example\"><em>The kids <strong>ran out of</strong> the house.</em></div>\n        <div class=\"turkish\">Çocuklar evden koşarak çıktı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>before + something + runs out</code>\n        <div>→ … bitmeden / tükenmeden önce</div>\n        <div class=\"example\"><em>Buy tickets <strong>before they run out</strong>.</em></div>\n        <div class=\"turkish\">Biletler tükenmeden önce al.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<div class=\"tip\" style=\"margin-bottom: 1rem;\">\n        <strong>⚠️ Not:</strong> \"Run\" düzensiz (irregular) bir fiildir: <strong>run – ran – run</strong>. Dikkat: past participle yine \"run\"dır, \"runned\" değil!\n      </div>\n\n      <table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>run(s) out</td><td>Milk runs out quickly in our house.</td><td>Evimizde süt çabuk tükenir.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are running out</td><td>We are running out of time.</td><td>Zamanımız tükeniyor.</td></tr>\n          <tr><td>Simple Past</td><td>ran out</td><td>The battery ran out during the meeting.</td><td>Toplantı sırasında pil bitti.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were running out</td><td>Supplies were running out fast.</td><td>Malzemeler hızla tükeniyordu.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has run out</td><td>We have run out of options.</td><td>Seçeneklerimiz tükendi.</td></tr>\n          <tr><td>Past Perfect</td><td>had run out</td><td>The fuel had run out before they reached the station.</td><td>İstasyona ulaşmadan önce yakıt tükenmişti.</td></tr>\n          <tr><td>Future Simple</td><td>will run out</td><td>The offer will run out at midnight.</td><td>Teklif gece yarısı sona erecek.</td></tr>\n          <tr><td>Future Perfect</td><td>will have run out</td><td>By then, the funds will have run out.</td><td>O zamana kadar fonlar tükenmiş olacak.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Informal Contractions / Yaygın Kısaltmalar</h3>\n      <div class=\"tip\">\n        Günlük konuşmada çok sık duyarsınız:<br>\n        <em>\"We''ve run out of milk.\"</em> → Sütümüz bitti.<br>\n        <em>\"I''ve run out of ideas.\"</em> → Fikirlerim tükendi.<br>\n        <em>\"Time''s running out!\"</em> → Zaman daralıyor!\n      </div>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>run out <strong>of</strong> (something)</td><td>We ran out of gas.</td><td>Benzinimiz bitti.</td></tr>\n          <tr><td>run out <strong>of</strong> (a place)</td><td>She ran out of the room crying.</td><td>Ağlayarak odadan koşarak çıktı.</td></tr>\n          <tr><td>run out <strong>on</strong> (someone)</td><td>Don''t run out on me!</td><td>Beni yüzüstü bırakma!</td></tr>\n          <tr><td>run out <strong>at</strong> / <strong>by</strong> (time)</td><td>The contract runs out at the end of March.</td><td>Sözleşme Mart sonunda sona eriyor.</td></tr>\n          <tr><td>run out <strong>before</strong> (event)</td><td>Supplies ran out before the rescue arrived.</td><td>Kurtarma ekibi gelmeden malzemeler tükendi.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">run out of time <span class=\"tr\">— zamanı tükenmek</span></span>\n        <span class=\"collocation-tag\">run out of money <span class=\"tr\">— parası bitmek</span></span>\n        <span class=\"collocation-tag\">run out of patience <span class=\"tr\">— sabrı tükenmek</span></span>\n        <span class=\"collocation-tag\">run out of ideas <span class=\"tr\">— fikirleri tükenmek</span></span>\n        <span class=\"collocation-tag\">run out of gas / fuel <span class=\"tr\">— benzin/yakıt bitmek</span></span>\n        <span class=\"collocation-tag\">run out of steam <span class=\"tr\">— enerjisi tükenmek (deyim)</span></span>\n        <span class=\"collocation-tag\">run out of luck <span class=\"tr\">— şansı tükenmek</span></span>\n        <span class=\"collocation-tag\">run out of options <span class=\"tr\">— seçenekleri tükenmek</span></span>\n        <span class=\"collocation-tag\">run out of space <span class=\"tr\">— yer kalmamak</span></span>\n        <span class=\"collocation-tag\">run out of stock <span class=\"tr\">— stoku tükenmek</span></span>\n        <span class=\"collocation-tag\">the lease runs out <span class=\"tr\">— kira sözleşmesi sona ermek</span></span>\n        <span class=\"collocation-tag\">the clock is running out <span class=\"tr\">— süre dolmak üzere</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. We''ve run out of bread.</div>\n          <div class=\"tr\">Ekmek bitti. / Ekmeğimiz kalmadı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. My phone battery ran out.</div>\n          <div class=\"tr\">Telefonumun pili bitti.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. The children ran out into the garden.</div>\n          <div class=\"tr\">Çocuklar bahçeye koşarak çıktı.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. Hurry up! Time is running out.</div>\n          <div class=\"tr\">Acele et! Zaman tükeniyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The company ran out of funds before completing the project.</div>\n          <div class=\"tr\">Şirketin projeyi tamamlamadan önce parası tükendi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. My visa runs out next month, so I need to renew it.</div>\n          <div class=\"tr\">Vizem gelecek ay sona eriyor, bu yüzden yenilemem gerekiyor.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. Analysts warn that global reserves of rare minerals could run out within decades.</div>\n          <div class=\"tr\">Analistler, küresel nadir mineral rezervlerinin on yıllar içinde tükenebileceği konusunda uyarıyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. The team had run out of steam by the fourth quarter, and their performance dropped significantly.</div>\n          <div class=\"tr\">Takım dördüncü çeyrekte enerjisini kaybetmişti ve performansları önemli ölçüde düştü.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. Negotiations stalled as both parties appeared to have run out of concessions to offer.</div>\n          <div class=\"tr\">Her iki tarafın da sunacak tavizleri tükenmiş göründüğünden müzakereler durdu.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Idioms & Informal / Deyimler ve Günlük Dil</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. He ran out on his wife and kids — no one knows where he went.</div>\n          <div class=\"tr\">Karısını ve çocuklarını terk etti — nereye gittiğini kimse bilmiyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. I''ve completely run out of steam. I need a break.</div>\n          <div class=\"tr\">Enerjim tamamen tükendi. Bir molaya ihtiyacım var.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">12. Their luck finally ran out when the police caught them.</div>\n          <div class=\"tr\">Polis onları yakaladığında şansları sonunda tükendi.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Type</strong></td><td>Phrasal verb: <strong>run</strong> + <strong>out</strong></td></tr>\n          <tr><td><strong>\"Run\" origin</strong></td><td>Old English: <strong>rinnan</strong> (to flow, to run) → Proto-Germanic: <strong>*rinnaną</strong> → PIE root: <strong>*h₃reyH-</strong> (to flow, to move / akmak, hareket etmek)</td></tr>\n          <tr><td><strong>\"Out\" origin</strong></td><td>Old English: <strong>ūt</strong> → Proto-Germanic: <strong>*ūt</strong> (out, outside / dışarı)</td></tr>\n          <tr><td><strong>Literal meaning</strong></td><td>\"Akarak/koşarak dışarı çıkmak\" — bir sıvının kaptan akıp dışarı çıkması gibi</td></tr>\n          <tr><td><strong>Depletion sense</strong></td><td>Bir şeyin \"dışarı akması\" → \"tükenmesi\" mecazı çok eskidir. Orta Çağ İngilizce''sinden beri \"bitmek, kalmamak\" anlamında kullanılır. Kum saatindeki kumun akıp bitmesini düşünün.</td></tr>\n          <tr><td><strong>Expiry sense</strong></td><td>\"Sürenin dolması\" anlamı 17. yüzyıldan itibaren yaygınlaşmıştır — zaman \"akarak biter\" metaforuna dayanır.</td></tr>\n          <tr><td><strong>\"Run out on\" sense</strong></td><td>\"Birini terk etmek\" anlamı 19. yüzyıl Amerikan İngilizce''sinden gelir — \"koşarak kaçmak ve birini geride bırakmak\" somut fikrine dayanır.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (*h₃reyH- = to flow)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>run</strong></td><td>to move fast on foot; to operate</td><td>koşmak; çalıştırmak</td></tr>\n          <tr><td><strong>river</strong></td><td>a flowing body of water</td><td>nehir (akan su)</td></tr>\n          <tr><td><strong>rival</strong></td><td>one who uses the same river (Latin <em>rivalis</em>)</td><td>rakip (aynı nehri kullanan)</td></tr>\n          <tr><td><strong>derive</strong></td><td>to come from a source (de- + rivus)</td><td>türemek, kaynaklanmak</td></tr>\n          <tr><td><strong>runway</strong></td><td>a strip for planes to run on</td><td>uçuş pisti</td></tr>\n          <tr><td><strong>runoff</strong></td><td>excess water that flows away</td><td>yüzey akışı, taşma</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Run out\" ifadesini kafanızda bir \"kum saati\" olarak hayal edin. Kum (kaynak) yukarıdan aşağıya doğru akar (run) ve sonunda dışarı çıkar (out) — kum biter, zaman biter. Para, benzin, sabır, fikirler... hepsi aynı şekilde \"akar ve tükenir.\" Bu görsel aklınızda kalsın!\n      </div>"}, {"icon": "⚖️", "title": "Run Out vs. Run Out Of vs. Use Up vs. Deplete / Farkları", "content": "<p>\"Tükenmek/bitirmek\" anlamında kullanılan bu ifadeler arasında önemli yapı ve nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Run Out</th><th>Run Out Of</th><th>Use Up</th><th>Deplete</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Subject</td>\n            <td>The <em>thing</em> that depletes<br><em>Tükenen şey</em></td>\n            <td>The <em>person/entity</em> who depletes<br><em>Tüketen kişi/kurum</em></td>\n            <td>The <em>person</em> who consumes<br><em>Tüketen kişi</em></td>\n            <td>Formal; the <em>agent</em> that depletes<br><em>Resmi; tüketen etken</em></td>\n          </tr>\n          <tr>\n            <td>Structure</td>\n            <td>Something runs out<br><em>Bir şey tükenir</em></td>\n            <td>Someone runs out of something<br><em>Birinin şeyi tükenir</em></td>\n            <td>Someone uses up something<br><em>Birisi bir şeyi bitirir</em></td>\n            <td>Something depletes something<br><em>Bir şey bir şeyi tüketir</em></td>\n          </tr>\n          <tr>\n            <td>Formality</td>\n            <td>Neutral<br><em>Nötr</em></td>\n            <td>Neutral / informal<br><em>Nötr / günlük</em></td>\n            <td>Neutral<br><em>Nötr</em></td>\n            <td>Formal / scientific<br><em>Resmi / bilimsel</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>The milk ran out.</td>\n            <td>We ran out of milk.</td>\n            <td>We used up all the milk.</td>\n            <td>Overuse depleted the reserves.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Süt bitti.</td>\n            <td>Sütümüz bitti.</td>\n            <td>Bütün sütü bitirdik.</td>\n            <td>Aşırı kullanım rezervleri tüketti.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Run out\" ile özne tükenen <em>şeyin kendisi</em>dir (The milk ran out). \"Run out of\" ile özne tükenen şeyin <em>sahibi/kullanıcısı</em>dır (We ran out of milk). Bu ayrımı hatırlayın — İngilizce''de en sık yapılan hatalardan biridir!\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Daily Life</strong><br>(Günlük Hayat)</td>\n            <td>Running out of food, supplies, battery</td>\n            <td>We''ve run out of eggs — can you buy some?</td>\n            <td>Yumurtamız bitti — alabilir misin?</td>\n          </tr>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Running out of budget, resources, time</td>\n            <td>The project ran out of budget in Q3.</td>\n            <td>Projenin bütçesi 3. çeyrekte tükendi.</td>\n          </tr>\n          <tr>\n            <td><strong>Legal</strong><br>(Hukuk)</td>\n            <td>Contract, visa, or license expiring</td>\n            <td>Your work permit runs out in June.</td>\n            <td>Çalışma izniniz Haziran''da sona eriyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Technology</strong><br>(Teknoloji)</td>\n            <td>Storage, memory, or battery depletion</td>\n            <td>The server ran out of disk space.</td>\n            <td>Sunucunun disk alanı tükendi.</td>\n          </tr>\n          <tr>\n            <td><strong>Environment</strong><br>(Çevre)</td>\n            <td>Natural resources being depleted</td>\n            <td>Scientists predict we could run out of fresh water by 2050.</td>\n            <td>Bilim insanları 2050''ye kadar tatlı su kaynaklarımızın tükenebileceğini öngörüyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Sports</strong><br>(Spor)</td>\n            <td>Running out of energy / stamina</td>\n            <td>The runner ran out of steam in the final lap.</td>\n            <td>Koşucu son turda enerjisini kaybetti.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "Other Phrasal Verbs with \"Run\" / \"Run\" İle Diğer Öbekli Fiiller", "content": "<table>\n        <thead><tr><th>Phrasal Verb</th><th>Meaning</th><th>Turkish</th><th>Example</th></tr></thead>\n        <tbody>\n          <tr><td><strong>run into</strong></td><td>to meet by chance; to collide with</td><td>tesadüfen karşılaşmak; çarpmak</td><td>I ran into my old teacher at the mall.</td></tr>\n          <tr><td><strong>run over</strong></td><td>to hit with a vehicle; to exceed time</td><td>araçla ezmek; süreyi aşmak</td><td>The meeting ran over by 30 minutes.</td></tr>\n          <tr><td><strong>run through</strong></td><td>to review quickly; to practice</td><td>hızlıca gözden geçirmek; prova etmek</td><td>Let''s run through the presentation once more.</td></tr>\n          <tr><td><strong>run away</strong></td><td>to escape, to flee</td><td>kaçmak, firar etmek</td><td>The cat ran away from the dog.</td></tr>\n          <tr><td><strong>run up</strong></td><td>to accumulate (debt/costs)</td><td>biriktirmek (borç/masraf)</td><td>She ran up a huge credit card bill.</td></tr>\n          <tr><td><strong>run down</strong></td><td>to lose power; to criticize</td><td>gücü tükenmek; eleştirmek, kötülemek</td><td>The battery has run down completely.</td></tr>\n          <tr><td><strong>run after</strong></td><td>to chase</td><td>kovalamak, peşinden koşmak</td><td>The dog ran after the ball.</td></tr>\n        </tbody>\n      </table>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('spike', 'SPIKE', '/spaɪk/', 'sivri uç · ani artış · çivi · sıçramak · artırmak', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Spike</strong> hem isim hem de fiil olarak kullanılan, çok yönlü bir kelimedir. Fiziksel, istatistiksel, spor ve günlük dilde farklı anlamlar taşır.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Spike\" kelimesinin temelinde <em>\"sivri, keskin bir çıkıntı\"</em> somut anlamı vardır. Bir çivinin veya dikenin sivri ucu gibi düşünün. Buradan yola çıkarak, bir grafikte ani ve keskin bir yükseliş de \"spike\" olarak adlandırılır — çünkü grafikteki şekil sivri bir tepeye benzer. Fiil olarak ise \"ani bir şekilde yükselmek\" veya \"bir şeye gizlice bir şey eklemek\" gibi anlamlara genişlemiştir.</p>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Noun</strong> (isim)</td><td>A thin, sharp piece of metal or wood</td><td>Sivri uç, çivi, diken</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>A sudden, sharp increase</td><td>Ani artış, sıçrama, zirve</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>Metal points on the bottom of sports shoes</td><td>Krampon çivisi, krampon dişi</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To increase sharply and suddenly</td><td>Ani bir şekilde artmak/yükselmek</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To add alcohol or drugs to a drink secretly</td><td>İçeceğe gizlice bir şey katmak</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To push something sharp into; to impale</td><td>Sivri bir şeyle saplamak</td></tr>\n          <tr><td><strong>Verb</strong> (fiil)</td><td>To hit the ball downward forcefully (volleyball)</td><td>Smaç vurmak (voleybol)</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>spike</strong></td><td>noun (isim)</td><td>sivri uç, ani artış, çivi</td></tr>\n          <tr><td><strong>spike</strong></td><td>verb (fiil)</td><td>ani artmak, gizlice katmak, saplamak</td></tr>\n          <tr><td><strong>spiked</strong></td><td>adjective (sıfat)</td><td>sivri uçlu, dikenli; içine bir şey katılmış</td></tr>\n          <tr><td><strong>spiky / spikey</strong></td><td>adjective (sıfat)</td><td>dikenli, sivri, diklik saçlı</td></tr>\n          <tr><td><strong>spikes</strong></td><td>noun (isim, çoğul)</td><td>krampon ayakkabılar; sivri uçlar</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Spike\" düzenli (regular) bir fiildir: <strong>spike – spiked – spiked</strong>. Çoğul isim formu: <strong>spikes</strong>.\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>a spike in + something</code>\n        <div>→ Bir şeydeki ani artış</div>\n        <div class=\"example\"><em>There was <strong>a spike in</strong> oil prices.</em></div>\n        <div class=\"turkish\">Petrol fiyatlarında ani bir artış oldu.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>something + spike(s)</code>\n        <div>→ Bir şey ani bir şekilde yükselir</div>\n        <div class=\"example\"><em>Temperatures <strong>spiked</strong> to 45°C yesterday.</em></div>\n        <div class=\"turkish\">Sıcaklıklar dün 45°C''ye sıçradı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>spike + someone''s drink</code>\n        <div>→ Birinin içeceğine gizlice bir şey katmak</div>\n        <div class=\"example\"><em>Someone <strong>spiked</strong> his drink at the party.</em></div>\n        <div class=\"turkish\">Partide birisi onun içeceğine gizlice bir şey kattı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>spike + something + with + something</code>\n        <div>→ Bir şeye … ile lezzet/içerik katmak</div>\n        <div class=\"example\"><em>She <strong>spiked</strong> the punch <strong>with</strong> vodka.</em></div>\n        <div class=\"turkish\">Meşrubata votka kattı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>spike the ball (sports)</code>\n        <div>→ Topu sert bir şekilde yere vurmak / smaç yapmak</div>\n        <div class=\"example\"><em>He <strong>spiked the ball</strong> for the winning point.</em></div>\n        <div class=\"turkish\">Kazandıran sayı için topa smaç vurdu.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>spike / spikes</td><td>Demand spikes every December.</td><td>Talep her Aralık''ta ani artış gösterir.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are spiking</td><td>Prices are spiking due to the crisis.</td><td>Kriz nedeniyle fiyatlar hızla artıyor.</td></tr>\n          <tr><td>Simple Past</td><td>spiked</td><td>Infections spiked last winter.</td><td>Enfeksiyonlar geçen kış ani artış gösterdi.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were spiking</td><td>Traffic was spiking when the server crashed.</td><td>Sunucu çöktüğünde trafik hızla artıyordu.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has spiked</td><td>Energy costs have spiked this year.</td><td>Enerji maliyetleri bu yıl ani artış gösterdi.</td></tr>\n          <tr><td>Past Perfect</td><td>had spiked</td><td>The fever had spiked before the doctor arrived.</td><td>Doktor gelmeden önce ateş yükselmişti.</td></tr>\n          <tr><td>Future Simple</td><td>will spike</td><td>Experts say inflation will spike next quarter.</td><td>Uzmanlar enflasyonun gelecek çeyrekte sıçrayacağını söylüyor.</td></tr>\n          <tr><td>Future Perfect</td><td>will have spiked</td><td>By summer, temperatures will have spiked several times.</td><td>Yaza kadar sıcaklıklar birkaç kez ani yükseliş göstermiş olacak.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Spike\" edilgen çatıda özellikle \"içeceğe bir şey katma\" anlamında sıkça kullanılır:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Someone spiked the drink.</td><td>The drink <strong>was spiked</strong>.</td><td>İçeceğe bir şey katılmış.</td></tr>\n          <tr><td>She spiked the coffee with rum.</td><td>The coffee <strong>was spiked with</strong> rum.</td><td>Kahveye rom katılmış.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>a spike <strong>in</strong> something</td><td>A spike in crime rates.</td><td>Suç oranlarında ani artış.</td></tr>\n          <tr><td>spike <strong>to</strong> (a level)</td><td>Prices spiked to $200.</td><td>Fiyatlar 200 dolara sıçradı.</td></tr>\n          <tr><td>spike <strong>by</strong> (an amount)</td><td>Sales spiked by 40%.</td><td>Satışlar %40 arttı.</td></tr>\n          <tr><td>spike something <strong>with</strong> something</td><td>Spike the lemonade with gin.</td><td>Limonataya cin katmak.</td></tr>\n          <tr><td>spike <strong>above</strong> / <strong>beyond</strong></td><td>Temperatures spiked above 40°C.</td><td>Sıcaklıklar 40°C''nin üzerine sıçradı.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">price spike <span class=\"tr\">— fiyat sıçraması</span></span>\n        <span class=\"collocation-tag\">traffic spike <span class=\"tr\">— trafik artışı</span></span>\n        <span class=\"collocation-tag\">temperature spike <span class=\"tr\">— sıcaklık sıçraması</span></span>\n        <span class=\"collocation-tag\">spike in demand <span class=\"tr\">— talep artışı</span></span>\n        <span class=\"collocation-tag\">spike in cases <span class=\"tr\">— vaka artışı</span></span>\n        <span class=\"collocation-tag\">sudden spike <span class=\"tr\">— ani sıçrama</span></span>\n        <span class=\"collocation-tag\">sharp spike <span class=\"tr\">— keskin artış</span></span>\n        <span class=\"collocation-tag\">spike a drink <span class=\"tr\">— içeceğe bir şey katmak</span></span>\n        <span class=\"collocation-tag\">spiked hair <span class=\"tr\">— dikleştirilmiş saç</span></span>\n        <span class=\"collocation-tag\">spiked shoes <span class=\"tr\">— krampon ayakkabı</span></span>\n        <span class=\"collocation-tag\">voltage spike <span class=\"tr\">— gerilim sıçraması</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. Be careful — there are spikes on the fence.</div>\n          <div class=\"tr\">Dikkatli ol — çitin üzerinde sivri uçlar var.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. Gas prices spiked last week.</div>\n          <div class=\"tr\">Benzin fiyatları geçen hafta ani artış gösterdi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. She spiked the ball over the net.</div>\n          <div class=\"tr\">Topu file üzerinden smaçladı.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. There has been a sharp spike in online shopping since the pandemic.</div>\n          <div class=\"tr\">Pandemiden bu yana online alışverişte keskin bir artış oldu.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The detective suspected someone had spiked the victim''s drink.</div>\n          <div class=\"tr\">Dedektif, birisinin kurbanın içeceğine bir şey kattığından şüphelendi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. Website traffic spiked to 10 million visits after the ad campaign.</div>\n          <div class=\"tr\">Reklam kampanyasından sonra web sitesi trafiği 10 milyon ziyarete sıçradı.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. The central bank raised interest rates to counteract the spike in inflation.</div>\n          <div class=\"tr\">Merkez bankası enflasyondaki ani yükselişe karşı koymak için faiz oranlarını artırdı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. Analysts warned that a voltage spike could damage the entire power grid.</div>\n          <div class=\"tr\">Analistler, bir gerilim sıçramasının tüm elektrik şebekesine zarar verebileceği konusunda uyardı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. The data showed a concerning spike in cortisol levels among participants under stress.</div>\n          <div class=\"tr\">Veriler, stres altındaki katılımcılar arasında endişe verici bir kortizol seviyesi sıçraması gösterdi.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Informal & Idioms / Günlük Dil ve Deyimler</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. He spiked his hair with gel for the concert.</div>\n          <div class=\"tr\">Konser için saçlarını jöle ile dikleştirdi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. The editor decided to spike the story (= reject/cancel it).</div>\n          <div class=\"tr\">Editör haberi geri çekmeye (iptal etmeye) karar verdi.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>Middle English (13. yüzyıl)</td></tr>\n          <tr><td><strong>Root</strong></td><td>Old Norse: <strong>spík</strong> (nail, spike) veya Middle Dutch: <strong>spiker</strong> (nail)</td></tr>\n          <tr><td><strong>Latin connection</strong></td><td>Latin: <strong>spīca</strong> (ear of grain / başak) — sivri uçlu şekil benzerliğinden</td></tr>\n          <tr><td><strong>Original meaning</strong></td><td>\"Büyük, sivri çivi\" — demiryolu raylarını sabitleyen çiviler (railroad spikes) bu anlamın en bilinen örneğidir.</td></tr>\n          <tr><td><strong>Graph sense</strong></td><td>20. yüzyılda \"grafikte sivri tepe\" → \"ani artış\" anlamı yaygınlaştı. Grafikte oluşan keskin çıkıntı fiziksel bir spike''a benzediği için bu isim verildi.</td></tr>\n          <tr><td><strong>Drink sense</strong></td><td>\"İçeceğe gizlice bir şey katmak\" anlamı 1800''lerin sonunda ABD''de ortaya çıktı. Muhtemelen \"bir şeyi sivri bir aletle delmek/karıştırmak\" eylemine dayalıdır.</td></tr>\n          <tr><td><strong>Sports sense</strong></td><td>Voleybolda \"spike\" terimi 1920''lerden beri kullanılmaktadır — topun aşağı doğru sivri bir açıyla vurulması.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>spiky</strong></td><td>having sharp points</td><td>dikenli, sivri</td></tr>\n          <tr><td><strong>spire</strong></td><td>a tall pointed structure (church)</td><td>sivri kule (kilise)</td></tr>\n          <tr><td><strong>spine</strong></td><td>backbone; thorn</td><td>omurga; diken</td></tr>\n          <tr><td><strong>spike (botany)</strong></td><td>a type of flower cluster</td><td>başak (botanik)</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Spike\" kelimesini kafanızda \"sivri bir çivi\" olarak hayal edin. Her anlamı bu sivri şekle bağlanır: grafikte sivri tepe = ani artış, sivri uçlu ayakkabılar = krampon, topu sivri açıyla vurmak = smaç. Şekli hatırlayın, anlamları gelsin!\n      </div>"}, {"icon": "⚖️", "title": "Spike vs. Surge vs. Jump vs. Soar / Farkları", "content": "<p>\"Ani artış\" anlamında kullanılan bu kelimeler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Spike</th><th>Surge</th><th>Jump</th><th>Soar</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Character</td>\n            <td>Sharp, sudden, often temporary<br><em>Keskin, ani, genelde geçici</em></td>\n            <td>Powerful, wave-like increase<br><em>Güçlü, dalga gibi artış</em></td>\n            <td>Quick, noticeable increase<br><em>Hızlı, fark edilir artış</em></td>\n            <td>Rising very high, continuous<br><em>Çok yükselen, sürekli</em></td>\n          </tr>\n          <tr>\n            <td>Duration</td>\n            <td>Usually brief<br><em>Genelde kısa süreli</em></td>\n            <td>Can last a while<br><em>Bir süre devam edebilir</em></td>\n            <td>Brief<br><em>Kısa</em></td>\n            <td>Extended<br><em>Uzun süreli</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>A spike in fever.</td>\n            <td>A surge in demand.</td>\n            <td>A jump in profits.</td>\n            <td>Prices soared this year.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Ateşte ani sıçrama.</td>\n            <td>Talepte dalgalanma/artış.</td>\n            <td>Kârlarda sıçrama.</td>\n            <td>Fiyatlar bu yıl fırladı.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Spike\" genellikle <em>geçici</em> ve <em>keskin</em> bir artışı ifade eder — yükselir ve tekrar düşer. \"Surge\" daha güçlü ve biraz daha kalıcıdır. \"Soar\" ise yükselip yukarıda kaldığını ima eder.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Finance</strong><br>(Finans)</td>\n            <td>Sudden price or rate increase</td>\n            <td>Bitcoin saw a massive spike overnight.</td>\n            <td>Bitcoin bir gecede büyük bir sıçrama gördü.</td>\n          </tr>\n          <tr>\n            <td><strong>Medicine</strong><br>(Tıp)</td>\n            <td>Sudden rise in body temperature or vitals</td>\n            <td>The patient''s blood pressure spiked.</td>\n            <td>Hastanın kan basıncı ani artış gösterdi.</td>\n          </tr>\n          <tr>\n            <td><strong>Technology</strong><br>(Teknoloji)</td>\n            <td>Traffic or load spike on servers</td>\n            <td>The server couldn''t handle the traffic spike.</td>\n            <td>Sunucu trafik sıçramasını kaldıramadı.</td>\n          </tr>\n          <tr>\n            <td><strong>Sports</strong><br>(Spor)</td>\n            <td>Forceful downward hit (volleyball)</td>\n            <td>She scored with a powerful spike.</td>\n            <td>Güçlü bir smaçla sayı yaptı.</td>\n          </tr>\n          <tr>\n            <td><strong>Electrical</strong><br>(Elektrik)</td>\n            <td>Voltage spike — sudden increase in power</td>\n            <td>A voltage spike damaged the motherboard.</td>\n            <td>Gerilim sıçraması anakartı bozdu.</td>\n          </tr>\n          <tr>\n            <td><strong>Journalism</strong><br>(Gazetecilik)</td>\n            <td>To spike a story — to kill/cancel an article</td>\n            <td>The editor spiked the controversial article.</td>\n            <td>Editör tartışmalı makaleyi geri çekti.</td>\n          </tr>\n        </tbody>\n      </table>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('stand-alone', 'STAND ALONE', '/ˌstænd əˈloʊn/', 'tek başına durmak · bağımsız olmak · eşsiz olmak', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Stand alone</strong> hem bir <em>phrasal verb</em> (öbekli fiil) hem de birleşik sıfat (<em>standalone / stand-alone</em>) olarak kullanılır. İngilizce''de çok yönlü ve güçlü bir ifadedir.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Stand alone\" ifadesinin özünde <em>\"tek başına ayakta durmak\"</em> fiziksel anlamı vardır. Buradan mecazi olarak üç önemli anlam dalı çıkar: (1) bağımsız olmak, hiçbir şeye bağlı olmadan işlev görmek, (2) eşsiz/benzersiz olmak, hiçbir şeyle kıyaslanamamak, (3) bir konuda yalnız kalmak, desteklenmemek. Sıfat olarak \"standalone\" ise özellikle teknoloji ve iş dünyasında \"bağımsız çalışan\" anlamında çok yaygındır.</p>\n\n      <table>\n        <thead><tr><th>Usage</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Phrasal Verb</strong><br>Bağımsızlık</td><td>To function independently, without needing support</td><td>Bağımsız olmak, tek başına işlev görmek</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Eşsizlik</td><td>To be unique, unmatched, or superior</td><td>Eşsiz olmak, benzersiz olmak, rakipsiz olmak</td></tr>\n          <tr><td><strong>Phrasal Verb</strong><br>Yalnızlık</td><td>To be alone in an opinion or position</td><td>Tek başına kalmak, yalnız durmak</td></tr>\n          <tr><td><strong>Adjective</strong><br>(standalone / stand-alone)</td><td>Operating independently; not connected to other systems</td><td>Bağımsız, tek başına çalışan, müstakil</td></tr>\n          <tr><td><strong>Noun</strong><br>(standalone)</td><td>A device or software that works independently</td><td>Bağımsız cihaz/yazılım</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>stand alone</strong></td><td>phrasal verb (öbekli fiil)</td><td>tek başına durmak, bağımsız olmak</td></tr>\n          <tr><td><strong>standalone / stand-alone</strong></td><td>adjective (sıfat)</td><td>bağımsız, müstakil, tek başına çalışan</td></tr>\n          <tr><td><strong>standalone</strong></td><td>noun (isim)</td><td>bağımsız cihaz/uygulama</td></tr>\n          <tr><td><strong>standing alone</strong></td><td>present participle</td><td>tek başına duran</td></tr>\n          <tr><td><strong>stood alone</strong></td><td>past tense</td><td>tek başına durdu</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Yazım Kuralı:</strong><br>\n        <strong>Fiil olarak:</strong> iki ayrı kelime → <em>stand alone</em><br>\n        <strong>Sıfat olarak:</strong> tire ile veya bitişik → <em>stand-alone</em> veya <em>standalone</em><br>\n        ✅ <em>This is a <strong>standalone</strong> application.</em> (sıfat — bitişik veya tireli)<br>\n        ✅ <em>The building <strong>stands alone</strong> on the hill.</em> (fiil — ayrı)<br>\n        ❌ <em>The building <strong>standalones</strong> on the hill.</em> (yanlış!)\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>stand alone (as something unique)</code>\n        <div>→ Eşsiz/benzersiz olmak</div>\n        <div class=\"example\"><em>This novel <strong>stands alone</strong> as a masterpiece of modern literature.</em></div>\n        <div class=\"turkish\">Bu roman modern edebiyatın başyapıtı olarak eşsizdir.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>stand alone + in + doing something / area</code>\n        <div>→ Bir alanda tek başına olmak</div>\n        <div class=\"example\"><em>Japan <strong>stands alone in</strong> its approach to robotics.</em></div>\n        <div class=\"turkish\">Japonya robotik yaklaşımında tek başınadır (benzersizdir).</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>stand alone + against + something/someone</code>\n        <div>→ Bir şeye/birine karşı yalnız durmak</div>\n        <div class=\"example\"><em>She <strong>stood alone against</strong> the entire board.</em></div>\n        <div class=\"turkish\">Tüm yönetim kuruluna karşı yalnız durdu.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>standalone + noun (adjective usage)</code>\n        <div>→ Bağımsız + isim</div>\n        <div class=\"example\"><em>We need a <strong>standalone</strong> server for this project.</em></div>\n        <div class=\"turkish\">Bu proje için bağımsız bir sunucuya ihtiyacımız var.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>can stand alone</code>\n        <div>→ Tek başına var olabilmek / yeterli olmak</div>\n        <div class=\"example\"><em>Each chapter <strong>can stand alone</strong> as a short story.</em></div>\n        <div class=\"turkish\">Her bölüm tek başına bir kısa öykü olarak var olabilir.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses / Fiil Zamanları", "content": "<div class=\"tip\" style=\"margin-bottom: 1rem;\">\n        <strong>⚠️ Not:</strong> \"Stand\" düzensiz (irregular) bir fiildir: <strong>stand – stood – stood</strong>. \"Alone\" kısmı değişmez.\n      </div>\n\n      <table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>stand(s) alone</td><td>This product stands alone in quality.</td><td>Bu ürün kalitede eşsizdir.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are standing alone</td><td>He is standing alone on this issue.</td><td>Bu konuda tek başına duruyor.</td></tr>\n          <tr><td>Simple Past</td><td>stood alone</td><td>The old tree stood alone in the field.</td><td>Yaşlı ağaç tarlada tek başına duruyordu.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were standing alone</td><td>She was standing alone when I arrived.</td><td>Ben vardığımda tek başına duruyordu.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has stood alone</td><td>This record has stood alone for 20 years.</td><td>Bu rekor 20 yıldır kırılmadan tek başına duruyor.</td></tr>\n          <tr><td>Past Perfect</td><td>had stood alone</td><td>The castle had stood alone for centuries.</td><td>Kale yüzyıllarca tek başına durmuştu.</td></tr>\n          <tr><td>Future Simple</td><td>will stand alone</td><td>This achievement will stand alone in history.</td><td>Bu başarı tarihte eşsiz olarak kalacak.</td></tr>\n          <tr><td>Future Perfect</td><td>will have stood alone</td><td>By then, the lighthouse will have stood alone for 200 years.</td><td>O zamana kadar deniz feneri 200 yıldır tek başına durmuş olacak.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>stand alone <strong>in</strong> (a field/area)</td><td>She stands alone in her expertise.</td><td>Uzmanlığında eşsizdir.</td></tr>\n          <tr><td>stand alone <strong>as</strong> (something)</td><td>It stands alone as the best option.</td><td>En iyi seçenek olarak rakipsizdir.</td></tr>\n          <tr><td>stand alone <strong>against</strong> (opposition)</td><td>He stood alone against corruption.</td><td>Yolsuzluğa karşı tek başına durdu.</td></tr>\n          <tr><td>stand alone <strong>among</strong> (peers)</td><td>This design stands alone among competitors.</td><td>Bu tasarım rakipler arasında benzersizdir.</td></tr>\n          <tr><td>stand alone <strong>on</strong> (an issue)</td><td>We stand alone on this decision.</td><td>Bu konuda tek başınayız.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">standalone application <span class=\"tr\">— bağımsız uygulama</span></span>\n        <span class=\"collocation-tag\">standalone device <span class=\"tr\">— bağımsız cihaz</span></span>\n        <span class=\"collocation-tag\">standalone software <span class=\"tr\">— bağımsız yazılım</span></span>\n        <span class=\"collocation-tag\">standalone product <span class=\"tr\">— bağımsız ürün</span></span>\n        <span class=\"collocation-tag\">standalone system <span class=\"tr\">— bağımsız sistem</span></span>\n        <span class=\"collocation-tag\">standalone feature <span class=\"tr\">— bağımsız özellik</span></span>\n        <span class=\"collocation-tag\">standalone episode <span class=\"tr\">— bağımsız bölüm</span></span>\n        <span class=\"collocation-tag\">standalone novel <span class=\"tr\">— bağımsız roman (seri olmayan)</span></span>\n        <span class=\"collocation-tag\">can stand alone <span class=\"tr\">— tek başına yeterli olabilir</span></span>\n        <span class=\"collocation-tag\">truly stands alone <span class=\"tr\">— gerçekten eşsizdir</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. The house stands alone on the hill.</div>\n          <div class=\"tr\">Ev tepenin üzerinde tek başına duruyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. This is a standalone app.</div>\n          <div class=\"tr\">Bu bağımsız bir uygulamadır.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. She stood alone in the empty room.</div>\n          <div class=\"tr\">Boş odada tek başına durdu.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. No other company can match them — they stand alone in the industry.</div>\n          <div class=\"tr\">Hiçbir şirket onlarla boy ölçüşemez — sektörde eşsizdirler.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The software works as a standalone product, no internet required.</div>\n          <div class=\"tr\">Yazılım bağımsız bir ürün olarak çalışır, internet gerekmez.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. Each episode stands alone, so you can watch them in any order.</div>\n          <div class=\"tr\">Her bölüm bağımsızdır, bu yüzden istediğiniz sırayla izleyebilirsiniz.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. His courage to stand alone against injustice inspired millions.</div>\n          <div class=\"tr\">Adaletsizliğe karşı tek başına durma cesareti milyonlara ilham verdi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. The evidence stands alone as sufficient proof of the defendant''s innocence.</div>\n          <div class=\"tr\">Kanıt, sanığın masumiyetinin yeterli delili olarak tek başına yeterlidir.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. While most frameworks require dependencies, this one stands alone — a testament to its elegant design.</div>\n          <div class=\"tr\">Çoğu framework bağımlılık gerektirirken, bu tek başına çalışır — zarif tasarımının bir kanıtıdır.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Technology / Teknoloji</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. We deployed it as a standalone microservice.</div>\n          <div class=\"tr\">Onu bağımsız bir mikro hizmet olarak dağıttık.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. The VR headset is standalone — no PC needed.</div>\n          <div class=\"tr\">VR başlığı bağımsızdır — bilgisayara gerek yoktur.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Type</strong></td><td>Compound phrase: <strong>stand</strong> + <strong>alone</strong></td></tr>\n          <tr><td><strong>\"Stand\" origin</strong></td><td>Old English: <strong>standan</strong> → Proto-Germanic: <strong>*standaną</strong> → PIE root: <strong>*steh₂-</strong> (to stand, to be firm / ayakta durmak, sağlam olmak)</td></tr>\n          <tr><td><strong>\"Alone\" origin</strong></td><td>Middle English: <strong>al one</strong> = \"all one\" → \"completely by oneself\" (tamamen tek başına)</td></tr>\n          <tr><td><strong>Literal meaning</strong></td><td>\"to be standing all by oneself\" / \"tamamen tek başına ayakta durmak\"</td></tr>\n          <tr><td><strong>Evolution</strong></td><td>Fiziksel olarak \"tek başına ayakta durmak\" anlamından → mecazi olarak \"bağımsız olmak, eşsiz olmak\" anlamına evrilmiştir. 20. yüzyılda teknolojide \"standalone\" sıfatı yaygınlaşmıştır.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (*steh₂-)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>stand</strong></td><td>to be on your feet; to endure</td><td>ayakta durmak; katlanmak</td></tr>\n          <tr><td><strong>standard</strong></td><td>a level of quality; a flag</td><td>standart, ölçüt</td></tr>\n          <tr><td><strong>stance</strong></td><td>a way of standing; an opinion</td><td>duruş; tutum</td></tr>\n          <tr><td><strong>outstanding</strong></td><td>exceptionally good</td><td>olağanüstü, mükemmel</td></tr>\n          <tr><td><strong>understand</strong></td><td>to comprehend</td><td>anlamak</td></tr>\n          <tr><td><strong>withstand</strong></td><td>to resist, to endure</td><td>dayanmak, karşı koymak</td></tr>\n          <tr><td><strong>stable</strong></td><td>firm, not changing</td><td>istikrarlı, sabit</td></tr>\n          <tr><td><strong>station</strong></td><td>a place where things stand/stop</td><td>istasyon, durak</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Stand alone\" ifadesini kafanızda \"tek başına, sağlam bir şekilde ayakta durmak\" olarak hayal edin. Hiçbir desteğe ihtiyaç duymadan, kendi ayakları üzerinde duran bir şey — işte bu \"stand alone\"dur. Aynı kök (*steh₂-) birçok İngilizce kelimeye \"sağlamlık ve ayakta durma\" anlamı vermiştir.\n      </div>"}, {"icon": "⚖️", "title": "Stand Alone vs. Independent vs. Self-Contained / Farkları", "content": "<p>Bu üç ifade \"bağımsız\" anlamında kullanılır ama nüansları farklıdır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Stand Alone / Standalone</th><th>Independent</th><th>Self-Contained</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Focus</td>\n            <td>Works without external connection<br><em>Dış bağlantı olmadan çalışır</em></td>\n            <td>Free from control or influence<br><em>Kontrol veya etkiden bağımsız</em></td>\n            <td>Complete in itself, all parts included<br><em>Kendi içinde eksiksiz</em></td>\n          </tr>\n          <tr>\n            <td>Common use</td>\n            <td>Technology, products<br><em>Teknoloji, ürünler</em></td>\n            <td>General, political, personal<br><em>Genel, siyasi, kişisel</em></td>\n            <td>Housing, systems<br><em>Konut, sistemler</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>A standalone GPS device.</td>\n            <td>An independent nation.</td>\n            <td>A self-contained apartment.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Bağımsız bir GPS cihazı.</td>\n            <td>Bağımsız bir ülke.</td>\n            <td>Müstakil bir daire.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Standalone\" özellikle teknolojide ve ürünlerde tercih edilir. \"Independent\" daha genel ve soyut bağımsızlık için kullanılır. \"Self-contained\" ise \"her şeyi kendi içinde barındıran\" anlamını vurgular.\n      </div>"}, {"icon": "🧩", "title": "Other Phrasal Verbs with \"Stand\" / \"Stand\" İle Diğer Öbekli Fiiller", "content": "<table>\n        <thead><tr><th>Phrasal Verb</th><th>Meaning</th><th>Turkish</th><th>Example</th></tr></thead>\n        <tbody>\n          <tr><td><strong>stand by</strong></td><td>to wait; to support</td><td>beklemek; desteklemek</td><td>I''ll stand by you no matter what.</td></tr>\n          <tr><td><strong>stand for</strong></td><td>to represent; to tolerate</td><td>temsil etmek; hoşgörmek</td><td>UN stands for United Nations.</td></tr>\n          <tr><td><strong>stand out</strong></td><td>to be noticeable</td><td>göze çarpmak, öne çıkmak</td><td>Her talent stands out.</td></tr>\n          <tr><td><strong>stand up</strong></td><td>to rise to your feet</td><td>ayağa kalkmak</td><td>Please stand up.</td></tr>\n          <tr><td><strong>stand up for</strong></td><td>to defend</td><td>savunmak, tarafını tutmak</td><td>Stand up for your rights.</td></tr>\n          <tr><td><strong>stand down</strong></td><td>to resign; to withdraw</td><td>çekilmek, istifa etmek</td><td>The CEO decided to stand down.</td></tr>\n          <tr><td><strong>stand in for</strong></td><td>to replace temporarily</td><td>yerine geçmek, vekalet etmek</td><td>She stood in for the teacher.</td></tr>\n        </tbody>\n      </table>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('vetting', 'VETTING', '/ˈvetɪŋ/', 'inceleme · denetleme · soruşturma · güvenlik araştırması · kontrol etme', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Vetting</strong>, bir kişi, belge, plan veya ürünün uygunluğunu, güvenilirliğini veya kalitesini belirlemek amacıyla yapılan <em>dikkatli inceleme ve araştırma süreci</em>dir. \"Vet\" fiilinin isim-fiil (gerund) / present participle formudur.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Vetting\" kelimesinin kökeni ilginçtir: at yarışlarında bir <em>veteriner</em> (vet) hayvanın sağlığını kontrol eder ve yarışa uygun olup olmadığına karar verirdi. Bu somut eylemden mecazi anlam türemiştir: bir kişiyi veya şeyi \"vet etmek\" = onu dikkatle incelemek, uygunluğunu araştırmak. Günümüzde özellikle üç bağlamda karşılaşırsınız: (1) <strong>İnsan kaynakları</strong> — aday özgeçmişlerini ve referanslarını kontrol etme. (2) <strong>Güvenlik</strong> — bir kişinin geçmişini, sabıka kaydını, bağlantılarını araştırma (security vetting). (3) <strong>Genel</strong> — herhangi bir bilgiyi, planı veya belgeyi doğruluk ve kalite açısından gözden geçirme.</p>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Noun</strong> (isim)</td><td>The process of carefully examining someone or something for suitability</td><td>İnceleme, denetleme, araştırma süreci</td></tr>\n          <tr><td><strong>Noun</strong> (isim)</td><td>Background investigation, especially for security clearance</td><td>Güvenlik soruşturması, geçmiş araştırması</td></tr>\n          <tr><td><strong>Gerund</strong> (isim-fiil)</td><td>The act of vetting (from the verb \"to vet\")</td><td>\"Vet etme\" eylemi (inceleme yapmak)</td></tr>\n          <tr><td><strong>Verb: vet</strong> (fiil)</td><td>To examine carefully; to check for accuracy or suitability</td><td>İncelemek, denetlemek, kontrol etmek</td></tr>\n          <tr><td><strong>Verb: vet</strong> (fiil, orijinal)</td><td>To treat an animal medically (as a veterinarian)</td><td>Veteriner olarak tedavi etmek</td></tr>\n        </tbody>\n      </table>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>vet</strong></td><td>verb (fiil)</td><td>incelemek, denetlemek, kontrol etmek</td></tr>\n          <tr><td><strong>vet</strong></td><td>noun (isim)</td><td>veteriner (kısaltma)</td></tr>\n          <tr><td><strong>vetting</strong></td><td>noun / gerund (isim / isim-fiil)</td><td>inceleme, denetleme, soruşturma</td></tr>\n          <tr><td><strong>vetted</strong></td><td>adjective / past participle</td><td>incelenmiş, onaylanmış, denetlenmiş</td></tr>\n          <tr><td><strong>veterinarian</strong></td><td>noun (isim)</td><td>veteriner hekim</td></tr>\n          <tr><td><strong>veterinary</strong></td><td>adjective (sıfat)</td><td>veterinerlik ile ilgili</td></tr>\n          <tr><td><strong>unvetted</strong></td><td>adjective (sıfat)</td><td>incelenmemiş, denetlenmemiş</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Vet\" düzenli (regular) bir fiildir: <strong>vet – vetted – vetted</strong>.<br>\n        Present participle: <strong>vetting</strong> (çift ''t'' — CVC kuralı: vet → vetted / vetting)\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>vet + someone / something</code>\n        <div>→ Birini / bir şeyi incelemek, denetlemek</div>\n        <div class=\"example\"><em>All candidates are <strong>vetted</strong> before the interview stage.</em></div>\n        <div class=\"turkish\">Tüm adaylar mülakat aşamasından önce incelenir.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>vet + someone + for + (role / position / clearance)</code>\n        <div>→ Birini belirli bir rol/pozisyon için araştırmak</div>\n        <div class=\"example\"><em>She was <strong>vetted for</strong> a senior intelligence role.</em></div>\n        <div class=\"turkish\">Üst düzey bir istihbarat görevi için güvenlik soruşturmasından geçti.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>undergo vetting / go through vetting</code>\n        <div>→ İnceleme / soruşturma sürecinden geçmek</div>\n        <div class=\"example\"><em>Employees must <strong>undergo vetting</strong> before accessing classified data.</em></div>\n        <div class=\"turkish\">Çalışanlar gizli verilere erişmeden önce güvenlik soruşturmasından geçmelidir.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>the vetting process / vetting procedure</code>\n        <div>→ İnceleme süreci / denetleme prosedürü</div>\n        <div class=\"example\"><em>The <strong>vetting process</strong> takes approximately six weeks.</em></div>\n        <div class=\"turkish\">İnceleme süreci yaklaşık altı hafta sürer.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>thoroughly / carefully / properly vetted</code>\n        <div>→ Kapsamlı / dikkatli / düzgün şekilde incelenmiş</div>\n        <div class=\"example\"><em>Make sure every supplier is <strong>thoroughly vetted</strong>.</em></div>\n        <div class=\"turkish\">Her tedarikçinin kapsamlı bir şekilde incelendiğinden emin ol.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>security vetting</code>\n        <div>→ Güvenlik soruşturması (en yaygın bileşik isim)</div>\n        <div class=\"example\"><em>He failed the <strong>security vetting</strong> due to undisclosed foreign contacts.</em></div>\n        <div class=\"turkish\">Bildirilmemiş yabancı bağlantıları nedeniyle güvenlik soruşturmasını geçemedi.</div>\n      </div>"}, {"icon": "⏱️", "title": "Verb Tenses: \"Vet\" / Fiil Zamanları", "content": "<div class=\"tip\" style=\"margin-bottom: 1rem;\">\n        <strong>📌 Not:</strong> \"Vetting\" bir isim-fiildir (gerund). Fiil hali <strong>vet</strong>''tir. Düzenli fiildir: <strong>vet – vetted – vetted</strong>. Çift ''t'' kuralını unutmayın!\n      </div>\n\n      <table>\n        <thead><tr><th>Tense</th><th>Form</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Simple Present</td><td>vet / vets</td><td>The agency vets all applicants carefully.</td><td>Ajans tüm başvuru sahiplerini dikkatle inceler.</td></tr>\n          <tr><td>Present Continuous</td><td>am/is/are vetting</td><td>We are currently vetting the new suppliers.</td><td>Şu anda yeni tedarikçileri inceliyoruz.</td></tr>\n          <tr><td>Simple Past</td><td>vetted</td><td>The committee vetted the proposal last week.</td><td>Komite geçen hafta teklifi inceledi.</td></tr>\n          <tr><td>Past Continuous</td><td>was/were vetting</td><td>They were vetting candidates when the policy changed.</td><td>Politika değiştiğinde adayları inceliyorlardı.</td></tr>\n          <tr><td>Present Perfect</td><td>have/has vetted</td><td>We have vetted over 200 applications this quarter.</td><td>Bu çeyrekte 200''den fazla başvuruyu inceledik.</td></tr>\n          <tr><td>Past Perfect</td><td>had vetted</td><td>She had already been vetted before joining the team.</td><td>Ekibe katılmadan önce zaten incelenmişti.</td></tr>\n          <tr><td>Future Simple</td><td>will vet</td><td>The board will vet the final candidates next Monday.</td><td>Kurul gelecek Pazartesi son adayları inceleyecek.</td></tr>\n          <tr><td>Future Perfect</td><td>will have vetted</td><td>By Friday, we will have vetted all submissions.</td><td>Cuma''ya kadar tüm başvuruları incelemiş olacağız.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Passive Voice / Edilgen Yapı</h3>\n      <p>\"Vet\" edilgen çatıda çok yaygındır — incelenen kişi veya şey genellikle öznedir:</p>\n      <table>\n        <thead><tr><th>Active</th><th>Passive</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>The HR team vets every candidate.</td><td>Every candidate <strong>is vetted</strong> by the HR team.</td><td>Her aday İK ekibi tarafından incelenir.</td></tr>\n          <tr><td>They vetted the documents.</td><td>The documents <strong>were vetted</strong> thoroughly.</td><td>Belgeler kapsamlı bir şekilde incelendi.</td></tr>\n          <tr><td>We are vetting the data.</td><td>The data <strong>is being vetted</strong>.</td><td>Veriler inceleniyor.</td></tr>\n        </tbody>\n      </table>"}, {"icon": "🔗", "title": "Common Prepositions & Collocations / Edatlar ve Eşdizimler", "content": "<h3>Prepositions / Edatlar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>vet + someone/something</td><td>We need to vet the contractor.</td><td>Yükleniciyi incelememiz gerekiyor.</td></tr>\n          <tr><td>vet + someone + <strong>for</strong> (a role)</td><td>He was vetted for top-secret clearance.</td><td>Çok gizli güvenlik izni için araştırıldı.</td></tr>\n          <tr><td>vet + something + <strong>against</strong> (criteria)</td><td>Applications are vetted against strict criteria.</td><td>Başvurular katı kriterlere göre incelenir.</td></tr>\n          <tr><td><strong>undergo</strong> vetting</td><td>All staff undergo annual vetting.</td><td>Tüm personel yıllık incelemeden geçer.</td></tr>\n          <tr><td><strong>subject to</strong> vetting</td><td>The offer is subject to security vetting.</td><td>Teklif güvenlik soruşturmasına tabidir.</td></tr>\n          <tr><td>vetting <strong>of</strong> (something/someone)</td><td>The vetting of suppliers is essential.</td><td>Tedarikçilerin incelenmesi zorunludur.</td></tr>\n          <tr><td>vetting <strong>by</strong> (an authority)</td><td>Vetting by intelligence services can take months.</td><td>İstihbarat servisleri tarafından yapılan soruşturma aylarca sürebilir.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">security vetting <span class=\"tr\">— güvenlik soruşturması</span></span>\n        <span class=\"collocation-tag\">background vetting <span class=\"tr\">— geçmiş araştırması</span></span>\n        <span class=\"collocation-tag\">vetting process <span class=\"tr\">— inceleme süreci</span></span>\n        <span class=\"collocation-tag\">vetting procedure <span class=\"tr\">— denetleme prosedürü</span></span>\n        <span class=\"collocation-tag\">thorough vetting <span class=\"tr\">— kapsamlı inceleme</span></span>\n        <span class=\"collocation-tag\">proper vetting <span class=\"tr\">— uygun / düzgün inceleme</span></span>\n        <span class=\"collocation-tag\">due diligence vetting <span class=\"tr\">— durum tespiti incelemesi</span></span>\n        <span class=\"collocation-tag\">pre-employment vetting <span class=\"tr\">— işe alım öncesi araştırma</span></span>\n        <span class=\"collocation-tag\">fully vetted <span class=\"tr\">— tam olarak incelenmiş</span></span>\n        <span class=\"collocation-tag\">carefully vetted <span class=\"tr\">— dikkatle incelenmiş</span></span>\n        <span class=\"collocation-tag\">vet a candidate <span class=\"tr\">— adayı incelemek</span></span>\n        <span class=\"collocation-tag\">vet a claim <span class=\"tr\">— iddiayı doğrulamak</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. The company vets all new employees before hiring.</div>\n          <div class=\"tr\">Şirket işe almadan önce tüm yeni çalışanları inceler.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. Have you been vetted yet?</div>\n          <div class=\"tr\">Henüz inceleme sürecinden geçtin mi?</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. The vetting process can take up to three months.</div>\n          <div class=\"tr\">İnceleme süreci üç aya kadar sürebilir.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. All suppliers must undergo rigorous vetting before being approved.</div>\n          <div class=\"tr\">Tüm tedarikçilerin onaylanmadan önce sıkı bir inceleme sürecinden geçmesi gerekir.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. The journalist carefully vetted her sources before publishing the story.</div>\n          <div class=\"tr\">Gazeteci, haberi yayımlamadan önce kaynaklarını dikkatle inceledi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. The investment firm''s vetting of startups is notoriously strict.</div>\n          <div class=\"tr\">Yatırım şirketinin girişimleri inceleme süreci katılığıyla ünlüdür.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. Only vetted personnel are allowed in the restricted area.</div>\n          <div class=\"tr\">Kısıtlı alana yalnızca güvenlik soruşturmasından geçmiş personel girebilir.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye</div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. The failure to properly vet the contractor led to a major security breach.</div>\n          <div class=\"tr\">Yüklenicinin düzgün şekilde incelenmemesi büyük bir güvenlik ihlaline yol açtı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. In an era of misinformation, vetting online sources has become a critical skill.</div>\n          <div class=\"tr\">Dezenformasyon çağında çevrimiçi kaynakları doğrulamak kritik bir beceri haline geldi.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. The presidential candidate''s running mate underwent months of intensive vetting.</div>\n          <div class=\"tr\">Başkan adayının yardımcısı aylarca süren yoğun bir inceleme sürecinden geçti.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Technology / Teknoloji</div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. Always vet third-party libraries before adding them to your project.</div>\n          <div class=\"tr\">Projenize eklemeden önce üçüncü taraf kütüphaneleri her zaman inceleyin.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">12. The code review acts as a vetting mechanism for quality assurance.</div>\n          <div class=\"tr\">Kod incelemesi, kalite güvencesi için bir denetleme mekanizması işlevi görür.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>19. yüzyıl başları (İngiliz İngilizcesi)</td></tr>\n          <tr><td><strong>Root</strong></td><td><strong>veterinarian</strong> (veteriner hekim) → kısaltma: <strong>vet</strong></td></tr>\n          <tr><td><strong>Latin root</strong></td><td>Latin: <strong>veterīnārius</strong> (hayvanlarla ilgilenen) → <strong>veterīna</strong> (yük hayvanı, çeki hayvanı)</td></tr>\n          <tr><td><strong>Original meaning</strong></td><td>İlk anlamı tamamen veterinerlikle ilgiliydi: bir hayvanı (özellikle yarış atını) muayene etmek. Bir at yarışa katılmadan önce veteriner tarafından sağlık kontrolünden geçirilirdi — bu eyleme \"to vet\" denildi.</td></tr>\n          <tr><td><strong>Horse racing</strong></td><td>19. yüzyıl İngiltere''sinde at yarışları çok popülerdi. Yarış öncesi \"vetting\" süreci, atın sağlıklı ve yarışa uygun olup olmadığını belirliyordu. Bu uygulama kelimenin mecazi anlamının temelini attı.</td></tr>\n          <tr><td><strong>Figurative sense</strong></td><td>20. yüzyılın başlarında \"vet\" fiili mecazi anlam kazandı: herhangi bir kişiyi veya şeyi \"uygunluk açısından dikkatle incelemek.\" Tıpkı veterinerin ata yaptığı gibi, bir kurumun adaya yaptığı kapsamlı inceleme.</td></tr>\n          <tr><td><strong>Security sense</strong></td><td>İkinci Dünya Savaşı sırasında ve sonrasında \"security vetting\" (güvenlik soruşturması) kavramı istihbarat servisleri tarafından yaygınlaştırıldı. Devlet görevlilerinin geçmişlerinin araştırılması \"vetting\" olarak adlandırıldı.</td></tr>\n          <tr><td><strong>Modern usage</strong></td><td>Günümüzde \"vetting\" İK, güvenlik, gazetecilik, siyaset ve teknoloji alanlarında standart bir terimdir. \"Fact-checking\" kavramıyla yakından ilişkilidir.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (veterīna = working animal)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>vet</strong> (noun)</td><td>veterinarian (shortened)</td><td>veteriner</td></tr>\n          <tr><td><strong>vet</strong> (verb)</td><td>to examine carefully</td><td>incelemek, denetlemek</td></tr>\n          <tr><td><strong>vetting</strong></td><td>the process of careful examination</td><td>inceleme, soruşturma</td></tr>\n          <tr><td><strong>vetted</strong></td><td>examined and approved</td><td>incelenmiş, onaylanmış</td></tr>\n          <tr><td><strong>veterinarian</strong></td><td>animal doctor</td><td>veteriner hekim</td></tr>\n          <tr><td><strong>veterinary</strong></td><td>relating to animal medicine</td><td>veterinerlik ile ilgili</td></tr>\n          <tr><td><strong>veteran</strong></td><td>experienced person; ex-soldier (from Latin <em>vetus</em> = old — farklı kök, ancak benzer ses)</td><td>deneyimli kişi; eski asker</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Vetting\" kelimesini hatırlamak için şunu hayal edin: bir <em>veteriner</em> (vet) yarış atını yarış öncesi baştan aşağı muayene eder — kulağına, dişlerine, bacaklarına tek tek bakar. İşte bir şirkette İK''nın adayları \"vet etmesi\" de tam olarak budur: özgeçmişini, referanslarını, geçmişini baştan aşağı incelemek. <em>Veterinerin titiz muayenesi = vetting!</em>\n      </div>"}, {"icon": "⚖️", "title": "Vetting vs. Screening vs. Background Check vs. Due Diligence", "content": "<p>\"İnceleme / araştırma\" anlamında kullanılan bu terimler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Vetting</th><th>Screening</th><th>Background Check</th><th>Due Diligence</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Focus</td>\n            <td>Thorough examination of suitability<br><em>Uygunluğun kapsamlı incelenmesi</em></td>\n            <td>Initial filtering of candidates/items<br><em>Adayların / öğelerin ilk elenmesi</em></td>\n            <td>Verifying personal history and records<br><em>Kişisel geçmiş ve kayıtların doğrulanması</em></td>\n            <td>Comprehensive investigation before a deal<br><em>Anlaşma öncesi kapsamlı araştırma</em></td>\n          </tr>\n          <tr>\n            <td>Depth</td>\n            <td>Deep and detailed<br><em>Derin ve detaylı</em></td>\n            <td>Surface-level, filtering<br><em>Yüzeysel, eleme</em></td>\n            <td>Moderate; focused on records<br><em>Orta; kayıtlara odaklı</em></td>\n            <td>Very deep and broad<br><em>Çok derin ve geniş</em></td>\n          </tr>\n          <tr>\n            <td>Common in</td>\n            <td>Security, HR, journalism<br><em>Güvenlik, İK, gazetecilik</em></td>\n            <td>HR, medical, airport<br><em>İK, sağlık, havalimanı</em></td>\n            <td>Employment, housing<br><em>İstihdam, konut</em></td>\n            <td>Finance, M&A, investment<br><em>Finans, birleşme, yatırım</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>Security vetting of staff.</td>\n            <td>Screening applicants by CV.</td>\n            <td>Running a criminal background check.</td>\n            <td>Conducting due diligence on an acquisition.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Personelin güvenlik soruşturması.</td>\n            <td>Başvuranların CV ile elenmesi.</td>\n            <td>Adli sicil araştırması yapma.</td>\n            <td>Bir satın alma için durum tespiti yapmak.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Screening\" en <em>yüzeyseldir</em> — ilk eleme. \"Background check\" belirli kayıtlara (sabıka, eğitim, kredi geçmişi) odaklanır. \"Vetting\" daha derin ve kapsamlıdır — sadece kayıtlar değil, uygunluğun genel değerlendirmesi. \"Due diligence\" ise en geniş kapsamlıdır — genellikle finansal, hukuki ve operasyonel boyutları kapsayan büyük ölçekli bir araştırmadır.\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>HR / Recruitment</strong><br>(İnsan Kaynakları)</td>\n            <td>Checking candidates'' qualifications, references, and history</td>\n            <td>Pre-employment vetting revealed a gap in his work history.</td>\n            <td>İşe alım öncesi inceleme, iş geçmişinde bir boşluk ortaya çıkardı.</td>\n          </tr>\n          <tr>\n            <td><strong>Security</strong><br>(Güvenlik)</td>\n            <td>Government / military security clearance investigations</td>\n            <td>She holds DV (Developed Vetting) clearance.</td>\n            <td>DV (Gelişmiş Güvenlik Soruşturması) izni sahibidir.</td>\n          </tr>\n          <tr>\n            <td><strong>Politics</strong><br>(Siyaset)</td>\n            <td>Investigating candidates for political office</td>\n            <td>The VP pick was carefully vetted for any past controversies.</td>\n            <td>Başkan yardımcısı adayı, geçmişteki tartışmalar açısından dikkatle araştırıldı.</td>\n          </tr>\n          <tr>\n            <td><strong>Journalism</strong><br>(Gazetecilik)</td>\n            <td>Verifying sources and facts</td>\n            <td>Editors vet all claims before publication.</td>\n            <td>Editörler yayın öncesi tüm iddiaları doğrular.</td>\n          </tr>\n          <tr>\n            <td><strong>Technology</strong><br>(Teknoloji)</td>\n            <td>Reviewing code, libraries, vendors</td>\n            <td>We vet every open-source dependency for vulnerabilities.</td>\n            <td>Her açık kaynak bağımlılığını güvenlik açıkları açısından inceliyoruz.</td>\n          </tr>\n          <tr>\n            <td><strong>Finance</strong><br>(Finans)</td>\n            <td>Investigating investments or partners</td>\n            <td>The fund manager vets each investment opportunity carefully.</td>\n            <td>Fon yöneticisi her yatırım fırsatını dikkatle inceler.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "Bonus: Vet as an Animal Doctor / Vet''in Veteriner Anlamı", "content": "<p>\"Vet\" kelimesinin asıl anlamını — veteriner — unutmayalım. Bu anlam hâlâ çok yaygındır:</p>\n      <table>\n        <thead><tr><th>Context</th><th>Meaning</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Noun</strong></td>\n            <td>Veterinarian (short form)</td>\n            <td>I need to take my cat to the vet.</td>\n            <td>Kedimi veterinere götürmem gerekiyor.</td>\n          </tr>\n          <tr>\n            <td><strong>Verb (original)</strong></td>\n            <td>To examine/treat an animal</td>\n            <td>The horse was vetted before the race.</td>\n            <td>At yarış öncesi muayene edildi.</td>\n          </tr>\n          <tr>\n            <td><strong>Verb (figurative)</strong></td>\n            <td>To examine for suitability</td>\n            <td>The proposal was vetted by the board.</td>\n            <td>Teklif yönetim kurulu tarafından incelendi.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>⚠️ Karıştırmayın:</strong>\n        <br>• <strong>vet</strong> (veteriner / incelemek) ≠ <strong>veto</strong> (veto etmek, reddetmek)\n        <br>• <strong>vet</strong> ≠ <strong>veteran</strong> (deneyimli kişi / eski asker) — farklı Latince köklerden gelir\n        <br>• \"Vet\" bir şeyi <em>incelemek</em> demektir, <em>reddetmek</em> değil. İnceleme sonucunda kabul de edilebilir, reddedilebilir de.\n      </div>"}]'::jsonb)
ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, phonetic = EXCLUDED.phonetic, subtitle = EXCLUDED.subtitle, sections = EXCLUDED.sections;

INSERT INTO words (slug, title, phonetic, subtitle, sections) VALUES ('whilst', 'WHILST', '/waɪlst/', '-iken · sırasında · oysa · -diği halde · rağmen', '[{"icon": "📖", "title": "Definition / Tanım", "content": "<p><strong>Whilst</strong>, \"while\" kelimesinin daha resmi ve edebi versiyonudur. Özellikle İngiliz İngilizcesi''nde (British English) yaygındır. Hem bağlaç hem de — nadiren — isim olarak kullanılır.</p>\n\n      <h3>Step-by-step reasoning / Adım adım düşünme:</h3>\n      <p style=\"margin-bottom:0.8rem;\">\"Whilst\" kelimesi üç temel bağlamda kullanılır: (1) <strong>Eşzamanlılık</strong> — iki eylemin aynı anda gerçekleşmesini ifade eder: \"Whilst I was cooking, the phone rang\" (Yemek yaparken telefon çaldı). (2) <strong>Karşıtlık / zıtlık</strong> — iki durum arasındaki farkı vurgular: \"Whilst some agreed, others objected\" (Bazıları kabul ederken diğerleri itiraz etti). (3) <strong>Taviz / rağmen</strong> — bir şeyi kabul edip başka bir şeyi vurgulama: \"Whilst expensive, the quality is excellent\" (Pahalı olmasına rağmen kalitesi mükemmel). Anlamca \"while\" ile tamamen aynıdır; fark yalnızca üsluptadır — \"whilst\" daha resmi/edebi hissiyat verir.</p>\n\n      <table>\n        <thead><tr><th>Part of Speech</th><th>Meaning (English)</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Conjunction</strong> (bağlaç)</td><td>During the time that; at the same time as</td><td>-iken, sırasında, -diği sırada</td></tr>\n          <tr><td><strong>Conjunction</strong> (bağlaç)</td><td>Whereas; in contrast to the fact that</td><td>Oysa, halbuki, ise</td></tr>\n          <tr><td><strong>Conjunction</strong> (bağlaç)</td><td>Although; even though (concessive)</td><td>-masına rağmen, -diği halde, her ne kadar</td></tr>\n          <tr><td><strong>Noun</strong> (isim, nadir)</td><td>A period of time (same as \"while\")</td><td>Bir süre, bir müddet</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>🇬🇧 vs 🇺🇸 :</strong> \"Whilst\" İngiliz İngilizcesi''nde (British English) tercih edilir. Amerikan İngilizcesi''nde (American English) neredeyse hiç kullanılmaz — orada sadece \"while\" kullanılır. Uluslararası yazışmalarda \"while\" daha güvenli bir tercihtir; ancak akademik ve hukuki metinlerde \"whilst\" zarif bir dokunuş katar.\n      </div>"}, {"icon": "📝", "title": "Grammar and Usage / Dilbilgisi ve Kullanım", "content": "<h3>Word Family / Kelime Ailesi</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Part of Speech</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>while</strong></td><td>conjunction / noun / verb</td><td>-iken, oysa; bir süre; (zaman) geçirmek</td></tr>\n          <tr><td><strong>whilst</strong></td><td>conjunction (bağlaç)</td><td>-iken, oysa, rağmen (resmi/edebi)</td></tr>\n          <tr><td><strong>meanwhile</strong></td><td>adverb (zarf)</td><td>bu arada, bu sırada</td></tr>\n          <tr><td><strong>worthwhile</strong></td><td>adjective (sıfat)</td><td>değerli, zahmete değer</td></tr>\n          <tr><td><strong>awhile</strong></td><td>adverb (zarf)</td><td>bir süre, bir müddet</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>📌 Not:</strong> \"Whilst\" bir bağlaçtır (conjunction), fiil değildir. Cümleleri birbirine bağlar. Fiil çekimi yoktur — her zaman aynı formda kullanılır.\n      </div>\n\n      <h3>Key Structures / Temel Yapılar</h3>\n\n      <div class=\"structure-box\">\n        <code>Whilst + subject + verb, main clause</code>\n        <div>→ Eşzamanlılık: …iken / …sırasında</div>\n        <div class=\"example\"><em><strong>Whilst</strong> I was reading, the lights went out.</em></div>\n        <div class=\"turkish\">Okurken ışıklar söndü.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>Main clause + whilst + subject + verb</code>\n        <div>→ Eşzamanlılık: Ana cümle + …iken</div>\n        <div class=\"example\"><em>She fell asleep <strong>whilst</strong> watching TV.</em></div>\n        <div class=\"turkish\">Televizyon izlerken uyuyakaldı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>Whilst + clause A, clause B (contrast)</code>\n        <div>→ Karşıtlık: …iken / …oysa</div>\n        <div class=\"example\"><em><strong>Whilst</strong> the first report was optimistic, the second painted a bleaker picture.</em></div>\n        <div class=\"turkish\">İlk rapor iyimser iken ikinci rapor daha kasvetli bir tablo çizdi.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>Whilst + adjective/participle (reduced clause)</code>\n        <div>→ Taviz: …olmasına rağmen, …olsa da</div>\n        <div class=\"example\"><em><strong>Whilst</strong> expensive, the course is worth every penny.</em></div>\n        <div class=\"turkish\">Pahalı olmasına rağmen kurs her kuruşuna değer.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>Whilst + -ing (participle)</code>\n        <div>→ …yaparken, …ederken</div>\n        <div class=\"example\"><em>He injured his knee <strong>whilst</strong> playing football.</em></div>\n        <div class=\"turkish\">Futbol oynarken dizini sakatladı.</div>\n      </div>\n\n      <div class=\"structure-box\">\n        <code>Whilst + acknowledging / recognizing …</code>\n        <div>→ …kabul etmekle birlikte / …farkında olmakla birlikte (resmi yazılarda)</div>\n        <div class=\"example\"><em><strong>Whilst</strong> acknowledging the risks, the board approved the project.</em></div>\n        <div class=\"turkish\">Riskleri kabul etmekle birlikte yönetim kurulu projeyi onayladı.</div>\n      </div>"}, {"icon": "⏱️", "title": "Tense Patterns with \"Whilst\" / \"Whilst\" ile Zaman Kalıpları", "content": "<div class=\"tip\" style=\"margin-bottom: 1rem;\">\n        <strong>📌 Not:</strong> \"Whilst\" bir bağlaçtır, fiil değildir. Bu nedenle kendi fiil çekimi yoktur. Ancak hangi zamanlarla birlikte kullanıldığı çok önemlidir.\n      </div>\n\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>Whilst + Past Continuous, Past Simple</td><td>Whilst I was walking home, it started raining.</td><td>Eve yürürken yağmur yağmaya başladı.</td></tr>\n          <tr><td>Whilst + Past Continuous, Past Continuous</td><td>Whilst she was studying, he was cooking.</td><td>O ders çalışırken, o yemek yapıyordu.</td></tr>\n          <tr><td>Whilst + Present Simple, Present Simple</td><td>Whilst some prefer tea, others prefer coffee.</td><td>Bazıları çayı tercih ederken, diğerleri kahveyi tercih eder.</td></tr>\n          <tr><td>Whilst + Present Perfect, Present Perfect</td><td>Whilst costs have risen, quality has improved.</td><td>Maliyetler artarken kalite de iyileşti.</td></tr>\n          <tr><td>Whilst + -ing (reduced)</td><td>Whilst travelling, always keep your passport handy.</td><td>Seyahat ederken pasaportunuzu her zaman yanınızda bulundurun.</td></tr>\n          <tr><td>Whilst + adjective (reduced)</td><td>Whilst understandable, his reaction was disproportionate.</td><td>Anlaşılır olmakla birlikte tepkisi orantısızdı.</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>⚡ En yaygın kalıp:</strong> <strong>Whilst + Past Continuous, Past Simple</strong> — bir eylem devam ederken başka bir eylemin gerçekleşmesi. Bu, İngilizce dilbilgisi sınavlarında en çok test edilen yapılardan biridir.\n      </div>"}, {"icon": "🔗", "title": "Common Patterns & Collocations / Kalıplar ve Eşdizimler", "content": "<h3>Common Patterns / Yaygın Kalıplar</h3>\n      <table>\n        <thead><tr><th>Pattern</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>whilst <strong>at the same time</strong></td><td>Whilst saving money, he was at the same time investing wisely.</td><td>Para biriktirirken aynı zamanda akıllıca yatırım yapıyordu.</td></tr>\n          <tr><td>whilst <strong>also</strong></td><td>The app is free, whilst also being feature-rich.</td><td>Uygulama ücretsiz, aynı zamanda özellik açısından da zengin.</td></tr>\n          <tr><td>whilst <strong>still</strong></td><td>She managed to stay calm whilst still under pressure.</td><td>Hâlâ baskı altındayken sakin kalmayı başardı.</td></tr>\n          <tr><td>whilst <strong>ensuring</strong></td><td>Cut costs whilst ensuring quality.</td><td>Kaliteyi sağlarken maliyetleri azaltın.</td></tr>\n          <tr><td>whilst <strong>maintaining</strong></td><td>Diversify the portfolio whilst maintaining low risk.</td><td>Düşük riski korurken portföyü çeşitlendirin.</td></tr>\n          <tr><td>whilst <strong>on</strong> (a trip/duty)</td><td>She wrote the novel whilst on maternity leave.</td><td>Doğum iznindeyken romanı yazdı.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Common Collocations / Yaygın Eşdizimler</h3>\n      <div class=\"collocation-list\">\n        <span class=\"collocation-tag\">whilst working <span class=\"tr\">— çalışırken</span></span>\n        <span class=\"collocation-tag\">whilst studying <span class=\"tr\">— ders çalışırken</span></span>\n        <span class=\"collocation-tag\">whilst travelling <span class=\"tr\">— seyahat ederken</span></span>\n        <span class=\"collocation-tag\">whilst driving <span class=\"tr\">— sürerken</span></span>\n        <span class=\"collocation-tag\">whilst acknowledging <span class=\"tr\">— kabul etmekle birlikte</span></span>\n        <span class=\"collocation-tag\">whilst ensuring <span class=\"tr\">— sağlarken</span></span>\n        <span class=\"collocation-tag\">whilst maintaining <span class=\"tr\">— korurken</span></span>\n        <span class=\"collocation-tag\">whilst abroad <span class=\"tr\">— yurt dışındayken</span></span>\n        <span class=\"collocation-tag\">whilst asleep <span class=\"tr\">— uyurken</span></span>\n        <span class=\"collocation-tag\">whilst on holiday <span class=\"tr\">— tatildeyken</span></span>\n      </div>"}, {"icon": "💬", "title": "Example Sentences / Örnek Cümleler", "content": "<div class=\"example-group\">\n        <div class=\"label\">Basic / Temel (Eşzamanlılık)</div>\n        <div class=\"example-item\">\n          <div class=\"en\">1. He called me whilst I was having dinner.</div>\n          <div class=\"tr\">Akşam yemeği yerken beni aradı.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">2. Please don''t talk whilst eating.</div>\n          <div class=\"tr\">Lütfen yemek yerken konuşma.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">3. She smiled whilst shaking my hand.</div>\n          <div class=\"tr\">Elimi sıkarken gülümsedi.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Intermediate / Orta Seviye (Karşıtlık)</div>\n        <div class=\"example-item\">\n          <div class=\"en\">4. Whilst I agree with the goal, I disagree with the method.</div>\n          <div class=\"tr\">Amaç konusunda hemfikirim, ancak yöntem konusunda aynı fikirde değilim.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">5. Whilst London is rainy, Madrid enjoys sunshine most of the year.</div>\n          <div class=\"tr\">Londra yağışlı iken, Madrid yılın büyük bölümünde güneşin tadını çıkarır.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">6. Whilst some students excelled, others struggled to keep up.</div>\n          <div class=\"tr\">Bazı öğrenciler mükemmel başarı gösterirken, diğerleri ayak uydurmakta zorlandı.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Advanced / İleri Seviye (Taviz / Resmi)</div>\n        <div class=\"example-item\">\n          <div class=\"en\">7. Whilst the economy has shown signs of recovery, unemployment remains stubbornly high.</div>\n          <div class=\"tr\">Ekonomi toparlanma belirtileri gösterse de işsizlik inatla yüksek kalmaya devam ediyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">8. Whilst not legally binding, the agreement sets a strong moral precedent.</div>\n          <div class=\"tr\">Hukuki olarak bağlayıcı olmamakla birlikte, anlaşma güçlü bir ahlaki emsal oluşturuyor.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">9. The company expanded rapidly whilst maintaining strict quality standards.</div>\n          <div class=\"tr\">Şirket, sıkı kalite standartlarını korurken hızla büyüdü.</div>\n        </div>\n      </div>\n\n      <div class=\"example-group\">\n        <div class=\"label\">Formal & Academic / Resmi ve Akademik</div>\n        <div class=\"example-item\">\n          <div class=\"en\">10. Whilst acknowledging the limitations of this study, the findings are nonetheless significant.</div>\n          <div class=\"tr\">Bu çalışmanın sınırlılıklarını kabul etmekle birlikte, bulgular yine de önemlidir.</div>\n        </div>\n        <div class=\"example-item\">\n          <div class=\"en\">11. Data was collected whilst participants were engaged in the task.</div>\n          <div class=\"tr\">Katılımcılar görevle meşgulken veriler toplandı.</div>\n        </div>\n      </div>"}, {"icon": "🏛️", "title": "Word Root & History / Kelimenin Kökeni", "content": "<table>\n        <thead><tr><th>Aspect</th><th>Detail</th></tr></thead>\n        <tbody>\n          <tr><td><strong>Origin</strong></td><td>Middle English (14. yüzyıl)</td></tr>\n          <tr><td><strong>Formation</strong></td><td><strong>whiles</strong> (eski İngilizce zaman zarfı) + <strong>-t</strong> (ek ses / paragogic ''t'')</td></tr>\n          <tr><td><strong>Root</strong></td><td>Old English: <strong>hwīl</strong> (a period of time / bir süre, zaman dilimi)</td></tr>\n          <tr><td><strong>Proto-Germanic</strong></td><td><strong>*hwīlō</strong> (time of rest, pause / dinlenme zamanı, mola)</td></tr>\n          <tr><td><strong>PIE Root</strong></td><td><strong>*kʷyeh₁-</strong> (to rest, to be quiet / dinlenmek, sessiz olmak)</td></tr>\n          <tr><td><strong>The \"-st\" ending</strong></td><td>Orta İngilizce döneminde \"whiles\" (sırasında) kelimesinin sonuna bir <em>-t</em> sesi eklendi — buna <em>paragogic t</em> denir. Aynı olgu \"among → amongst\", \"amid → amidst\", \"again → against\" kelimelerinde de görülür. Bu -t eki anlam değiştirmez, sadece fonetik bir gelişmedir.</td></tr>\n          <tr><td><strong>While vs Whilst</strong></td><td>\"While\" 9. yüzyıldan beri kullanılırken, \"whilst\" 14. yüzyılda ortaya çıkmıştır. İkisi de aynı kökten gelir ve anlamca tamamen aynıdır. Tek fark: \"whilst\" daha resmi ve İngiliz İngilizcesi''ne özgüdür.</td></tr>\n          <tr><td><strong>Modern usage</strong></td><td>Günümüzde \"whilst\" İngiliz İngilizcesi''nde yaygın, Amerikan İngilizcesi''nde nadirdir. Akademik yazılarda, hukuk metinlerinde ve resmi yazışmalarda tercih edilir.</td></tr>\n        </tbody>\n      </table>\n\n      <h3>Related Words from the Same Root (hwīl = time)</h3>\n      <table>\n        <thead><tr><th>Word</th><th>Meaning</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>while</strong></td><td>during; whereas; a period of time</td><td>-iken; oysa; bir süre</td></tr>\n          <tr><td><strong>whilst</strong></td><td>same as while (formal/British)</td><td>-iken; oysa (resmi)</td></tr>\n          <tr><td><strong>meanwhile</strong></td><td>at the same time; in the interim</td><td>bu arada, bu sırada</td></tr>\n          <tr><td><strong>awhile</strong></td><td>for a short time</td><td>bir süre, bir müddet</td></tr>\n          <tr><td><strong>worthwhile</strong></td><td>worth the time spent</td><td>zahmete değer</td></tr>\n          <tr><td><strong>erstwhile</strong></td><td>former, previous</td><td>eski, önceki</td></tr>\n          <tr><td><strong>whilom</strong></td><td>(archaic) formerly</td><td>eskiden (arkaik)</td></tr>\n        </tbody>\n      </table>\n\n      <h3>The \"-st\" Pattern / \"-st\" Kalıbı</h3>\n      <p>İngilizce''de birçok kelime aynı <em>paragogic -t/-st</em> ekini almıştır:</p>\n      <table>\n        <thead><tr><th>Base Form</th><th>Extended Form</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td>while</td><td><strong>whilst</strong></td><td>-iken, oysa</td></tr>\n          <tr><td>among</td><td><strong>amongst</strong></td><td>arasında</td></tr>\n          <tr><td>amid</td><td><strong>amidst</strong></td><td>ortasında</td></tr>\n          <tr><td>again</td><td><strong>against</strong></td><td>karşı (anlam kaymıştır)</td></tr>\n          <tr><td>between</td><td><strong>betwixt</strong> (archaic)</td><td>arasında (arkaik)</td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"tip\">\n        <strong>💡 Hatırlatma notu:</strong> \"Whilst\" kelimesini hatırlamak için şunu düşünün: <em>\"while\"</em> ile tamamen aynı — sadece sonuna bir <em>-st</em> eklendi. Tıpkı \"among/amongst\" gibi. Bu -st eki kelimeye hiçbir anlam farkı katmaz, sadece daha resmi ve İngiliz bir hava verir. Bir British centilmenin konuşma tarzını hayal edin!\n      </div>"}, {"icon": "⚖️", "title": "Whilst vs. While vs. During vs. As / Farkları", "content": "<p>\"…iken / sırasında\" anlamında kullanılan bu kelimeler arasında önemli nüans farkları vardır:</p>\n      <table class=\"vs-table\">\n        <thead><tr><th></th><th>Whilst</th><th>While</th><th>During</th><th>As</th></tr></thead>\n        <tbody>\n          <tr>\n            <td>Type</td>\n            <td>Conjunction<br><em>Bağlaç</em></td>\n            <td>Conjunction<br><em>Bağlaç</em></td>\n            <td>Preposition<br><em>Edat</em></td>\n            <td>Conjunction<br><em>Bağlaç</em></td>\n          </tr>\n          <tr>\n            <td>Followed by</td>\n            <td>Subject + Verb<br><em>Özne + Fiil</em></td>\n            <td>Subject + Verb<br><em>Özne + Fiil</em></td>\n            <td>Noun / Noun phrase<br><em>İsim / İsim öbeği</em></td>\n            <td>Subject + Verb<br><em>Özne + Fiil</em></td>\n          </tr>\n          <tr>\n            <td>Register</td>\n            <td>Formal / British<br><em>Resmi / İngiliz</em></td>\n            <td>Neutral / Universal<br><em>Nötr / Evrensel</em></td>\n            <td>Neutral<br><em>Nötr</em></td>\n            <td>Neutral to formal<br><em>Nötr — resmi</em></td>\n          </tr>\n          <tr>\n            <td>Contrast?</td>\n            <td>✅ Yes<br><em>Evet</em></td>\n            <td>✅ Yes<br><em>Evet</em></td>\n            <td>❌ No<br><em>Hayır</em></td>\n            <td>❌ Rarely<br><em>Nadiren</em></td>\n          </tr>\n          <tr>\n            <td>Example</td>\n            <td>Whilst it rained, we stayed in.</td>\n            <td>While it rained, we stayed in.</td>\n            <td>During the rain, we stayed in.</td>\n            <td>As it rained, we stayed in.</td>\n          </tr>\n          <tr>\n            <td>Turkish</td>\n            <td>Yağmur yağarken içeride kaldık.</td>\n            <td>Yağmur yağarken içeride kaldık.</td>\n            <td>Yağmur sırasında içeride kaldık.</td>\n            <td>Yağmur yağarken içeride kaldık.</td>\n          </tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>📌 En önemli fark:</strong>\n        <br>• <strong>Whilst / While</strong> = bağlaç → arkasından <em>cümle</em> gelir (subject + verb).\n        <br>• <strong>During</strong> = edat → arkasından <em>isim</em> gelir (noun/noun phrase).\n        <br>• <em>\"Whilst / While I was sleeping\"</em> ✅ ama <em>\"During I was sleeping\"</em> ❌\n        <br>• <em>\"During the meeting\"</em> ✅ ama <em>\"Whilst the meeting\"</em> ❌ (cümle olmalı: <em>\"Whilst we were in the meeting\"</em>)\n      </div>"}, {"icon": "🌍", "title": "Usage in Different Fields / Farklı Alanlarda Kullanım", "content": "<table>\n        <thead><tr><th>Field / Alan</th><th>Usage</th><th>Example</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr>\n            <td><strong>Academic</strong><br>(Akademik)</td>\n            <td>Contrast or concession in papers</td>\n            <td>Whilst earlier studies suggested X, our findings indicate Y.</td>\n            <td>Önceki çalışmalar X''i önerirken, bulgularımız Y''yi göstermektedir.</td>\n          </tr>\n          <tr>\n            <td><strong>Legal</strong><br>(Hukuk)</td>\n            <td>Formal clauses and conditions</td>\n            <td>Whilst every effort has been made to ensure accuracy…</td>\n            <td>Doğruluğu sağlamak için her türlü çaba gösterilmiş olmakla birlikte…</td>\n          </tr>\n          <tr>\n            <td><strong>Business</strong><br>(İş Dünyası)</td>\n            <td>Reports, emails (British style)</td>\n            <td>Whilst revenue grew, profit margins shrank.</td>\n            <td>Gelir artarken kâr marjları daraldı.</td>\n          </tr>\n          <tr>\n            <td><strong>Technology</strong><br>(Teknoloji)</td>\n            <td>Documentation, technical writing</td>\n            <td>Whilst the API supports JSON, XML is also available.</td>\n            <td>API JSON''u desteklerken, XML de kullanılabilir.</td>\n          </tr>\n          <tr>\n            <td><strong>Daily Life</strong><br>(Günlük Hayat)</td>\n            <td>British informal speech</td>\n            <td>I read the news whilst having breakfast.</td>\n            <td>Kahvaltı yaparken haberleri okudum.</td>\n          </tr>\n          <tr>\n            <td><strong>Literature</strong><br>(Edebiyat)</td>\n            <td>Narrative, descriptive prose</td>\n            <td>Whilst the world slept, the fox crept through the garden.</td>\n            <td>Dünya uyurken tilki bahçede sessizce ilerledi.</td>\n          </tr>\n        </tbody>\n      </table>"}, {"icon": "🧩", "title": "Bonus: British vs. American Pairs / İngiliz vs. Amerikan Çiftleri", "content": "<p>\"Whilst/while\" gibi İngiliz ve Amerikan İngilizcesi arasında tercih farkı olan kelime çiftleri:</p>\n      <table>\n        <thead><tr><th>British English 🇬🇧</th><th>American English 🇺🇸</th><th>Turkish</th></tr></thead>\n        <tbody>\n          <tr><td><strong>whilst</strong></td><td>while</td><td>-iken, oysa</td></tr>\n          <tr><td><strong>amongst</strong></td><td>among</td><td>arasında</td></tr>\n          <tr><td><strong>amidst</strong></td><td>amid</td><td>ortasında</td></tr>\n          <tr><td><strong>towards</strong></td><td>toward</td><td>-e doğru</td></tr>\n          <tr><td><strong>afterwards</strong></td><td>afterward</td><td>daha sonra</td></tr>\n          <tr><td><strong>forwards</strong></td><td>forward</td><td>ileri doğru</td></tr>\n          <tr><td><strong>colour</strong></td><td>color</td><td>renk</td></tr>\n          <tr><td><strong>favourite</strong></td><td>favorite</td><td>favori</td></tr>\n          <tr><td><strong>realise</strong></td><td>realize</td><td>fark etmek</td></tr>\n        </tbody>\n      </table>\n      <div class=\"tip\">\n        <strong>💡 Pratik tavsiye:</strong> Her iki formu da anlayın, ancak tutarlı olun. Eğer İngiliz İngilizcesi tarzında yazıyorsanız \"whilst, amongst, colour\" kullanın; Amerikan tarzında yazıyorsanız \"while, among, color\" tercih edin. İkisini karıştırmak profesyonel metinlerde göze batar!\n      </div>"}]'::jsonb)
